function getFeatIcon(item) {
  if (!item.type) return '📜';
  const tags = item.type.split(',').map(t => t.trim());
  // For combo types, prefer the more-specific tag over plain Combat
  // i.e. "Combat, Style" → 👊, "Combat, Teamwork" → 🤝
  const preferred = tags.filter(t => t !== 'Combat');
  for (const tag of preferred) {
    if (FEAT_TYPE_ICONS[tag]) return FEAT_TYPE_ICONS[tag];
  }
  // Fall back to Combat or whatever is first
  for (const tag of tags) {
    if (FEAT_TYPE_ICONS[tag]) return FEAT_TYPE_ICONS[tag];
  }
  return '📜';
}

