// SQL.JS LOADER
// ═══════════════════════════════════════════════════════════════════════════
async function loadSqlJs() {
  if (window.SQL) return window.SQL;
  return new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = SQLJS_CDN;
    s.onload = () => initSqlJs({ locateFile: () => SQLJS_WASM })
      .then(SQL => { window.SQL = SQL; resolve(SQL); }).catch(reject);
    s.onerror = () => reject(new Error('Failed to load sql.js from CDN'));
    document.head.appendChild(s);
  });
}

async function openDb(filename) {
  const res = await fetch(filename);
  if (!res.ok) throw new Error(`Cannot fetch ${filename}: HTTP ${res.status}`);
  return new window.SQL.Database(new Uint8Array(await res.arrayBuffer()));
}

// Run a query against the index DB
function idxQuery(sql, params) {
  const rows = [];
  try {
    const stmt = indexDb.prepare(sql);
    if (params) stmt.bind(params);
    while (stmt.step()) rows.push(stmt.getAsObject());
    stmt.free();
  } catch(e) { console.warn('idxQuery:', e.message, sql); }
  return rows;
}

// Run a query against a book DB, loading it if needed
async function bookQuery(dbFile, sql, params) {
  if (!bookDbs[dbFile]) {
    try { bookDbs[dbFile] = await openDb(dbFile); }
    catch(e) { console.warn(`Could not open ${dbFile}:`, e.message); return []; }
  }
  const rows = [];
  try {
    const stmt = bookDbs[dbFile].prepare(sql);
    if (params) stmt.bind(params);
    while (stmt.step()) rows.push(stmt.getAsObject());
    stmt.free();
  } catch(e) { console.warn('bookQuery:', dbFile, e.message); }
  return rows;
}

const AVAILABLE_DBS = new Set(DB_FILES);

// ═══════════════════════════════════════════════════════════════════════════
// ROW MAPPER — central_index row → UI item object
// ═══════════════════════════════════════════════════════════════════════════
function mapIndexRow(row) {
  const cleanStr = s => s ? String(s).replace(/&mdash;/g,'—').replace(/&rsquo;/g,"'").replace(/&amp;/g,'&').replace(/&ndash;/g,'–') : null;

  // Parse "Wizard: 3; Sorcerer: 3" into levels array
  const levels = [];
  if (row.spell_list_text) {
    for (const part of row.spell_list_text.split(';')) {
      const m = part.trim().match(/^(.+?):\s*(\d+)$/);
      if (m) levels.push({ class: m[1].trim(), level: parseInt(m[2]) });
    }
  }

  const featType = row.feat_type_description
    ? row.feat_type_description.replace(/[()]/g,'').trim() : 'General';
  const traitType = row.subtype
    ? row.subtype.replace(/_/g,' ').replace(/\b\w/g, l=>l.toUpperCase()) : 'Basic';

  return {
    name:        row.name,
    _name:       row.name,
    _source:     row.source,
    _db:         row.database,
    _index_id:   row.index_id,
    _section_id: row.section_id,
    _path:       row.type === 'class'
      ? `/class/${row.subtype||'core'}/${(row.name||'').toLowerCase().replace(/\s+/g,'_')}`
      : (row.url || ''),
    type:        row.type,
    subtype:     row.subtype,
    url:         row.url,
    source:      row.source,
    description: cleanStr(row.description),

    // Feat fields
    ...(row.type === 'feat' && {
      type:          featType,
      benefit:       cleanStr(row.description),
      prerequisites: cleanStr(row.feat_prerequisites),
    }),
    // Trait fields
    ...(row.type === 'trait' && {
      type:    traitType,
      benefit: cleanStr(row.description),
    }),
    // Spell fields
    ...(row.type === 'spell' && {
      school:     row.spell_school,
      descriptor: row.spell_descriptor_text,
      components: row.spell_component_text,
      level_text: row.spell_list_text,
      levels,
    }),
    // Item fields
    ...(row.type === 'item' && {
      slot: row.subtype,
    }),
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// FAST INDEX QUERIES (synchronous — index.db is in memory)
// ═══════════════════════════════════════════════════════════════════════════
function dbListSql() { return DB_FILES.map(f=>`'${f}'`).join(','); }

function loadRaces()   {
  return idxQuery(`SELECT * FROM central_index WHERE type='race' AND database IN (${dbListSql()}) ORDER BY name`).map(mapIndexRow);
}
function loadClasses() {
  return idxQuery(`SELECT * FROM central_index WHERE type='class' AND subtype NOT IN ('npc') AND database IN (${dbListSql()}) ORDER BY name`).map(mapIndexRow);
}
function loadFeats()   {
  return idxQuery(`SELECT * FROM central_index WHERE type='feat' AND database IN (${dbListSql()}) ORDER BY name`).map(mapIndexRow);
}
function loadTraits()  {
  const rows = idxQuery(`SELECT * FROM central_index WHERE type='trait' AND database IN (${dbListSql()}) ORDER BY name`).map(mapIndexRow);
  // Deduplicate by name — the index can contain the same trait from multiple book DBs
  const seen = new Set();
  return rows.filter(t => {
    const key = (t.name || t._name || '').toLowerCase().trim();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
function loadItems()   {
  return idxQuery(`SELECT * FROM central_index WHERE type='item' AND database IN (${dbListSql()}) ORDER BY name`).map(mapIndexRow);
}
function loadSpellsForClassFromIndex(className) {
  const rows = idxQuery(`
    SELECT ci.*, sli.level as _cls_level
    FROM central_index ci
    JOIN spell_list_index sli ON ci.index_id = sli.index_id
    WHERE ci.type='spell' AND ci.database IN (${dbListSql()}) AND sli.class=?
    ORDER BY sli.level, ci.name`, [className]);
  return rows.map(r => {
    const item = mapIndexRow(r);
    item._class_level = r._cls_level;
    if (!item.levels.find(l=>l.class===className)) item.levels.push({ class:className, level:r._cls_level });
    return item;
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// FULL DETAIL — fetch body + sections from book DB on demand
// ═══════════════════════════════════════════════════════════════════════════
async function loadFullDetail(item) {
  const dbFile = item._db;
  if (!dbFile || !AVAILABLE_DBS.has(dbFile)) return item;
  const sid = item._section_id;
  if (!sid) return item;

  const rows = await bookQuery(dbFile, `SELECT * FROM sections WHERE section_id=?`, [sid]);
  if (!rows.length) return item;
  const row = rows[0];

  // Recursively fetch child sections
  async function fetchChildren(parentId, depth) {
    const kids = await bookQuery(dbFile,
      `SELECT section_id, name, type, subtype, body FROM sections WHERE parent_id=? AND type!='link' ORDER BY lft`,
      [parentId]);
    if (depth <= 0) return kids.map(k=>({...k, sections:[]}));
    return Promise.all(kids.map(async k => ({
      ...k, sections: await fetchChildren(k.section_id, depth-1)
    })));
  }
  const sections = await fetchChildren(sid, 5);

  let extra = {};

  if (item.type === 'class') {
    const cd = await bookQuery(dbFile, `SELECT hit_die, alignment FROM class_details WHERE section_id=?`, [sid]);
    if (cd.length) extra = { ...extra, hit_die: cd[0].hit_die, alignment: cd[0].alignment };

    // Strategy 1: lft/rgt nested set — finds tables nested inside the class section (CR/APG style)
    const lftRgt = await bookQuery(dbFile, `SELECT lft, rgt FROM sections WHERE section_id=?`, [sid]);
    let classTables = [];
    if (lftRgt.length) {
      const { lft, rgt } = lftRgt[0];
      classTables = await bookQuery(dbFile,
        `SELECT section_id, name, type, subtype, body FROM sections
         WHERE lft > ? AND rgt < ? AND type='table' AND name LIKE 'Table:%'
         ORDER BY lft`,
        [lft, rgt]);
    }

    // Strategy 2: index lookup — finds sibling tables with the same class name (ACG style)
    // These are registered separately in central_index with type='table' and matching name.
    // We also match "ClassName %" to pick up companion tables like "Hunter Spells Known",
    // "Bloodrager Spells Known", "Skald Spells Known", "Arcanist Spells Prepared", etc.
    if (classTables.length === 0 && indexDb) {
      const className = item.name || item._name || '';
      const idxRows = idxQuery(
        `SELECT section_id FROM central_index WHERE database=? AND type='table' AND (name=? OR name LIKE ?) ORDER BY section_id`,
        [dbFile, className, className + ' %']);
      if (idxRows.length) {
        const sids = idxRows.map(r => r.section_id);
        for (const tsid of sids) {
          const trows = await bookQuery(dbFile,
            `SELECT section_id, name, type, subtype, body FROM sections WHERE section_id=?`, [tsid]);
          classTables.push(...trows);
        }
      }
    }

    if (classTables.length) extra._classTables = classTables;
  }

  // Item details
  if (item.type === 'item') {
    const id = await bookQuery(dbFile, `SELECT price, weight, slot, aura, cl FROM item_details WHERE section_id=?`, [sid]);
    if (id.length) extra = { ...extra, ...id[0] };
    const md = await bookQuery(dbFile, `SELECT field, subsection, value FROM item_misc WHERE section_id=?`, [sid]);
    if (md.length) {
      const misc = {};
      for (const m of md) { const sec=m.subsection||'null'; if(!misc[sec])misc[sec]={}; misc[sec][m.field]=m.value; }
      extra.misc = misc;
    }
  }

  return { ...item, body: row.body, sections, ...extra };
}

// ─── Cross-book sub-feature loader ────────────────────────────────────────────
// Loads focused/elemental arcane schools and cleric subdomains from book-apg.db,
// grouping them by their associated parent feature (e.g. "conjuration" → [Creation, Teleportation]).
// Elemental schools use the special key "__elemental__".
// Result is attached to item._subFeatures for use by renderSecondaryFeatureList.
async function loadCrossBookSubFeatures(item) {
  const className = (item.name || item._name || '').toLowerCase().trim();
  const sfConfig = CLASS_SECONDARY_TYPES[className];
  if (!sfConfig) return item;

  const src = CROSSBOOK_SUBFEATURE_SOURCES[sfConfig.subtype];
  if (!src || !AVAILABLE_DBS.has(src.db)) return item;

  try {
    const byParent = {};

    for (const subtype of src.subtypes) {
      const rows = await bookQuery(src.db,
        `SELECT section_id, name, subtype, body FROM sections WHERE subtype=? ORDER BY name`,
        [subtype]);

      for (const row of rows) {
        // Fetch direct children (includes "Associated School/Domain" + abilities)
        const children = await bookQuery(src.db,
          `SELECT section_id, name, type, subtype, body FROM sections WHERE parent_id=? ORDER BY lft`,
          [row.section_id]);

        // Find the assoc-field child to get the parent feature name
        const assocChild = children.find(c => c.name === src.assocField);
        const assocName  = assocChild
          ? (assocChild.body || '').replace(/<[^>]+>/g, '').trim().replace(/\.$/, '')
          : '';

        // Fetch one level deeper so abilities/sections have their own children
        const childrenDeep = await Promise.all(children.map(async c => ({
          ...c,
          sections: await bookQuery(src.db,
            `SELECT section_id, name, type, subtype, body FROM sections WHERE parent_id=? ORDER BY lft`,
            [c.section_id])
        })));

        // Parse which parent powers this variant replaces (from "Replacement Power(s)" child)
        const repPowerChild = children.find(c => /^replacement powers?$/i.test(c.name || ''));
        let replaces = [];
        if (repPowerChild) {
          const bodyText = (repPowerChild.body || '').replace(/<[^>]+>/g, '').trim();
          // Match: "replaces the acid dart power and the dimensional steps power of the conjuration school"
          const m = bodyText.match(/replace[s]?\s+the\s+(.*?)(?:\s+of\s+the\b|\.\s*$|$)/i);
          if (m) {
            replaces = m[1]
              .split(/\s+and\s+the\s+|\s+and\s+/i)
              .map(s => s.trim()
                .replace(/\s+powers?$|\s+ability$|\s+abilities$/i, '')
                .toLowerCase())
              .filter(Boolean);
          }
        }

        // Replacement abilities = all children that aren't the "Associated School/Domain"
        // header or the "Replacement Power(s)" text block (those are structural, not actual powers)
        const replacementAbilities = childrenDeep.filter(c =>
          c.name &&
          !/^associated (school|domain)$/i.test(c.name) &&
          !/^replacement powers?$/i.test(c.name)
        );

        const subItem = {
          ...row,
          _db: src.db,
          _parentSubtype: src.parentSubtype,   // used by toggleSecondaryFeature for counting
          associated: assocName,
          sections: childrenDeep,
          replaces,              // e.g. ["acid dart"] or ["acid dart", "dimensional steps"]
          replacementAbilities,  // ability sections to show in place of the replaced ones
        };

        // Elemental schools have no parent school; use a sentinel key
        const key = (subtype === 'elemental_arcane_school')
          ? '__elemental__'
          : assocName.toLowerCase();

        if (!byParent[key]) byParent[key] = [];
        byParent[key].push(subItem);
      }
    }

    return { ...item, _subFeatures: byParent };
  } catch (e) {
    console.warn('loadCrossBookSubFeatures error:', e);
    return item;
  }
}

// Parse a revelation (or similar) body for level-scaling sentences ("At Xth level, ...").
// Returns an HTML string of child rows, with active levels highlighted and future levels grayed.
function parseRevelationScalingHtml(bodyHtml, currentLevel, clsColor) {
  const plain = (bodyHtml || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g,' ').trim();
  if (!plain) return '';

  // Match "At Xth level" / "At Xrd level" / "At Xnd level" / "At Xst level" patterns
  const re = /at\s+(\d+)(?:st|nd|rd|th)\s+level/gi;
  const entries = [];
  let m;
  while ((m = re.exec(plain)) !== null) {
    const lvl = parseInt(m[1]);
    // Extract the sentence: from previous period (or start) to next period
    let start = plain.lastIndexOf('.', m.index);
    start = start < 0 ? 0 : start + 1;
    let end = plain.indexOf('.', m.index + m[0].length);
    end = end < 0 ? plain.length : end + 1;
    const sentence = plain.slice(start, end).trim();
    if (sentence && lvl >= 1 && !entries.some(e => e.level === lvl)) {
      entries.push({ level: lvl, text: sentence });
    }
  }
  if (!entries.length) return '';
  entries.sort((a,b) => a.level - b.level);

  return entries.map(e => {
    const isActive = currentLevel >= e.level;
    const isNew    = isActive && currentLevel === e.level;
    const rowStyle = isActive
      ? `background:${clsColor}12;border-left:2px solid ${clsColor};`
      : `background:rgba(100,100,100,0.05);border-left:2px solid rgba(150,150,150,0.3);opacity:0.65;`;
    const textStyle = isActive
      ? `color:var(--text-primary);`
      : `color:var(--text-muted);font-style:italic;`;
    const icon = isActive ? '✦' : '◇';
    const iconColor = isActive ? clsColor : 'var(--text-muted)';
    const newBadge = isNew
      ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
      : '';
    return `<div style="display:flex;gap:0.5rem;align-items:baseline;padding:0.3rem 0.7rem;margin:2px 0;border-radius:3px;${rowStyle}">
      <span style="color:${iconColor};font-size:0.7rem;flex-shrink:0;">${icon}</span>
      <span style="${textStyle}font-size:0.8rem;line-height:1.4;">
        <strong style="color:${isActive ? clsColor : 'var(--text-muted)'};">Level ${e.level}:</strong>
        ${boldKeyTerms(e.text)}${newBadge}
      </span>
    </div>`;
  }).join('');
}

// Parse a mystery/bloodline/domain bonus-spells string into a level-gated list.
// Format: "spell name (Nth), spell name (Nth), ..." where N is the class level gained.
// Returns HTML rows styled identically to parseRevelationScalingHtml.
function parseMysterySpellsHtml(bonusSpells, clsLevel, clsColor) {
  if (!bonusSpells) return '';
  const entries = [];
  const re = /([^,(]+?)\s*\(\s*(\d+)(?:st|nd|rd|th)\s*\)/gi;
  let m;
  while ((m = re.exec(bonusSpells)) !== null) {
    const name = m[1].trim();
    const reqLevel = parseInt(m[2]);
    if (name && reqLevel >= 1 && !entries.some(e => e.reqLevel === reqLevel)) {
      // Derive the spell's own level: mystery spells come at class levels 2,4,6,8… = spell levels 1,2,3,4…
      const spellLevel = Math.round(reqLevel / 2) || 1;
      const ord = ['1st','2nd','3rd'][spellLevel-1] || `${spellLevel}th`;
      entries.push({ name, reqLevel, spellLevel, ord });
    }
  }
  if (!entries.length) return '';
  entries.sort((a, b) => a.reqLevel - b.reqLevel);

  return entries.map(e => {
    const isActive = clsLevel >= e.reqLevel;
    const isNew    = isActive && clsLevel === e.reqLevel;
    const rowStyle = isActive
      ? `background:${clsColor}12;border-left:2px solid ${clsColor};`
      : `background:rgba(100,100,100,0.05);border-left:2px solid rgba(150,150,150,0.3);opacity:0.65;`;
    const textStyle = isActive ? `color:var(--text-primary);` : `color:var(--text-muted);font-style:italic;`;
    const icon      = isActive ? '✦' : '◇';
    const iconColor = isActive ? clsColor : 'var(--text-muted)';
    const lvlBadge  = isActive ? clsColor : 'var(--text-muted)';
    const newBadge  = isNew
      ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
      : '';
    return `<div style="display:flex;gap:0.5rem;align-items:baseline;padding:0.3rem 0.7rem;margin:2px 0;border-radius:3px;${rowStyle}">
      <span style="color:${iconColor};font-size:0.7rem;flex-shrink:0;">${icon}</span>
      <span style="${textStyle}font-size:0.8rem;line-height:1.4;">
        <strong style="color:${lvlBadge};">Lvl ${e.reqLevel}:</strong>
        ${boldKeyTerms(e.name)}
        <span style="font-size:0.72rem;opacity:0.7;">(${e.ord}-level spell)</span>${newBadge}
      </span>
    </div>`;
  }).join('');
}

// ─── Build class features HTML for the character sheet card ─────────────────
// Parses the progression table to find which features appear at which level,
// then renders collapsible rows for all features gained up to clsLevel.
// Archetype replacements are applied so replaced features show the replacement name.
// ─── Secondary feature body hydrator ─────────────────────────────────────────
// Re-renders sf.body from the class section tree when it's missing (post-save-load).
// Also re-extracts grantedPowers if they have empty bodies.
function _sfBodyFromClass(sf, clsObj, classColor) {
  function _findSec(id, sections) {
    for (const s of (sections || [])) {
      if (!s) continue;
      if (s.section_id === id) return s;
      const found = _findSec(id, s.sections);
      if (found) return found;
    }
    return null;
  }
  const sec = _findSec(sf.id, (clsObj && clsObj.sections) || []);
  if (!sec) return sf.body || '';

  // Re-render body if empty (stripped on save)
  if (!sf.body || !sf.body.trim()) {
    sf.body = renderSecondaryFeatureBody(sec, classColor);
  }
  // Re-extract granted powers with full bodies if they have missing bodies
  if (!sf.grantedPowers || !sf.grantedPowers.length || sf.grantedPowers.every(p => !p.body)) {
    sf.grantedPowers = extractGrantedPowers(sec);
  }
  // Re-extract class skills and notes if missing (safety net for old saves)
  if (!sf.classSkills || !sf.classSkills.length) {
    const annot = extractSFAnnotations(sec);
    sf.classSkills = annot.classSkills;
    if (!sf.skillNotes && annot.skillNotes) sf.skillNotes = annot.skillNotes;
  } else if (!sf.skillNotes) {
    const annot = extractSFAnnotations(sec);
    if (annot.skillNotes) sf.skillNotes = annot.skillNotes;
  }
  return sf.body || '';
}

function buildClassFeaturesHtml(full, clsLevel, archetypes, clsColor, secondaryFeatures, levelChoices, clsName) {
  const plain = s => (s || '').replace(/<[^>]+>/g, '').trim();

  // ── Build archetype replacement map (featureSlug → {replacementName, archName}) ──
  const repMap = {};
  function localParseReplaces(text) {
    const names = [];
    const matches = text.match(/replac(?:es?|ing)\s+(?:the\s+)?(.+?)(?:\s+class feature|\s+ability|\s+bardic performance|\.|$)/gi) || [];
    for (const m of matches) {
      const raw = m.replace(/replac(?:es?|ing)\s+(?:the\s+)?/i,'').replace(/\s+class feature|\s+ability|\s+bardic performance|\./gi,'');
      raw.split(/\s+and\s+|,\s*/).forEach(part => {
        const c = part.trim().toLowerCase().replace(/\s+/g,' ');
        if (c && c.length > 2) names.push(c);
      });
    }
    return names;
  }
  for (const arch of (archetypes || [])) {
    const data = archetypeCache[arch.path];
    if (!data || !Array.isArray(data.sections)) continue;
    (function walk(secs) {
      for (const feat of secs) {
        if (!feat) continue;
        const txt = plain(feat.body);
        for (const name of localParseReplaces(txt)) {
          const slug = name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
          if (!repMap[slug]) repMap[slug] = { replacementName: feat.name, archName: arch.name, archPath: arch.path, replacementBody: plain(feat.body) };
        }
        if (Array.isArray(feat.sections)) walk(feat.sections);
      }
    })(data.sections);
  }

  // ── Parse the progression table to get level→[featureNames] ──────────────
  // We need the raw table body from full._classTables
  const levelFeatures = {}; // level (int) → Set of feature name strings
  for (const t of (full._classTables || [])) {
    if (!t.body) continue;
    const tableHtml = t.body;
    // Find Special column index
    const theadM = tableHtml.match(/<thead>([\s\S]*?)<\/thead>/i);
    if (!theadM) continue;
    const firstRow = theadM[1].match(/<tr[^>]*>([\s\S]*?)<\/tr>/i);
    if (!firstRow) continue;
    const ths = [...firstRow[1].matchAll(/<th[^>]*>([\s\S]*?)<\/th>/gi)];
    let specIdx = -1;
    ths.forEach((m, i) => { if (m[1].replace(/<[^>]+>/g,'').trim().toLowerCase() === 'special') specIdx = i; });
    if (specIdx < 0) continue;

    // Walk every data row
    const rowRe = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let rm;
    while ((rm = rowRe.exec(tableHtml)) !== null) {
      const cells = [...rm[1].matchAll(/<td[^>]*>([\s\S]*?)<\/td>/gi)];
      if (!cells.length) continue;
      const lvlText = cells[0]?.[1].replace(/<[^>]+>/g,'').trim();
      const lvl = parseInt(lvlText);
      if (!lvl || lvl < 1 || lvl > 20) continue;
      if (specIdx >= cells.length) continue;
      const specText = cells[specIdx][1].replace(/<[^>]+>/g,'').trim();
      if (!specText || specText === '—' || specText === '&mdash;') continue;
      if (!levelFeatures[lvl]) levelFeatures[lvl] = [];
      specText.split(',').forEach(part => {
        const name = part.trim().replace(/\s*(\+\d+|\d+\/day)$/i,'').trim();
        if (name && name !== '—' && name.length > 1) levelFeatures[lvl].push(name);
      });
    }
  }

  // ── Custom class features — rendered from metadata.features ──────────────
  if (full && full.isCustom && full._customId) {
    const _ccEntry = (character.customContent || []).find(c => c.id === full._customId);
    if (_ccEntry && _ccEntry.metadata && _ccEntry.metadata.features && _ccEntry.metadata.features.length) {
      const clsCol = clsColor || '#7ac87a';
      let html = '<div>';
      for (const feat of _ccEntry.metadata.features) {
        const typeTag = feat.type ? ` <span style="color:var(--text-muted);font-size:0.6rem;font-family:sans-serif;">${feat.type}</span>` : '';
        const bodyHtml = feat.body ? `<div class="char-cf-row-body" style="display:none;">${feat.body.replace(/\n/g, '<br>')}</div>` : '';
        html += `
        <div class="char-cf-row" style="border-left:3px solid ${clsCol};">
          <div class="char-cf-row-header" onclick="event.stopPropagation();(function(h){const b=h.nextElementSibling,a=h.querySelector('.char-cf-arr');if(!b)return;const open=b.style.display!=='block';b.style.display=open?'block':'none';a.style.transform=open?'rotate(90deg)':'rotate(0deg)';})(this)">
            <span class="char-cf-arr" style="color:${clsCol};">▸</span>
            <span class="char-cf-name">${feat.name}${typeTag}</span>
          </div>
          ${bodyHtml}
        </div>`;
      }
      html += '</div>';
      return html;
    }
    return ''; // Custom class with no parsed features yet
  }

  if (!Object.keys(levelFeatures).length) return '';

  // ── Build feature lookup from sections (moved up so sfAdditionsHtml can use it) ────
  const featureMap = {};
  if (Array.isArray(full.sections)) {
    for (const sec of full.sections) {
      if (!sec || sec.type === 'link') continue;
      if (sec.name && /class features?/i.test(sec.name)) {
        for (const feat of (sec.sections || [])) {
          if (feat && feat.name) featureMap[feat.name.toLowerCase().trim()] = feat;
        }
      }
    }
  }

  // Features promoted to "From Selections" — skip them in the per-level list
  const skipInLevelFeatures = new Set();

  // ── Secondary-feature additions banner (class skills, bonus spells from mysteries, etc.) ──
  let sfAdditionsHtml = '';
  {
    // Collect top-level secondary features only (skip subdomains / focused schools)
    const topSFs = (secondaryFeatures || []).filter(sf => !sf.parentSectionId);

    // Aggregate shared class-skill additions across ALL selections
    const sfClassSkills = [];
    for (const sf of topSFs) {
      if (sf.classSkills && sf.classSkills.length) sfClassSkills.push(...sf.classSkills);
    }

    // Map: SF subtype → which level-choice subtypes should nest under it
    const SF_NESTED_CHOICE_SUBTYPES = {
      'oracle_mystery': ['oracle_revelation'],
    };

    const topChoicesAll = (levelChoices || []).filter(lc => lc.level <= clsLevel);

    // Build a set of all subtypes that are claimed by some SF so we can split the list
    const claimedSubtypes = new Set();
    for (const sf of topSFs) {
      for (const sub of (SF_NESTED_CHOICE_SUBTYPES[sf.subtype] || [])) claimedSubtypes.add(sub);
    }
    // Standalone = choices whose subtype is NOT claimed by any SF
    const standaloneChoices = topChoicesAll.filter(lc => !claimedSubtypes.has(lc.subtype));

    const bardicPerfSection = featureMap['bardic performance'] || null;
    // Bardic Performance parent still appears under Level 1, but its individual sub-performances
    // (Countersong, Distraction, Fascinate, etc.) and their archetype replacements (Sea Shanty, etc.)
    // are managed in From Selections, so skip them from the per-level list.
    if (bardicPerfSection) {
      for (const sub of (bardicPerfSection.sections || []).filter(s => s && s.type !== 'link' && s.name)) {
        const origKey  = sub.name.toLowerCase().trim();
        const origSlug = origKey.replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
        skipInLevelFeatures.add(origKey);
        // Also skip the archetype replacement name for this sub (e.g. "sea shanty" for "countersong")
        const rep = repMap[origSlug];
        if (rep) skipInLevelFeatures.add(rep.replacementName.toLowerCase().trim());
      }
    }

    // Helper: parse the unlock level from a bardic performance sub-feature body
    const parseBpUnlockLevel = (bodyText) => {
      const text = (bodyText || '').replace(/<[^>]+>/g, '');
      // "A bard of 3rd level or higher" / "Starting at 3rd level" / "At 3rd level"
      const m = text.match(/(?:a\s+bard\s+of\s+|starting\s+at\s+|(?<!\w)at\s+)(\d+)(?:st|nd|rd|th)\s+level/i);
      if (m) return parseInt(m[1]);
      return 1; // default — assume unlocked at 1st level
    };

    if (topSFs.length > 0 || topChoicesAll.length > 0 || !!bardicPerfSection) {
      sfAdditionsHtml += `<div class="char-cf-level-group" style="background:rgba(201,168,76,0.04);border:1px solid rgba(201,168,76,0.18);border-radius:4px;margin-bottom:0.5rem;padding:0.4rem 0.75rem 0.5rem;">`;
      sfAdditionsHtml += `<div class="char-cf-level-label" style="color:var(--gold);font-size:0.62rem;letter-spacing:0.1em;">From Selections</div>`;

      // Toggle helper (inline) for From Selections rows
      const sfToggle = `event.stopPropagation();(function(h){const b=h.nextElementSibling,a=h.querySelector('.char-cf-arr');const open=b.style.display!=='block';b.style.display=open?'block':'none';a.style.transform=open?'rotate(90deg)':'rotate(0deg)';})(this)`;

      // ── One row per top-level selection (mystery, school, bloodline) + its nested sub-rows ──
      for (const sf of topSFs) {
        const typeLabel = SECONDARY_SUBTYPE_LABELS[sf.subtype] || sf.subtype.replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase());
        // Hydrate body from class section tree if missing (stripped on save)
        const sfBodyRendered = _sfBodyFromClass(sf, full, clsColor);
        const hasBody   = !!(sfBodyRendered && sfBodyRendered.trim());

        // Main selection row — collapsed by default
        sfAdditionsHtml += `
          <div class="char-cf-row" style="border-left:3px solid ${clsColor};">
            <div class="char-cf-row-header" onclick="${sfToggle}" style="cursor:pointer;">
              <span class="char-cf-arr" style="color:${clsColor};">▸</span>
              <span class="char-cf-name">${sf.name}</span>
              <span class="char-cf-replaced" style="margin-left:0.5rem;">${typeLabel}</span>
            </div>
            <div class="char-cf-row-body">
              ${hasBody
                ? sfBodyRendered
                : `<span style="color:var(--text-muted);font-style:italic;">No description available.</span>`}
            </div>
          </div>`;

        // ── Sub-feature rows: Bonus Spells, Granted Powers, and nested level choices ──
        // All grouped and indented, expanded by default
        const spellsHtml    = parseMysterySpellsHtml(sf.bonusSpells, clsLevel, clsColor);
        const grantedPowers = sf.grantedPowers || [];
        const powersHtml    = grantedPowers.length ? buildGrantedPowersHtml(grantedPowers, clsLevel, clsColor) : '';

        // Level choices that belong to this SF (e.g. revelations under oracle mystery)
        const nestedSubtypes = SF_NESTED_CHOICE_SUBTYPES[sf.subtype] || [];
        const nestedChoices  = topChoicesAll.filter(lc => nestedSubtypes.includes(lc.subtype));

        const hasSubRows = spellsHtml || powersHtml || nestedChoices.length > 0;
        if (hasSubRows) {
          sfAdditionsHtml += `<div style="margin-top:0.15rem;margin-left:0.6rem;padding-left:0.5rem;border-left:2px solid ${clsColor}30;display:flex;flex-direction:column;gap:0.2rem;margin-bottom:0.3rem;">`;

          // Bonus Spells — expanded by default, collapsible
          if (spellsHtml) {
            // "New!" if any spell in the list unlocks exactly at clsLevel
            const _spellRe  = /\(\s*(\d+)(?:st|nd|rd|th)\s*\)/gi;
            const _spellLvls = [];
            let _spellM;
            while ((_spellM = _spellRe.exec(sf.bonusSpells || '')) !== null) _spellLvls.push(parseInt(_spellM[1]));
            const spellsIsNew  = _spellLvls.includes(clsLevel);
            const spellsNewBadge = spellsIsNew
              ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
              : '';
            sfAdditionsHtml += `
              <div class="char-cf-row" style="border-left:3px solid ${clsColor}55;">
                <div class="char-cf-row-header" onclick="${sfToggle}" style="cursor:pointer;padding-bottom:0.3rem;">
                  <span class="char-cf-arr" style="color:${clsColor};transform:rotate(90deg);">▸</span>
                  <span class="char-cf-name" style="font-size:0.82rem;">Bonus Spells</span>${spellsNewBadge}
                </div>
                <div class="char-cf-row-body" style="display:block;padding-top:0.1rem;">
                  ${spellsHtml}
                </div>
              </div>`;
          }

          // Granted Powers — expanded by default, collapsible
          if (powersHtml) {
            // "New!" if any power unlocks exactly at clsLevel, or has a scaling
            // milestone in its body that fires at clsLevel
            const _pwrScalingRe = /at\s+(\d+)(?:st|nd|rd|th)\s+level|starting at\s+(\d+)(?:st|nd|rd|th)\s+level/gi;
            const powersIsNew = grantedPowers.some(p => {
              if (p.reqLevel === clsLevel) return true;
              const _plain = (p.body || '').replace(/<[^>]+>/g, ' ');
              let _m;
              _pwrScalingRe.lastIndex = 0;
              while ((_m = _pwrScalingRe.exec(_plain)) !== null) {
                if (parseInt(_m[1] || _m[2]) === clsLevel) return true;
              }
              return false;
            });
            const powersNewBadge = powersIsNew
              ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
              : '';
            sfAdditionsHtml += `
              <div class="char-cf-row" style="border-left:3px solid ${clsColor}55;">
                <div class="char-cf-row-header" onclick="${sfToggle}" style="cursor:pointer;padding-bottom:0.3rem;">
                  <span class="char-cf-arr" style="color:${clsColor};transform:rotate(90deg);">▸</span>
                  <span class="char-cf-name" style="font-size:0.82rem;">${sf.name} Powers</span>${powersNewBadge}
                </div>
                <div class="char-cf-row-body" style="display:block;padding-top:0.1rem;">
                  ${powersHtml}
                </div>
              </div>`;
          }

          // Nested level choices (e.g. Revelations under Battle Mystery) — collapsed by default
          for (const lc of nestedChoices) {
            const choiceBodyHtml = lc.bodyHtml || '';
            const scalingHtml    = parseRevelationScalingHtml(choiceBodyHtml, clsLevel, clsColor);
            const hasScaling     = !!scalingHtml;
            const hasLcBody      = !!choiceBodyHtml.trim();
            // Show "New!" if the revelation was just picked at this level, OR if any
            // scaling milestone inside the body fires exactly at the current level.
            const _scalingRe    = /at\s+(\d+)(?:st|nd|rd|th)\s+level/gi;
            const _plainBody    = choiceBodyHtml.replace(/<[^>]+>/g, ' ');
            let _sm;
            const _scalingLvls  = [];
            while ((_sm = _scalingRe.exec(_plainBody)) !== null) _scalingLvls.push(parseInt(_sm[1]));
            const lcIsNew       = lc.level === clsLevel || _scalingLvls.includes(clsLevel);
            const lcNewBadge    = lcIsNew
              ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
              : '';
            sfAdditionsHtml += `
              <div class="char-cf-row" style="border-left:3px solid ${clsColor}55;">
                <div class="char-cf-row-header" onclick="${sfToggle}" style="cursor:pointer;">
                  <span class="char-cf-arr" style="color:${clsColor};">▸</span>
                  <span class="char-cf-name" style="font-size:0.85rem;">${lc.name}</span>
                  <span class="char-cf-replaced" style="margin-left:0.5rem;">${lc.label}</span>${lcNewBadge}
                  <span class="char-cf-replaced" style="margin-left:auto;font-size:0.6rem;color:${clsColor};">Lvl ${lc.level}</span>
                </div>
                <div class="char-cf-row-body">
                  ${hasLcBody ? `<div style="margin-bottom:${hasScaling ? '0.6rem' : '0'};">${choiceBodyHtml}</div>` : ''}
                  ${hasScaling ? `
                    <div style="border-top:1px solid ${clsColor}30;padding-top:0.4rem;margin-top:0.2rem;">
                      <div style="font-size:0.65rem;color:${clsColor};letter-spacing:0.08em;text-transform:uppercase;margin-bottom:0.3rem;">Scaling</div>
                      ${scalingHtml}
                    </div>` : ''}
                  ${!hasLcBody && !hasScaling ? `<span style="color:var(--text-muted);font-style:italic;font-size:0.8rem;">No description available.</span>` : ''}
                </div>
              </div>`;
          }

          sfAdditionsHtml += `</div>`;
        }
      }

      // ── Standalone level choices (not claimed by any SF) ──────────────────────
      for (const lc of standaloneChoices) {
        const choiceBodyHtml = lc.bodyHtml || '';
        const scalingHtml    = parseRevelationScalingHtml(choiceBodyHtml, clsLevel, clsColor);
        const hasScaling     = !!scalingHtml;
        const hasBody        = !!choiceBodyHtml.trim();
        // Find the index in the original levelChoices array for Replace/edit functionality
        const lcIdx = (levelChoices || []).indexOf(lc);
        // Check if this choice type is a feat (can be replaced)
        const clsNameLower = (clsName || '').toLowerCase().trim();
        const lcChoiceType = (CLASS_LEVEL_CHOICES[clsNameLower] || {})[lc.key];
        const isReplaceable = !!(lcChoiceType && lcChoiceType.isFeat) && lcIdx >= 0;
        const safeClsName = (clsName || '').replace(/'/g, "\\'");
        const replaceBtn = isReplaceable
          ? `<button onclick="event.stopPropagation();editLevelChoice('${safeClsName}',${lcIdx})"
               style="margin-left:auto;flex-shrink:0;background:transparent;border:1px solid ${clsColor}66;border-radius:5px;
                      color:${clsColor};font-family:Cinzel,serif;font-size:0.62rem;padding:0.2rem 0.55rem;
                      cursor:pointer;transition:background 0.15s,color 0.15s;"
               onmouseover="this.style.background='${clsColor}22'"
               onmouseout="this.style.background='transparent'">Replace</button>`
          : `<span class="char-cf-replaced" style="margin-left:auto;font-size:0.6rem;color:${clsColor};">Lvl ${lc.level}</span>`;
        sfAdditionsHtml += `
          <div class="char-cf-row" style="border-left:3px solid ${clsColor}88;">
            <div class="char-cf-row-header" onclick="${sfToggle}" style="cursor:pointer;">
              <span class="char-cf-arr" style="color:${clsColor};">▸</span>
              <span class="char-cf-name">${lc.name}</span>
              <span class="char-cf-replaced" style="margin-left:0.5rem;">${lc.label}</span>
              ${isReplaceable
                ? `<span class="char-cf-replaced" style="margin-left:0.35rem;font-size:0.6rem;color:${clsColor};">Lvl ${lc.level}</span>`
                : ''}
              ${replaceBtn}
            </div>
            <div class="char-cf-row-body">
              ${hasBody ? `<div style="margin-bottom:${hasScaling ? '0.6rem' : '0'};">${choiceBodyHtml}</div>` : ''}
              ${hasScaling ? `
                <div style="border-top:1px solid ${clsColor}30;padding-top:0.4rem;margin-top:0.2rem;">
                  <div style="font-size:0.65rem;color:${clsColor};letter-spacing:0.08em;text-transform:uppercase;margin-bottom:0.3rem;">Scaling</div>
                  ${scalingHtml}
                </div>` : ''}
              ${!hasBody && !hasScaling ? `<span style="color:var(--text-muted);font-style:italic;font-size:0.8rem;">No description available.</span>` : ''}
            </div>
          </div>`;
      }

      // ── Bardic Performance: show individual performances unlocked at/below current level ──
      if (bardicPerfSection) {
        const allBpSubs = (bardicPerfSection.sections || []).filter(s => s && s.type !== 'link' && s.name);
        // Only show performances the bard has actually unlocked at their current level
        const unlockedBpSubs = allBpSubs.filter(sub => parseBpUnlockLevel(sub.body || '') <= clsLevel);

        if (unlockedBpSubs.length > 0) {
          sfAdditionsHtml += `<div style="margin-top:0.2rem;display:flex;flex-direction:column;gap:0.2rem;">`;
          for (const sub of unlockedBpSubs) {
            const subSlug = sub.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
            const bpRep   = repMap[subSlug] || null;  // archetype replacement for this sub, if any

            const isNewAtThisLevel = parseBpUnlockLevel(sub.body || '') === clsLevel;
            const newBadge = isNewAtThisLevel
              ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
              : '';
            const archBadge = bpRep
              ? `<span style="font-size:0.5rem;background:var(--gold-dark);color:#fff;border-radius:3px;padding:1px 5px;font-family:Cinzel,serif;letter-spacing:0.06em;text-transform:uppercase;margin-left:0.4rem;vertical-align:middle;">via ${bpRep.archName}</span>`
              : '';

            // Show replacement name/body if archetype has replaced this performance
            const displayName = bpRep ? bpRep.replacementName : sub.name;
            const subBodyLines = [];
            if (bpRep) {
              if (bpRep.replacementBody) subBodyLines.push(`<div style="color:var(--text-secondary);font-size:0.88rem;line-height:1.6;">${boldKeyTerms(bpRep.replacementBody)}</div>`);
            } else {
              const subTop = plain(sub.body || '');
              if (subTop) subBodyLines.push(`<div style="color:var(--text-secondary);font-size:0.88rem;line-height:1.6;">${boldKeyTerms(subTop)}</div>`);
              for (const deep of (sub.sections || []).filter(d => d && d.type !== 'link')) {
                const deepBody = plain(deep.body || '');
                if (deep.name) subBodyLines.push(`<div style="font-family:Cinzel,serif;color:var(--gold-dark);font-size:0.74rem;text-transform:uppercase;letter-spacing:0.06em;margin-top:0.4rem;margin-bottom:0.1rem;">${deep.name}</div>`);
                if (deepBody) subBodyLines.push(`<div style="color:var(--text-secondary);font-size:0.85rem;line-height:1.55;">${boldKeyTerms(deepBody)}</div>`);
              }
            }
            sfAdditionsHtml += `
              <div style="border:1px solid var(--border);border-left:2px solid ${clsColor}88;border-radius:0 4px 4px 0;overflow:hidden;margin-bottom:0.1rem;">
                <div style="display:flex;align-items:center;gap:0.5rem;padding:0.4rem 0.75rem;background:var(--bg-card);cursor:pointer;transition:background 0.15s;"
                     onclick="(function(el){const b=el.nextElementSibling;const a=el.querySelector('.cfsub-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)"
                     onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-card)'">
                  <span class="cfsub-arr" style="color:${clsColor}99;font-size:0.7rem;width:10px;flex-shrink:0;">▸</span>
                  <span style="font-family:Cinzel,serif;color:var(--text-secondary);font-size:0.8rem;flex:1;">${displayName}${archBadge}${newBadge}</span>
                </div>
                <div style="display:none;padding:0.5rem 0.9rem 0.5rem 1.35rem;background:var(--bg-surface);border-top:1px solid var(--border);">
                  ${subBodyLines.join('') || '<span style="color:var(--text-muted);font-size:0.82rem;font-style:italic;">No description available.</span>'}
                </div>
              </div>`;
          }
          sfAdditionsHtml += `</div>`;
        }
      }

      sfAdditionsHtml += `</div>`;
    }
  }

  // (No level-choice lookup needed for feature rows — chosen names appear in "From Selections" above)

  // Detect whether any archetypes have modified Bardic Performance (sub-replacements or additions)
  const bardicPerfSection4Badge = featureMap['bardic performance'] || null;
  const bpHasArchMods = !!(bardicPerfSection4Badge && (
    (bardicPerfSection4Badge.sections || []).some(sub => {
      const slug = sub.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
      return repMap[slug] != null;
    }) ||
    Object.values(repMap).some(rep => (rep.replacementBody || '').toLowerCase().includes('bardic performance'))
  ));

  // ── Render levels 1..clsLevel ─────────────────────────────────────────────
  let html = '';
  const renderedNames = new Set(); // avoid dupes (e.g. "+1 level of class" repeated)

  for (let lvl = 1; lvl <= clsLevel; lvl++) {
    const names = levelFeatures[lvl];
    if (!names || !names.length) continue;

    // Filter out pure numeric/bonus entries, dedupes, and features promoted to From Selections
    const unique = names.filter(n => {
      const k = n.toLowerCase().trim();
      if (renderedNames.has(k)) return false;
      if (/^[+\-]\d+$/.test(n)) return false;
      if (skipInLevelFeatures.has(k)) return false;
      renderedNames.add(k);
      return true;
    });
    if (!unique.length) continue;

    const isCurrentLvl = lvl === clsLevel;
    html += `<div class="char-cf-level-group">`;
    html += `<div class="char-cf-level-label" style="${isCurrentLvl ? `color:${clsColor};font-weight:700;` : ''}">Level ${lvl}${isCurrentLvl ? ' ★' : ''}</div>`;

    for (const rawName of unique) {
      const slug = rawName.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
      const repInfo = repMap[slug];

      // Resolve: archetype replacement or original feature
      let displayName = rawName;
      let replacedBadge = '';
      let featSection = featureMap[rawName.toLowerCase().trim()];

      if (repInfo) {
        // Replaced — show replacement name, grey out original
        displayName = repInfo.replacementName;
        replacedBadge = `<span class="char-cf-replaced" title="Replaces: ${rawName}">via ${repInfo.archName}</span>`;
        // Try base class feature map first, then fall back to the archetype's own sections
        featSection = featureMap[repInfo.replacementName.toLowerCase().trim()] || null;
        if (!featSection && repInfo.archPath && archetypeCache[repInfo.archPath]) {
          const archData = archetypeCache[repInfo.archPath];
          const repNameLower = repInfo.replacementName.toLowerCase().trim();
          // Walk archetype sections to find the matching feature by name
          (function findInArch(secs) {
            for (const s of (secs || [])) {
              if (!s) continue;
              if (s.name && s.name.toLowerCase().trim() === repNameLower) {
                featSection = s;
                return;
              }
              if (!featSection && Array.isArray(s.sections)) findInArch(s.sections);
            }
          })(archData.sections);
        }
      } else if (rawName.toLowerCase().trim() === 'bardic performance' && bpHasArchMods) {
        // Bardic Performance itself is not replaced, but archetypes have modified its sub-performances
        replacedBadge = `<span style="font-size:0.55rem;background:rgba(201,168,76,0.18);color:var(--gold);border:1px solid rgba(201,168,76,0.45);border-radius:3px;padding:1px 7px;font-family:Cinzel,serif;letter-spacing:0.06em;text-transform:uppercase;margin-left:0.35rem;vertical-align:middle;">Archetype Modified</span>`;
      }

      // Build body content
      let bodyHtml = '';
      if (featSection) {
        const top = plain(featSection.body);
        if (top) bodyHtml += `<div style="margin-bottom:0.35rem;">${boldKeyTerms(top)}</div>`;
        const subs = (featSection.sections || []).filter(s => s && s.type !== 'link' && s.name);
        for (const sub of subs) {
          const subBody = plain(sub.body);
          bodyHtml += `<div style="font-family:Cinzel,serif;font-size:0.68rem;color:var(--gold-dark);text-transform:uppercase;letter-spacing:0.06em;margin-top:0.3rem;">${sub.name}</div>`;
          if (subBody) bodyHtml += `<div style="margin-bottom:0.2rem;">${boldKeyTerms(subBody)}</div>`;
        }
      } else {
        bodyHtml = '<span style="color:var(--text-muted);font-style:italic;">No description loaded — open the class detail for full text.</span>';
      }

      const uid = `ccf-${slug}-${lvl}-${Math.random().toString(36).slice(2,6)}`;
      html += `
        <div class="char-cf-row" style="border-left:3px solid ${clsColor};">
          <div class="char-cf-row-header" onclick="event.stopPropagation();(function(h){const b=h.nextElementSibling,a=h.querySelector('.char-cf-arr');const open=b.style.display!=='block';b.style.display=open?'block':'none';a.style.transform=open?'rotate(90deg)':'rotate(0deg)';})(this)">
            <span class="char-cf-arr" style="color:${clsColor};">▸</span>
            <span class="char-cf-name">${displayName}</span>
            ${replacedBadge}
          </div>
          <div class="char-cf-row-body">${bodyHtml}</div>
        </div>`;
    }
    html += `</div>`;
  }

  return sfAdditionsHtml + html;
}

// Apply archetype feature replacements to a live table element.
// Takes the table DOM element and an explicit archetypes array (from character.classes[i].archetypes).
// Does NOT rely on selectedArchetypes or the detail-panel DOM.
function applyArchetypeReplacementsToTable(tableEl, archetypes) {
  if (!tableEl || !archetypes || !archetypes.length) return;

  // Inline parseReplaces (mirrors buildArchetypeReplacementMap's closure)
  function parseReplaces(text) {
    const names = [];
    const matches = text.match(/replac(?:es?|ing)\s+(?:the\s+)?(.+?)(?:\s+class feature|\s+ability|\s+bardic performance|\.|$)/gi) || [];
    for (const m of matches) {
      const raw = m
        .replace(/replac(?:es?|ing)\s+(?:the\s+)?/i, '')
        .replace(/\s+class feature|\s+ability|\s+bardic performance|\./gi, '');
      raw.split(/\s+and\s+|,\s*/).forEach(part => {
        const clean = part.trim().toLowerCase().replace(/\s+/g, ' ');
        if (clean && clean.length > 2) names.push(clean);
      });
    }
    return names;
  }

  // Build a slug->replacementName map from the archetype cache
  const tableRepMap = {};
  for (const arch of archetypes) {
    const data = archetypeCache[arch.path];
    if (!data || !Array.isArray(data.sections)) continue;
    function walk(sections) {
      for (const feat of sections) {
        if (!feat) continue;
        const text = (feat.body || '').replace(/<[^>]+>/g, '');
        const names = parseReplaces(text);
        for (const name of names) {
          const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
          if (!tableRepMap[slug]) {
            tableRepMap[slug] = { replacementName: feat.name, archName: arch.name };
          }
        }
        if (Array.isArray(feat.sections) && feat.sections.length) walk(feat.sections);
      }
    }
    walk(data.sections);
  }

  if (!Object.keys(tableRepMap).length) return;

  // Patch every feature anchor in the table's Special column
  tableEl.querySelectorAll('a[data-feature]').forEach(a => {
    const slug = a.dataset.feature;
    const rep  = tableRepMap[slug];
    if (!rep) return;

    // Hide original, insert replacement span
    a.style.display = 'none';
    const ins = document.createElement('span');
    ins.className = 'table-replacement-insert';
    ins.title = `${rep.replacementName} — via ${rep.archName} archetype`;
    ins.style.cssText = 'color:var(--gold-light);font-style:italic;font-size:0.9em;border-bottom:1px dashed var(--gold);cursor:default;';
    ins.textContent = rep.replacementName;
    a.after(ins);
  });
}

// Highlight the row matching the character's current class level in a processed table
function highlightClassTableLevel(html, level) {
  if (!level || level < 1) return html;
  const targetLevel = parseInt(level);

  // processClassTable emits <tr class="odd"> / <tr class="even"> rows.
  // Browsers don't propagate background from <tr> to <td> when the <td>
  // already has a background set via CSS — so we must style each <td> directly.
  return html.replace(/(<tr[^>]*>)([\s\S]*?)(<\/tr>)/gi, (match, trOpen, inner, trClose) => {
    // Skip header rows
    if (inner.indexOf('<th') !== -1) return match;
    // Check first <td> text is the target level number
    const firstTdM = inner.match(/<td[^>]*>([\s\S]*?)<\/td>/i);
    if (!firstTdM) return match;
    const cellText = firstTdM[1].replace(/<[^>]+>/g, '').trim();
    if (parseInt(cellText) !== targetLevel) return match;

    // Stamp highlight background on every <td> in this row.
    // First <td> also gets the ★ prefix.
    let isFirst = true;
    const highlightedInner = inner.replace(/<td([^>]*)>([\s\S]*?)<\/td>/gi, (m, attrs, text) => {
      const prefix = isFirst ? '<span style="color:var(--gold);font-weight:700;margin-right:2px;">&#9733;</span>' : '';
      isFirst = false;
      return '<td' + attrs + ' style="background:rgba(201,168,76,0.16)!important;' +
             'border-top:1px solid rgba(201,168,76,0.55)!important;' +
             'border-bottom:1px solid rgba(201,168,76,0.55)!important;">' +
             prefix + text + '</td>';
    });
    return trOpen + highlightedInner + trClose;
  });
}
// Walk a sections tree looking for a class progression table (kept for reference)
function findTableInSections(sections, className) {
  for (const s of (sections || [])) {
    if (s.type === 'table' && s.name && s.name.toLowerCase().includes('table:')) return true;
    if (s.body && s.body.trim().startsWith('<table')) return true;
    if (findTableInSections(s.sections, className)) return true;
  }
  return false;
}

// ═══════════════════════════════════════════════════════════════════════════
// WEAPON/ARMOR MISC LOOKUP — built from book DBs at startup
// Maps lowercase item name → weapon or armor classification data
let weaponMiscMap = {};
let armorMiscMap  = {};
let weaponBodyMap = {}; // lowercase name → description text for card
let armorBodyMap  = {}; // lowercase name → description text for card
let itemBodyMap   = {}; // lowercase name → description for magic/goods items
let itemPriceMap  = {}; // lowercase name → price string
let itemSlotMap   = {}; // lowercase name → slot (magic items)
let itemAuraMap   = {}; // lowercase name → aura
let itemClMap     = {}; // lowercase name → caster level
let itemWeightMap = {}; // lowercase name → weight in lbs (number)

async function buildWeaponArmorMaps() {
  for (const dbFile of DB_FILES) {
    // Weapon stats
    try {
      const wrows = await bookQuery(dbFile, `
        SELECT s.name,
          MAX(CASE WHEN im.field='Proficiency'  THEN im.value END) as prof,
          MAX(CASE WHEN im.field='Weapon Class' THEN im.value END) as wc,
          MAX(CASE WHEN im.field='Range'        THEN im.value END) as range_inc,
          MAX(CASE WHEN im.field='Critical'     THEN im.value END) as critical,
          MAX(CASE WHEN im.field='Type'         THEN im.value END) as dmg_type,
          MAX(CASE WHEN im.field='Special'      THEN im.value END) as special,
          MAX(CASE WHEN im.field='Dmg (S)'      THEN im.value END) as dmg_s,
          MAX(CASE WHEN im.field='Dmg (M)'      THEN im.value END) as dmg_m,
          MAX(CASE WHEN im.field='Dmg (L)'      THEN im.value END) as dmg_l,
          MAX(CASE WHEN im.field='Dmg (T)'      THEN im.value END) as dmg_t,
          s.body, d.price
        FROM sections s
        JOIN item_misc im ON s.section_id=im.section_id
        LEFT JOIN item_details d ON s.section_id=d.section_id
        WHERE im.subsection='Weapon' GROUP BY s.name`);
      for (const r of wrows) {
        const k = (r.name||'').toLowerCase();
        if (!weaponMiscMap[k]) weaponMiscMap[k] = {
          prof: r.prof, wc: r.wc, range: r.range_inc,
          critical: r.critical, dmgType: r.dmg_type, special: r.special,
          dmgS: r.dmg_s, dmgM: r.dmg_m, dmgL: r.dmg_l, dmgT: r.dmg_t
        };
        if (!weaponBodyMap[k] && r.body) {
          const text = r.body.replace(/<[^>]+>/g,'').trim();
          if (text) weaponBodyMap[k] = text;
        }
        if (!itemPriceMap[k] && r.price) itemPriceMap[k] = r.price;
      }
    } catch(e) { console.warn('buildWeaponArmorMaps weapon:', dbFile, e.message); }

    // Armor stats
    try {
      const arows = await bookQuery(dbFile, `
        SELECT s.name,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Armor Type'                  THEN im.value END) as armor_type,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Armor Bonus'                 THEN im.value END) as armor_bonus,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Shield Bonus'                THEN im.value END) as shield_bonus,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Maximum Dex Bonus'           THEN im.value END) as max_dex,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Armor Check Penalty'         THEN im.value END) as check_penalty,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Arcane Spell Failure Chance' THEN im.value END) as spell_failure,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Speed (20 ft.)'              THEN im.value END) as speed20,
          MAX(CASE WHEN im.subsection='Armor' AND im.field='Speed (30 ft.)'              THEN im.value END) as speed30,
          s.body, d.price
        FROM sections s
        JOIN item_misc im ON s.section_id=im.section_id
        LEFT JOIN item_details d ON s.section_id=d.section_id
        WHERE im.subsection='Armor' GROUP BY s.name`);
      for (const r of arows) {
        const k = (r.name||'').toLowerCase();
        if (!armorMiscMap[k]) armorMiscMap[k] = {
          armorType: r.armor_type,
          armorBonus: r.armor_bonus || r.shield_bonus,
          maxDex: r.max_dex, checkPenalty: r.check_penalty,
          spellFailure: r.spell_failure, speed20: r.speed20, speed30: r.speed30
        };
        if (!armorBodyMap[k] && r.body) {
          const text = r.body.replace(/<[^>]+>/g,'').trim();
          if (text) armorBodyMap[k] = text;
        }
        if (!itemPriceMap[k] && r.price) itemPriceMap[k] = r.price;
      }
    } catch(e) { console.warn('buildWeaponArmorMaps armor:', dbFile, e.message); }

    // Item body text, price, slot, aura, CL for all items
    try {
      const irows = await bookQuery(dbFile, `
        SELECT s.name, s.body, d.price, d.slot, d.aura, d.cl, d.weight
        FROM sections s
        LEFT JOIN item_details d ON s.section_id=d.section_id
        WHERE s.type='item'`);
      for (const r of irows) {
        const k = (r.name||'').toLowerCase();
        if (!itemBodyMap[k] && r.body) {
          const text = r.body.replace(/<[^>]+>/g,'').trim();
          if (text) itemBodyMap[k] = text;
        }
        if (!itemPriceMap[k] && r.price) itemPriceMap[k] = r.price;
        if (!itemSlotMap[k] && r.slot && r.slot !== 'none' && r.slot !== '&mdash;') itemSlotMap[k] = r.slot.replace(/\b\w/g, l=>l.toUpperCase());
        if (!itemAuraMap[k] && r.aura)  itemAuraMap[k] = r.aura;
        if (!itemClMap[k]   && r.cl)    itemClMap[k]   = r.cl;
        if (itemWeightMap[k] === undefined && r.weight) {
          const wNum = parseFloat(String(r.weight).replace(/[^0-9.]/g,''));
          if (!isNaN(wNum)) itemWeightMap[k] = wNum;
        }
      }
    } catch(e) { console.warn('buildWeaponArmorMaps items:', dbFile, e.message); }

    // Description child sections for magic items whose body is on a child section
    try {
      const drows = await bookQuery(dbFile, `
        SELECT p.name, c.body
        FROM sections p
        JOIN sections c ON c.parent_id=p.section_id
        WHERE p.type='item' AND c.name='Description' AND c.body IS NOT NULL AND c.body != ''`);
      for (const r of drows) {
        const k = (r.name||'').toLowerCase();
        if (!itemBodyMap[k] && r.body) {
          const text = r.body.replace(/<[^>]+>/g,'').trim();
          if (text) itemBodyMap[k] = text;
        }
      }
    } catch(e) { console.warn('buildWeaponArmorMaps desc:', dbFile, e.message); }

    // After each DB finishes, clear cache and refresh equipment if currently visible
    equipmentTabCache = {};
    equipmentManifestIndex = null;
    buildEquipmentManifestIndex();
    if (currentEquipmentCategory && currentEquipmentSubcategory) {
      loadEquipmentByCategory();
    }
  }
  // Final rebuild after all DBs done
  equipmentTabCache = {};
  equipmentManifestIndex = null;
  buildEquipmentManifestIndex();
}

// ── Magic item category icons ──────────────────────────────────────────────
const MAGIC_SUBCATEGORY_ICONS = {
  'Wondrous Items': '✨',
  'Rings':          '💍',
  'Rods':           '🪄',
  'Staves':         '🔱',
  'Magic Weapons':  '⚔️',
  'Magic Armor':    '🛡️',
};

// ── Wondrous item slot icons ───────────────────────────────────────────────
const WONDROUS_SLOT_ICONS = {
  'neck':      '📿',
  'head':      '👑',
  'headband':  '🎀',
  'eyes':      '🕶️',
  'shoulders': '🧣',
  'chest':     '👕',
  'body':      '🥋',
  'belt':      '🟫',
  'wrists':    '⌚',
  'hands':     '🧤',
  'feet':      '👢',
  'ring':      '💍',
  'none':      '✨',
};

// ── Format a potentially multi-price string for card display ──────────────
// Extracts the first (lowest) price and appends "++" if multiple options exist.
// Multi-price strings always separate entries with "), " or ") or " — a closing
// paren before the next entry. Thousands-separator commas (1,800 gp) never have
// a closing paren before them, so this never false-splits.
function formatCardPrice(price) {
  if (!price) return '';
  const cleaned = price.replace(/&mdash;/g,'—').replace(/&amp;/g,'&').trim();
  if (cleaned === '—' || cleaned === '') return cleaned;
  // Split on "), digit" or ") or digit" — the pattern between multiple price entries
  const match = cleaned.match(/^(.*?\))\s*(?:,\s*\d|\s+or\s+\d)/);
  if (match) return match[1] + '++';
  return cleaned;
}

// EQUIPMENT CATEGORIZATION
// Uses weaponMiscMap/armorMiscMap for weapons & armor, URL patterns for everything else.
// ═══════════════════════════════════════════════════════════════════════════
function categorizeEquipmentItem(item) {
  const url   = (item.url     || '').toLowerCase();
  const sub   = (item.subtype || '').toLowerCase();
  const nameL = (item.name    || '').toLowerCase();
  const WONDROUS_SLOTS = new Set(['neck','head','headband','body','shoulders','feet','hands','eyes','chest','wrist','belt']);

  // Skip enchantment-ability and special-material entries
  if (url.includes('weapon special abilit') || url.includes('armor special abilit') ||
      url.includes('magic weapon special ability descriptions') ||
      url.includes('/special materials') ||
      url.includes('firearm special abilit') ||
      url.includes('/grit and deeds') || url.includes('/deeds'))
    return null;

  // Skip items whose price is an enhancement bonus (e.g. "+1 bonus", "+3 bonus") — these are
  // enchantment modifiers, not purchasable items
  const price = (item.price || '').toLowerCase().trim();
  if (/^\+\d+\s+bonus$/.test(price) || /^\+\d+$/.test(price))
    return null;

  // Magic items — check BEFORE firearms so named magic weapons (e.g. "Pistol of X") don't land here
  // Rods / Staves / Rings
  if (url.includes('/rods/') || url.includes('/gear/rods'))         return { main:'Magic Items', sub:'Rods' };
  if (url.includes('/staves/') || url.includes('/gear/staves'))     return { main:'Magic Items', sub:'Staves' };
  if (url.includes('/rings/') || url.includes('/gear/rings') || sub==='ring') return { main:'Magic Items', sub:'Rings' };

  // Wondrous items
  if (url.includes('/wondrous items/') || url.includes('/wondrous_items/') || url.includes('/gear/wondrous'))
    return { main:'Magic Items', sub:'Wondrous Items' };
  if (WONDROUS_SLOTS.has(sub)) return { main:'Magic Items', sub:'Wondrous Items' };

  // Specific magic weapons/armor
  if (url.includes('specific magic weapon') || url.includes('/magic items/weapons') ||
      url.includes('/magic arms and armor/specific magic weapon') || url.includes('/gear/specific weapons'))
    return { main:'Magic Items', sub:'Magic Weapons' };
  if (url.includes('specific magic armor') || url.includes('specific magic shield') ||
      url.includes('/magic items/armor') || url.includes('/magic arms and armor/specific magic armor') ||
      sub==='armor' || sub==='shield')
    return { main:'Magic Items', sub:'Magic Armor' };
  if (url.includes('/magic items/') || url.includes('/gear/magic items'))
    return { main:'Magic Items', sub:'Wondrous Items' };

  // Firearms (after magic checks so magic firearms route correctly)
  const isFirearmKit = nameL.includes('gunsmith') || nameL.includes('gunsmithing');
  if (isFirearmKit)
    return { main:'Firearms', sub:'Kits' };

  // Firearm accessories that aren't weapons or ammo — skip
  if (nameL === 'dry load powder horn' || nameL.includes('dry load'))
    return null;

  const isFirearmAmmo = nameL.includes('black powder') || nameL.includes('paper cartridge') ||
                        nameL.includes('firearm bullet') || nameL.includes('firearm shot') ||
                        nameL.includes('pellets') || nameL.includes('pellet bag') ||
                        (url.includes('/firearms') && (nameL.includes('bullet') || nameL.includes('cartridge') || nameL.includes('powder') || nameL.includes('pellet')));
  if (isFirearmAmmo)
    return { main:'Firearms', sub:'Ammunition' };
  if (url.includes('/firearms') || nameL.includes('pistol') || nameL.includes('musket') ||
      nameL.includes('pepperbox') || nameL.includes('blunderbuss'))
    return { main:'Firearms', sub: (nameL.includes('revolver') || url.includes('advanced')) ? 'Advanced Firearms' : 'Early Firearms' };

  // Mundane weapons — use weaponMiscMap for proficiency + hand-size
  const isWeaponUrl = url.includes('/weapons/weapon description') || url.includes('arms and armor/weapons') ||
                      url.includes('/equipment/weapons') || url.includes('/gear/weapons/');
  if (isWeaponUrl) {
    const w = weaponMiscMap[nameL];
    if (w) {
      const prof = (w.prof||'').toLowerCase();
      const wc   = (w.wc||'').toLowerCase();
      const profMain = prof.includes('exotic') ? 'Exotic' : prof.includes('martial') ? 'Martial' : 'Simple';
      // Name-based ammo keywords always route to Ammunition, regardless of weapon category flags
      const isAmmoByName = nameL.includes('arrow') || nameL.includes('bolt') || nameL.includes('dart');
      if (wc.includes('ammo') || wc.includes('ammunition') || isAmmoByName ||
          nameL.includes('bullets') || nameL.includes('shuriken') || nameL.includes('javelin') ||
          (w.range && w.range !== '—' && w.range !== '-')) {
        const sub = (wc.includes('ranged') && !wc.includes('ammo') && !isAmmoByName) ? 'Ranged' : 'Ammunition';
        return { main: profMain, sub };
      }
      if (wc.includes('light') || wc.includes('unarmed')) return { main: profMain, sub: 'Light Melee' };
      if (wc.includes('one-handed'))  return { main: profMain, sub: 'One-Handed' };
      if (wc.includes('two-handed'))  return { main: profMain, sub: 'Two-Handed' };
      return { main: profMain, sub: 'One-Handed' };
    }
    return { main:'Martial', sub:'One-Handed' }; // fallback until maps load
  }

  // Mundane armor — use armorMiscMap for type
  const isArmorUrl = url.includes('/armor/armor and shields') || url.includes('arms and armor/armor') ||
                     url.includes('/equipment/armor') || url.includes('/gear/armor/');
  if (isArmorUrl) {
    const a = armorMiscMap[nameL];
    if (a) {
      const at = (a.armorType||'').toLowerCase();
      if (at.includes('light'))  return { main:'Armor', sub:'Light Armor' };
      if (at.includes('medium')) return { main:'Armor', sub:'Medium Armor' };
      if (at.includes('heavy'))  return { main:'Armor', sub:'Heavy Armor' };
      if (at.includes('tower'))  return { main:'Armor', sub:'Tower Shield' }; // must check before 'shield'
      if (at.includes('shield')) return { main:'Armor', sub:'Shields' };
      return { main:'Armor', sub:'Other' };
    }
    // Name-based fallback: tower shields not in armorMiscMap yet
    if (nameL.includes('tower shield')) return { main:'Armor', sub:'Tower Shield' };
    return { main:'Armor', sub:'Light Armor' }; // fallback
  }

  // Goods & Services — parse URL sub-path
  if (url.includes('food') || url.includes('drink') || url.includes('lodging') ||
      url.includes('/inn') || url.includes('/meals'))                              return { main:'Goods & Services', sub:'Food & Lodging' };
  if (url.includes('/clothing/'))                                                  return { main:'Goods & Services', sub:'Clothing' };
  if (url.includes('mount') || url.includes('/animal-related') ||
      url.includes('/animal related') || url.includes('barding') ||
      url.includes('dog sled') || url.includes('/horse') || url.includes('/pony')) return { main:'Goods & Services', sub:'Mounts & Animals' };
  if (url.includes('/transport') || url.includes('vehicle') || url.includes('/ship') ||
      url.includes('/boat') || url.includes('/carriage') || url.includes('/cart') ||
      url.includes('/wagon'))                                                       return { main:'Goods & Services', sub:'Transport' };
  if (url.includes('/tools and skill kits') || url.includes('/tools and kits') ||
      url.includes('tools & kits') || url.includes('/tools/'))                    return { main:'Goods & Services', sub:'Tools & Kits' };
  if (url.includes('/alchemical') || url.includes('special substances') ||
      sub==='alchemical')                                                           return { main:'Goods & Services', sub:'Alchemical Items' };
  if (url.includes('/adventuring gear/') || url.includes('/adventuring_gear/') ||
      sub==='gear' || url.includes('/gear/adventuring') ||
      url.includes('/goods and services/'))                                        return { main:'Goods & Services', sub:'Adventuring Gear' };

  if (url.includes('/gear/') || url.includes('/equipment/'))
    return { main:'Goods & Services', sub:'Adventuring Gear' };

  return null;
}

function getEquipmentSummary(item) {
  let s='';
  if (item.price)  s += item.price;
  if (item.weight) s += (s?'  •  ':'')+item.weight;
  if (item.misc?.Weapon?.['Dmg (M)']) s += (s?'  •  ':'')+'Dmg: '+item.misc.Weapon['Dmg (M)'];
  if (item.misc?.Armor?.['Armor Bonus']) s += (s?'  •  ':'')+'AC: '+item.misc.Armor['Armor Bonus'];
  return s || item.source || 'Equipment';
}

// ═══════════════════════════════════════════════════════════════════════════
// EQUIPMENT TABS
// ═══════════════════════════════════════════════════════════════════════════
function buildEquipmentManifestIndex() {
  if (equipmentManifestIndex) return;
  equipmentManifestIndex = {};
  for (const item of dataCache.equipment) {
    const cat = categorizeEquipmentItem(item);
    if (!cat) continue;
    if (!equipmentManifestIndex[cat.main]) equipmentManifestIndex[cat.main] = {};
    if (!equipmentManifestIndex[cat.main][cat.sub]) equipmentManifestIndex[cat.main][cat.sub] = [];
    equipmentManifestIndex[cat.main][cat.sub].push(item);
  }
}

async function _fetchEquipmentTab(main, sub, tabKey) {
  const WCLASS = new Set(['Two-Handed Melee Weapons','One-Handed Melee Weapons','Light Melee Weapons','Ranged Weapons','Ammunition','Melee Weapons']);
  let items = dataCache.equipment.filter(item => {
    const cat = categorizeEquipmentItem(item);
    return cat && cat.main===main && (!sub||cat.sub===sub);
  });
  items.forEach(item => {
    const w = item.misc?.Weapon;
    if (!w) return;
    if (w['Proficiency']&&WCLASS.has(w['Proficiency'])&&(!w['Weapon Class']||w['Weapon Class']===null)) { w['Weapon Class']=w['Proficiency']; w['Proficiency']=null; }
    if (w['Weapon Class']===null) delete w['Weapon Class'];
    if (w['Proficiency']===null)  delete w['Proficiency'];
    if (w['Price']) delete w['Price'];
  });
  equipmentTabCache[tabKey] = items.sort((a,b)=>(a.name||'').localeCompare(b.name||''));
}

function renderEquipmentCategoryTabs() {
  const c = document.getElementById('equipment-category-tabs');
  if (!c) return;
  const _profs = getCharacterProficiencies();
  const _hasClasses = character.classes.length > 0;
  const PROF_GATED = new Set(['Simple', 'Martial', 'Exotic', 'Armor', 'Firearms']);

  // Build set of main categories that contain specific racial items (for ✦ indicator)
  const _specificCats = new Set();
  for (const [itemName] of _profs.specificItems) {
    const hint = RACIAL_ITEM_CATS[itemName];
    if (hint) _specificCats.add(hint.main);
  }

  c.innerHTML = Object.entries(EQUIPMENT_CATEGORIES).map(([cat, d]) => {
    const rgb = hexColorToRgb(d.color);
    let extraClass = '';
    if (PROF_GATED.has(cat) && _hasClasses) {
      let isProficient = false;
      if (cat === 'Simple')   isProficient = _profs.weaponLevels.has('simple');
      else if (cat === 'Martial')  isProficient = _profs.weaponLevels.has('martial');
      else if (cat === 'Exotic')   isProficient = false;
      else if (cat === 'Firearms') isProficient = _profs.firearmProf;
      else if (cat === 'Armor')    isProficient = _profs.armorTypes.has('light') || _profs.armorTypes.has('medium') || _profs.armorTypes.has('heavy');
      extraClass = isProficient ? ' equip-cat-prof-yes' : ' equip-cat-prof-no';
    } else {
      extraClass = ' equip-cat-themed';
    }
    // Specific racial items in this prof-gated category → always glow (overrides themed or dim)
    if (_specificCats.has(cat) && PROF_GATED.has(cat)) {
      extraClass = ' equip-cat-prof-yes';
    }
    // ✦ indicator: category contains specific racial-familiarity items
    if (_specificCats.has(cat)) extraClass += ' equip-cat-has-specific';

    return `<div class="equipment-category-tab${extraClass}" style="--equip-glow-color:${rgb};" onclick="selectEquipmentCategory('${cat}')">${d.icon} ${cat}</div>`;
  }).join('');

  // Keyword banner: show when race has keyword weapon familiarity
  const _banner = document.getElementById('equip-keyword-banner');
  if (_banner) {
    if (_profs.keywordProfs.length > 0) {
      const msgs = _profs.keywordProfs.map(({ keyword, source }) => {
        const hasMartial = _profs.weaponLevels.has('martial');
        const note = hasMartial
          ? ''
          : `<span style="opacity:0.60;font-size:0.9em;"> — gain Martial Weapon Proficiency to apply</span>`;
        return `📖 <strong style="color:rgba(240,220,150,1);">${source}</strong>: any weapon with <em>"${keyword}"</em> in its name is treated as a Martial weapon${note}`;
      });
      _banner.innerHTML = msgs.join('<br>');
      _banner.classList.add('visible');
    } else {
      _banner.classList.remove('visible');
      _banner.innerHTML = '';
    }
  }
}
function selectEquipmentCategory(category) {
  currentEquipmentCategory=category; currentEquipmentSubcategory=null;
  document.querySelectorAll('.equipment-category-tab').forEach(t=>t.classList.toggle('active',t.textContent.trim().includes(category)));
  renderEquipmentSubcategoryTabs();
  const subs=Object.keys(EQUIPMENT_CATEGORIES[category].subcategories);
  if (subs.length) selectEquipmentSubcategory(subs[0]); else loadEquipmentByCategory();
}
function renderEquipmentSubcategoryTabs() {
  const c = document.getElementById('equipment-subcategory-tabs');
  if (!c || !currentEquipmentCategory) return;
  const _profs = getCharacterProficiencies();
  const _hasClasses = character.classes.length > 0;
  const _catDef = EQUIPMENT_CATEGORIES[currentEquipmentCategory];
  const PROF_GATED = new Set(['Simple', 'Martial', 'Exotic', 'Armor', 'Firearms']);
  const isProfGated = PROF_GATED.has(currentEquipmentCategory);

  const _hasProfForSub = (sub) => {
    const main = currentEquipmentCategory;
    if (main === 'Simple')   return _profs.weaponLevels.has('simple');
    if (main === 'Martial')  return _profs.weaponLevels.has('martial');
    if (main === 'Firearms') return _profs.firearmProf;
    if (main === 'Exotic')   return false;
    if (main === 'Armor') {
      if (sub === 'Light Armor')   return _profs.armorTypes.has('light');
      if (sub === 'Medium Armor')  return _profs.armorTypes.has('medium');
      if (sub === 'Heavy Armor')   return _profs.armorTypes.has('heavy');
      if (sub === 'Shields')       return _profs.armorTypes.has('shields');
      if (sub === 'Tower Shield')  return false; // requires Tower Shield Proficiency feat
    }
    return null;
  };

  // Build set of subcategories within the current main category that contain specific racial items
  const _specificSubs = new Set();
  for (const [itemName] of _profs.specificItems) {
    const hint = RACIAL_ITEM_CATS[itemName];
    if (hint && hint.main === currentEquipmentCategory) _specificSubs.add(hint.sub);
  }

  c.innerHTML = Object.keys(_catDef.subcategories).map(s => {
    const subHex = (_catDef.subColors && _catDef.subColors[s]) || _catDef.color;
    const rgb = hexColorToRgb(subHex);

    let extraClass = '';
    if (isProfGated && _hasClasses) {
      const profResult = _hasProfForSub(s);
      if (profResult === true)  extraClass = ' equip-subtab-prof-yes';
      else if (profResult === false) extraClass = ' equip-subtab-prof-no';
    } else {
      extraClass = ' equip-subtab-themed';
    }
    // Specific racial items in this subcategory → always glow (overrides themed or dim)
    if (_specificSubs.has(s) && isProfGated) {
      extraClass = ' equip-subtab-prof-yes';
    }
    // ✦ indicator: subcategory contains specific racial-familiarity items
    if (_specificSubs.has(s)) extraClass += ' equip-subtab-has-specific';

    return `<div class="equipment-subcategory-tab${extraClass}" style="--equip-glow-color:${rgb};" onclick="selectEquipmentSubcategory('${s}')">${s}</div>`;
  }).join('');

  // Re-apply active state after rebuild
  document.querySelectorAll('.equipment-subcategory-tab').forEach(t =>
    t.classList.toggle('active', t.textContent.trim() === currentEquipmentSubcategory));
}
function selectEquipmentSubcategory(sub) {
  currentEquipmentSubcategory=sub;
  document.querySelectorAll('.equipment-subcategory-tab').forEach(t=>t.classList.toggle('active',t.textContent.trim()===sub));
  // Show slot filter only for Wondrous Items
  const slotWrap = document.getElementById('filter-equipment-slot-wrap');
  if (slotWrap) {
    slotWrap.style.display = (sub === 'Wondrous Items') ? '' : 'none';
    const slotSel = document.getElementById('filter-equipment-slot');
    if (slotSel) slotSel.value = '';
  }
  loadEquipmentByCategory();
}
async function loadEquipmentByCategory() {
  if (!currentEquipmentCategory) return;
  const main=currentEquipmentCategory, sub=currentEquipmentSubcategory||'', tabKey=`${main}|${sub}`;
  const cEl=document.getElementById('filter-count-equipment'), cont=document.getElementById('equipment-content');
  if (!equipmentTabCache[tabKey]) {
    if (cont) cont.innerHTML=`<div class="loading"><div class="loading-spinner"></div><div style="font-family:Cinzel,serif;color:var(--text-secondary);">Loading ${main}…</div></div>`;
    await _fetchEquipmentTab(main,sub,tabKey);
  }
  const items=equipmentTabCache[tabKey]||[];
  filteredData.equipment=items; renderData('equipment',items);
  if (cEl) cEl.textContent=`${items.length} items`;
}
function filterEquipmentData() {
  if (!currentEquipmentCategory) return;
  const tabKey=`${currentEquipmentCategory}|${currentEquipmentSubcategory||''}`;
  const base=equipmentTabCache[tabKey]||filteredData.equipment||[];
  const search=document.getElementById('search-equipment').value.toLowerCase();
  const typeFilter=document.getElementById('filter-equipment-type').value;
  const slotFilter=(document.getElementById('filter-equipment-slot')?.value||'').toLowerCase();
  let items=base;
  if (search) items=items.filter(i=>(i.name||'').toLowerCase().includes(search)||(i.description||'').toLowerCase().includes(search));
  if (typeFilter) items=items.filter(i=>(i.type||'')===typeFilter);
  if (slotFilter && currentEquipmentSubcategory === 'Wondrous Items') {
    items=items.filter(i => {
      const nameL=(i.name||'').toLowerCase();
      const slot=(i.slot||itemSlotMap[nameL]||'none').toLowerCase().replace(/\s*\(.*\)/,'').trim();
      return slot === slotFilter;
    });
  }
  filteredData.equipment=items; renderData('equipment',items);
  const cEl=document.getElementById('filter-count-equipment');
  if (cEl) cEl.textContent=`${items.length} items`;
}

