// SPELL POPUP
// ═══════════════════════════════════════════════════════════════════════════
function renderSpellClassSelection() {
  const cont=document.getElementById('spells-content');
  if (!cont) return;
  cont.innerHTML='';
  SPELL_CLASSES.forEach(cls=>{
    const card=document.createElement('div');
    card.className='class-card';
    const classKey = cls.toLowerCase();
    const color = CLASS_COLORS[classKey] || ARCANE_COLOR;
    const icon  = CLASS_ICONS[classKey] || '✨';
    card.style.setProperty('--card-color', color);
    card.style.borderColor = color;
    card.style.padding = '0';
    card.style.overflow = 'hidden';
    card.innerHTML = `
      <div style="padding:0.85rem 1.25rem;background:${color}22;border-bottom:2px solid ${color};border-radius:7px 7px 0 0;display:flex;align-items:center;gap:0.75rem;">
        <span style="font-size:1.8rem;line-height:1;flex-shrink:0;">${icon}</span>
        <div style="flex:1;min-width:0;">
          <div style="font-family:'Cinzel Decorative',serif;font-size:1.05rem;color:#fff;line-height:1.25;">${cls}</div>
        </div>
        <button class="card-btn" style="flex-shrink:0;" onclick="event.stopPropagation();openSpellPopup('${cls}')">View Spells</button>
      </div>`;
    card.addEventListener('click',()=>openSpellPopup(cls));
    cont.appendChild(card);
  });
}
async function openSpellPopup(className) {
  currentSpellClass = className;
  const classKey = className.toLowerCase();
  const color = CLASS_COLORS[classKey] || ARCANE_COLOR;
  const icon  = CLASS_ICONS[classKey] || '✨';

  // Build topbar (quota pill injected after quota data is ready)
  const topbar = document.querySelector('#spell-popup-wrap .detail-panel-topbar');
  if (topbar) {
    topbar.style.background = `${color}22`;
    topbar.style.borderBottom = `2px solid ${color}`;
    topbar.style.padding = '0.85rem 1.25rem';
    topbar.innerHTML = `
      <div style="display:flex;align-items:center;gap:0.75rem;flex:1;min-width:0;">
        <span style="font-size:1.8rem;line-height:1;flex-shrink:0;">${icon}</span>
        <div style="font-family:'Cinzel Decorative',serif;font-size:1.1rem;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${className} Spells</div>
        <span id="spell-topbar-quota" style="font-family:Cinzel,serif;font-size:0.78rem;white-space:nowrap;"></span>
      </div>
      <div class="detail-close"><button onclick="closeSpellPopup()">✕</button></div>`;
  }

  // Hide the old full quota bar (content now lives in topbar + tag strip)
  const oldBar = document.getElementById('spellcaster-spell-quota');
  if (oldBar) oldBar.style.display = 'none';

  document.getElementById('spell-popup-wrap').classList.add('active');
  ['spell-search','spell-school-filter','spell-level-filter'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  const ef=document.getElementById('spell-expensive-filter'); if(ef) ef.checked=false;
  const spells=loadSpellsForClassFromIndex(className);
  dataCache.spells=spells;
  updateSpellcasterQuotaTopbar();
  updateStartingSpellsInfo();
  renderChosenSpellTags();
  renderSpellPopup(spells);
}

// ── Lightweight quota pill in the topbar ─────────────────────────────────────
function updateSpellcasterQuotaTopbar() {
  const pill = document.getElementById('spell-topbar-quota');
  if (!pill) return;
  const clsKey   = (currentSpellClass || '').toLowerCase();
  const data     = getSpellcasterQuotaData(clsKey);
  if (!data) { pill.textContent = ''; return; }
  const isComplete = data.totalChosen >= data.totalExpected;
  const isExtract  = !!(data.isExtract);
  const label      = isExtract ? '⚗️' : data.type === 'spellbook' ? '📖' : '✨';
  pill.innerHTML = `<span style="background:rgba(0,0,0,0.35);border-radius:8px;padding:2px 10px;color:${isComplete?'#6abf7a':'#c9a84c'};">
    ${label} ${data.totalChosen}/${data.totalExpected}${isComplete?' ✓':''}
  </span>`;
}
function closeSpellPopup() { document.getElementById('spell-popup-wrap').classList.remove('active'); currentSpellClass=null; }

// ─── Spellcaster Spell-Known Quota System ────────────────────────────────────
// Tracks how many spells each class type should have chosen vs. how many they have.
//
// SPELLBOOK classes (Wizard, Magus, Arcanist): must record spells like a library.
//   Wizard  : Level 1 → 3 + Int mod non-cantrip spells; each level after → +2
//   Magus   : Level 1 → 3 non-cantrip spells; each level after → +1
//   Arcanist: same schedule as Wizard (3 + Int mod at 1, +2 each level)
//
// SPONTANEOUS classes (Sorcerer, Bard, Oracle, Summoner, Inquisitor, Bloodrager):
//   Track cumulative spells known from their official table.
//   Cantrips (0th level) are tracked too for these classes.
//
// PREPARED-from-full-list (Cleric, Druid, Paladin, Ranger, Witch):
//   No selection needed — they know (or have access to) all spells on their list.
//   These classes are intentionally excluded from the quota system.

// ── Spellbook classes ─────────────────────────────────────────────────────────
// Returns { totalExpected, maxSpellLevel, abilMod, abilKey, isExtract } for a spellbook/formula caster, or null.
// Covers: Wizard, Magus, Arcanist (arcane spellbook) + Alchemist, Investigator (formula book) + Witch (patron book)
function getSpellbookQuota(clsName) {
  const lk = clsName.toLowerCase();
  const cls = (character.classes || []).find(c =>
    (c.name || c._name || '').toLowerCase().trim() === lk);
  if (!cls) return null;
  const clsLevel = parseInt(cls.level) || 1;

  // Key ability score per class
  const ABIL_MAP = { wizard:'int', magus:'int', arcanist:'int', alchemist:'int', investigator:'int', witch:'int' };
  const abilKey = ABIL_MAP[lk];
  if (!abilKey) return null;

  const rawScore = (character.stats || {})[abilKey] || 10;
  const abilBonus = (typeof getTotalBonus === 'function') ? getTotalBonus(abilKey) : 0;
  const abilMod = Math.max(0, Math.floor(((rawScore + abilBonus) - 10) / 2));

  // Max formula/spell level per class
  const MAX_LVL_CAP = { magus:6, alchemist:6, investigator:6 };
  const maxSpellLevel = Math.min(MAX_LVL_CAP[lk] ?? 9, Math.ceil(clsLevel / 2));

  const isExtract = lk === 'alchemist' || lk === 'investigator';

  let totalExpected;
  if (lk === 'wizard' || lk === 'arcanist') {
    totalExpected = 3 + abilMod; // level 1 base (+Int mod)
    for (let lvl = 2; lvl <= clsLevel; lvl++) totalExpected += 2;
  } else if (lk === 'magus') {
    totalExpected = 3; // level 1 base; +1 per level
    for (let lvl = 2; lvl <= clsLevel; lvl++) totalExpected += 1;
  } else if (lk === 'alchemist' || lk === 'investigator') {
    // Formula book: 2 + Int mod at 1st; +2 per level
    totalExpected = 2 + abilMod;
    for (let lvl = 2; lvl <= clsLevel; lvl++) totalExpected += 2;
  } else if (lk === 'witch') {
    // Patron book: 2 + Int mod at 1st; +2 per level
    totalExpected = 2 + abilMod;
    for (let lvl = 2; lvl <= clsLevel; lvl++) totalExpected += 2;
  }

  return { totalExpected, maxSpellLevel, abilMod, abilKey, isExtract };
}

