function getDeityColor(item) {
  const nameL = (item.name||'').toLowerCase();
  // Try name lookup in DEITY_DATA
  for (const [k, d] of Object.entries(DEITY_DATA)) {
    if (k.toLowerCase() === nameL) return ALIGNMENT_COLORS[d.alignment] || '#6a6a7a';
  }
  // Fall back to item.alignment if present
  const al = (item.alignment||'').toUpperCase();
  return ALIGNMENT_COLORS[al] || '#6a6a7a';
}

function getDeityData(name) {
  for (const [k, d] of Object.entries(DEITY_DATA)) {
    if (k.toLowerCase() === (name||'').toLowerCase()) return { name: k, ...d };
  }
  return null;
}

// ═══════════════════════════════════════════════════════════════════════════
async function lazyLoadCategory(category) {
  const cont=document.getElementById(`${category}-content`);
  if (cont) cont.innerHTML=`<div class="loading"><div class="loading-spinner"></div><div style="font-family:Cinzel,serif;color:var(--text-secondary);">Loading ${category}…</div></div>`;
  if (category==='deities') {
    // Build deity list from DEITY_DATA hardcoded map (full alignment/domains/weapons/desc)
    const deities = Object.entries(DEITY_DATA).map(([name, d]) => ({
      name, _name: name, alignment: d.alignment, domains: d.domains,
      weapon: d.weapon, description: d.desc, emoji: d.emoji,
      type: 'deity', _source: 'Core', _db: null, _section_id: null,
    })).sort((a,b) => a.name.localeCompare(b.name));
    dataCache.deities=deities; filteredData.deities=deities;
    populateFilters('deities',deities); renderData('deities',deities);
    const cEl=document.getElementById('filter-count-deities');
    if (cEl) cEl.textContent=`${deities.length} deities`;
  }
  lazyLoadedCategories.add(category);
}

// ═══════════════════════════════════════════════════════════════════════════
// DETAIL VIEW — show panel immediately, load full data from book DB async
// ═══════════════════════════════════════════════════════════════════════════
async function openDetail(category, item) {
  // Show panel right away with spinner
  const cEl=document.getElementById('detail-content');
  if (cEl) cEl.innerHTML=`<div style="text-align:center;padding:3rem;color:var(--text-muted);"><div class="loading-spinner" style="margin:0 auto 1rem;"></div>Loading details…</div>`;
  document.getElementById('detail-page-wrap').classList.add('active');

  const enriched = await loadFullDetail(item);
  // For classes: load sub-variants (focused schools, subdomains) from cross-book sources
  const withSub = (category === 'classes') ? await loadCrossBookSubFeatures(enriched) : enriched;
  openDetailSync(category, withSub);
}

async function openDetailWithFullData(category, item) {
  return openDetail(category, item);
}

// ═══════════════════════════════════════════════════════════════════════════
// ARCHETYPE PANEL — loads from book DB on demand
// ═══════════════════════════════════════════════════════════════════════════
const archetypeCache = {};

// Map source folder name → book filename
function archPathToDbFile(path) {
  const folder = path.split('/')[0];
  const MAP = {
    advanced_players_guide: 'book-apg.db',
    ultimate_combat:        'book-uc.db',
    ultimate_magic:         'book-um.db',
    advanced_race_guide:    'book-arg.db',
    advanced_class_guide:   'book-acg.db',
    game_mastery_guide:     'book-gmg.db',
    ultimate_campaign:      'book-ucampaign.db',
    ultimate_equipment:     'book-ue.db',
    mythic_adventures:      'book-ma.db',
  };
  return MAP[folder] || null;
}

async function loadArchetypeDetail(archName, dbFile) {
  if (!dbFile || !AVAILABLE_DBS.has(dbFile)) return null;
  // Try class_archetype first (the correct type), fall back to section
  let rows = await bookQuery(dbFile, `SELECT section_id, name, body FROM sections WHERE name=? AND type='class_archetype' LIMIT 1`, [archName]);
  if (!rows.length) rows = await bookQuery(dbFile, `SELECT section_id, name, body FROM sections WHERE LOWER(name)=LOWER(?) AND type='class_archetype' LIMIT 1`, [archName]);
  if (!rows.length) rows = await bookQuery(dbFile, `SELECT section_id, name, body FROM sections WHERE name=? AND type='section' LIMIT 1`, [archName]);
  if (!rows.length) rows = await bookQuery(dbFile, `SELECT section_id, name, body FROM sections WHERE LOWER(name)=LOWER(?) LIMIT 1`, [archName]);
  if (!rows.length) return { name:archName, body:null, sections:[] };
  const row = rows[0];
  // Recursively fetch children so deeply-nested content (e.g. bardic performance
  // sub-types) is included, matching the depth used by the main class detail loader
  async function fetchKids(parentId, depth) {
    const kids = await bookQuery(dbFile,
      `SELECT section_id, name, type, subtype, body FROM sections WHERE parent_id=? AND type!='link' ORDER BY lft`,
      [parentId]);
    if (depth <= 0) return kids.map(k => ({...k, sections:[]}));
    return Promise.all(kids.map(async k => ({
      ...k, sections: await fetchKids(k.section_id, depth - 1)
    })));
  }
  const sections = await fetchKids(row.section_id, 4);
  return { name:row.name, body:row.body, sections };
}

// Toggle an alternate racial trait selection and re-render the race detail
function toggleRaceAltTrait(raceName, traitName, checked) {
  if (checked) {
    selectedRaceAltTraits[traitName] = true;
  } else {
    delete selectedRaceAltTraits[traitName];
  }
  // Re-render the detail content in place so checkboxes, conflicts and
  // replacement overlays all update without closing the panel
  if (currentDetail && (currentDetail.name || currentDetail._name) === raceName) {
    const html = buildRaceDetailHtml(currentDetail);
    const contentEl = document.getElementById('detail-content');
    if (contentEl) contentEl.innerHTML = html;
  }
}

async function toggleArchetype(path, rowId) {
  const row=document.getElementById(rowId); if(!row) return;
  if (row.style.display!=='none') {
    row.style.display='none';
    const btn=document.getElementById(rowId+'-btn'); if(btn) btn.textContent='▸';
    return;
  }
  const btn=document.getElementById(rowId+'-btn'); if(btn) btn.textContent='…';
  try {
    if (!archetypeCache[path]) {
      const parts=path.replace(/\.json$/,'').split('/');
      const archName=parts[parts.length-1].replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase());
      const dbFile=archPathToDbFile(path);
      archetypeCache[path]=await loadArchetypeDetail(archName,dbFile)||{name:archName,body:null,sections:[]};
    }
    const data=archetypeCache[path];
    let html='';
    if (data.body) html+=`<div style="color:var(--text-secondary);line-height:1.8;margin-bottom:0.75rem;">${boldKeyTerms(data.body.replace(/<[^>]+>/g,'').trim())}</div>`;
    const archIdBase = 'at-' + path.replace(/[^a-z0-9]/gi,'-').toLowerCase();
    let archIdCounter = 0;
    function renderArchSections(sections, depth) {
      let out = '';
      for (const s of (sections||[])) {
        if (!s || s.type === 'link') continue;
        const colId   = archIdBase + '-' + (archIdCounter++);
        const rawBody = s.body ? s.body.replace(/<[^>]+>/g,'').trim() : '';
        const hasSubs = !!(s.sections && s.sections.length);

        let bodyHtml = '';
        if (rawBody) {
          const mb = hasSubs ? '0.55rem' : '0';
          bodyHtml += `<div style="color:var(--text-secondary);line-height:1.7;font-size:${depth===0?'0.9rem':'0.88rem'};margin-bottom:${mb};">${boldKeyTerms(rawBody)}</div>`;
        }
        if (hasSubs) {
          bodyHtml += `<div style="display:flex;flex-direction:column;gap:0.2rem;margin-top:${rawBody?'0.1rem':'0'};">`;
          bodyHtml += renderArchSections(s.sections, depth + 1);
          bodyHtml += `</div>`;
        }
        if (!bodyHtml) bodyHtml = '<span style="color:var(--text-muted);font-size:0.85rem;font-style:italic;">No description available.</span>';

        if (depth === 0) {
          out += `<div style="border:1px solid var(--border);border-left:3px solid var(--border-glow);border-radius:0 5px 5px 0;overflow:hidden;">
            <div style="display:flex;align-items:center;gap:0.6rem;padding:0.5rem 0.9rem;background:var(--bg-card);cursor:pointer;transition:background 0.15s;"
                 onclick="(function(el){var b=document.getElementById('${colId}');var a=el.querySelector('.arch-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)"
                 onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-card)'">
              <span class="arch-arr" style="color:var(--gold-dark);font-size:0.72rem;width:10px;flex-shrink:0;">▸</span>
              <span style="font-family:Cinzel,serif;font-size:0.84rem;color:var(--text-primary);">${s.name||''}</span>
            </div>
            <div id="${colId}" style="display:none;padding:0.6rem 0.9rem 0.7rem 1.4rem;background:var(--bg-surface);border-top:1px solid var(--border);">
              ${bodyHtml}
            </div>
          </div>`;
        } else {
          out += `<div style="border:1px solid var(--border);border-left:2px solid var(--border-glow);border-radius:0 4px 4px 0;overflow:hidden;">
            <div style="display:flex;align-items:center;gap:0.5rem;padding:0.38rem 0.7rem;background:var(--bg-card);cursor:pointer;transition:background 0.15s;"
                 onclick="(function(el){var b=document.getElementById('${colId}');var a=el.querySelector('.arch-sub-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)"
                 onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-card)'">
              <span class="arch-sub-arr" style="color:var(--gold-dark);font-size:0.65rem;width:8px;flex-shrink:0;">▸</span>
              <span style="font-family:Cinzel,serif;font-size:0.8rem;color:var(--text-primary);">${s.name||''}</span>
            </div>
            <div id="${colId}" style="display:none;padding:0.5rem 0.85rem 0.55rem 1.2rem;background:var(--bg-surface);border-top:1px solid var(--border);">
              ${bodyHtml}
            </div>
          </div>`;
        }
      }
      return out;
    }
    const sectionsHtml = renderArchSections(data.sections, 0);
    if (sectionsHtml) html += `<div style="display:flex;flex-direction:column;gap:0.3rem;">${sectionsHtml}</div>`;
    if (!html) html='<div style="color:var(--text-muted);font-size:0.9rem;">No additional details available.</div>';
    row.innerHTML=`<div style="padding:0.5rem 0.75rem 0.75rem;">${html}</div>`;
    row.style.display='block'; if(btn) btn.textContent='▾';
    refreshArchetypeConflicts();
  } catch(e) {
    row.innerHTML=`<div style="color:var(--text-muted);font-size:0.85rem;padding:0.5rem 1rem;">Could not load archetype data.</div>`;
    row.style.display='block'; if(btn) btn.textContent='▾';
  }
}

// Extract class skill modifications from an archetype's cached sections
function extractArchetypeClassSkills(archSections) {
  if (!Array.isArray(archSections)) return { addedSkills: [], removedSkills: [], replacesAll: false, fullSkills: [] };
  const csSect = archSections.find(s => s && s.name && /^class skills?$/i.test(s.name.trim()));
  if (!csSect || !csSect.body) return { addedSkills: [], removedSkills: [], replacesAll: false, fullSkills: [] };
  const rawText = (csSect.body || '').replace(/<[^>]+>/g, '').trim();
  if (!rawText) return { addedSkills: [], removedSkills: [], replacesAll: false, fullSkills: [] };

  const isReplacement = /\b(?:replac|instead of|following class skills)\b/i.test(rawText);
  const isAddition    = /\b(?:adds?|gains?|also gain|in addition)\b/i.test(rawText) && !isReplacement;

  const ALL_SKILL_NAMES = ['Acrobatics','Appraise','Bluff','Climb','Craft','Diplomacy','Disable Device','Disguise','Escape Artist','Fly','Handle Animal','Heal','Intimidate','Knowledge (Arcana)','Knowledge (Dungeoneering)','Knowledge (Engineering)','Knowledge (Geography)','Knowledge (History)','Knowledge (Local)','Knowledge (Nature)','Knowledge (Nobility)','Knowledge (Planes)','Knowledge (Religion)','Linguistics','Perception','Perform','Profession','Ride','Sense Motive','Sleight of Hand','Spellcraft','Stealth','Survival','Swim','Use Magic Device'];

  // ── Extract added-skill text ──────────────────────────────────────────────
  let addedSkillText = '';
  if (isReplacement) {
    // Full replacement: scan everything after the colon (or whole text)
    const colonIdx = rawText.indexOf(':');
    addedSkillText = colonIdx >= 0 ? rawText.slice(colonIdx + 1) : rawText;
  } else {
    // Addition: try "adds/gains X to/as class skills" prose pattern first
    const proseAdd = rawText.match(/\b(?:adds?|gains?)\s+(.+?)\s+(?:to\s+(?:her|his|their|the)\b|as\s+class\s+skills?)/i);
    if (proseAdd) {
      addedSkillText = proseAdd[1];
    } else {
      // Colon format: "Class Skills: A X gains ..."
      const colonIdx = rawText.indexOf(':');
      if (colonIdx >= 0 && colonIdx < rawText.length - 2) {
        let afterColon = rawText.slice(colonIdx + 1);
        const listMatch = afterColon.match(/\b(?:gains?|adds?|are|include)\b\s+(.+?)(?:\.\s|$)/i);
        addedSkillText = listMatch ? listMatch[1] : afterColon;
      } else {
        // No clear pattern — scan the full text (isAddition=false generic modification)
        addedSkillText = rawText;
      }
    }
  }

  // ── Extract removed-skill text ────────────────────────────────────────────
  // Patterns: "does not gain X as a class skill" / "removes X" / "no longer gains X"
  let removedSkillText = '';
  const remMatch = rawText.match(/\b(?:does\s+not\s+gain|removes?\s+|no\s+longer\s+(?:gains?|has)\s+)(.+?)\s+(?:as|from)\s+(?:a\s+)?class\s+skill/i);
  if (remMatch) removedSkillText = remMatch[1];

  // ── Parse skill names from each text segment ──────────────────────────────
  const _findSkills = (text) => {
    const lo = text.toLowerCase();
    return ALL_SKILL_NAMES.filter(sk => lo.includes(sk.toLowerCase()));
  };

  const found        = _findSkills(addedSkillText);
  const foundRemoved = removedSkillText ? _findSkills(removedSkillText) : [];

  return {
    addedSkills:   isAddition || !isReplacement ? found : [],
    removedSkills: foundRemoved,
    replacesAll:   isReplacement,
    fullSkills:    isReplacement ? found : [],
  };
}

async function toggleArchetypeSelection(path, name, source, checkId) {
  const cb=document.getElementById(checkId); if(!cb) return;
  if (cb.checked) {
    if (!archetypeCache[path]) {
      const parts=path.replace(/\.json$/,'').split('/');
      const archName=parts[parts.length-1].replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase());
      const dbFile=archPathToDbFile(path);
      archetypeCache[path]=await loadArchetypeDetail(archName,dbFile)||{name:archName,body:null,sections:[]};
    }
    const archCS = extractArchetypeClassSkills((archetypeCache[path] || {}).sections);
    selectedArchetypes[path]={name,source,classSkillMods:archCS};
  } else { delete selectedArchetypes[path]; }
  const vis=document.getElementById(checkId+'-vis');
  if(vis){vis.innerHTML=cb.checked?`<span style="color:var(--gold);font-size:11px;line-height:1;">✓</span>`:'';vis.style.borderColor=cb.checked?'var(--gold)':'var(--gold-dark)';vis.style.background=cb.checked?'rgba(201,168,76,0.15)':'var(--bg-surface)';}
  refreshArchetypeConflicts();
  refreshClassFeatureReplacements();
  refreshArchetypeMetaSections();
  const count=Object.keys(selectedArchetypes).length;
  const abtn=document.getElementById('detail-build-btn');
  if(abtn&&!abtn.textContent.startsWith('✕')&&!abtn.textContent.startsWith('✓')) abtn.textContent=count>0?`+ Add to Character (${count} archetype${count>1?'s':''})`:'+ Add to Character';
}

// ─── Secondary feature selection (domains, bloodlines, schools, etc.) ─────────
// ─── Variant mutual exclusion refresh ─────────────────────────────────────────
// Called whenever a secondary feature checkbox changes.  Re-evaluates every base
// row and every variant row in the group and updates opacity / badges so that:
//   • Selecting a base school/domain greys all other bases and all their variants
//   • Selecting a focused-school / subdomain variant shows "→ Variant" badge on
//     its parent base row (auto-checking it visually) and greys all other bases
//   • Selecting an elemental school greys all base rows and all focused variants
//   • Deselecting anything restores normal state for remaining open slots

function refreshSFMutualExclusion(groupSlug, pickCount) {
  // Gather all picks in this group (keyed by groupSlug stored on the entry)
  const groupSelections = Object.entries(selectedSecondaryFeatures)
    .filter(([, f]) => f.groupSlug === groupSlug);

  const totalPicks   = groupSelections.length;
  const atLimit      = totalPicks >= pickCount;

  // shadowedParents: base sid → variant name (variant selected FOR that base)
  const shadowedParents = new Map();
  // variantForParent: base sid → variant section_id (for feature-replacement toggling)
  const variantForParent = new Map();
  const selectedBaseSids = new Set();
  let   elementalSelected = false;

  for (const [id, f] of groupSelections) {
    if (f.parentSectionId === '__elemental__') {
      elementalSelected = true;
    } else if (f.parentSectionId) {
      shadowedParents.set(String(f.parentSectionId), f.name);
      variantForParent.set(String(f.parentSectionId), String(id));
    } else {
      selectedBaseSids.add(String(id));
    }
  }

  // ── Base school / domain rows ─────────────────────────────────────────────
  document.querySelectorAll(`[data-sf-group="${groupSlug}"][data-sf-sid]`).forEach(el => {
    const sid               = el.getAttribute('data-sf-sid');
    const isDirectlySelected = selectedBaseSids.has(sid);
    const hasVariantSelected = shadowedParents.has(sid);
    const isTaken            = isDirectlySelected || hasVariantSelected;

    // Grey the row if: elemental chosen (all base rows lose selectability)
    //                  OR we're at limit and this row isn't one of the chosen slots
    const isGreyed = elementalSelected || (atLimit && !isTaken);

    const label = el.querySelector('label');
    if (label) {
      label.style.opacity       = isGreyed ? '0.32' : '';
      label.style.pointerEvents = isGreyed ? 'none'  : '';
    }

    // Replacement badge — injected next to the feature name
    const nameSpan = el.querySelector('[data-sf-name-slot]');
    if (nameSpan) {
      let badge = el.querySelector('[data-sf-replaced-badge]');
      if (hasVariantSelected) {
        const variantName = shadowedParents.get(sid);
        if (!badge) {
          badge = document.createElement('span');
          badge.setAttribute('data-sf-replaced-badge', '1');
          badge.style.cssText = 'font-family:"Crimson Pro",serif;font-size:0.7rem;font-style:italic;color:var(--text-muted);margin-left:0.45rem;';
          nameSpan.appendChild(badge);
        }
        badge.textContent = `→ ${variantName}`;
        // Visually show this base row as "checked" (variant is occupying the slot)
        const cbEl = el.querySelector('input[type=checkbox]');
        if (cbEl) {
          const vis = document.getElementById(cbEl.id + '-vis');
          if (vis) {
            vis.innerHTML      = `<span style="color:var(--gold);font-size:11px;line-height:1;">✓</span>`;
            vis.style.borderColor = 'var(--gold)';
            vis.style.background  = 'rgba(201,168,76,0.15)';
          }
        }
      } else {
        if (badge) badge.remove();
        // Reset visual checkbox if not directly selected
        if (!isDirectlySelected) {
          const cbEl = el.querySelector('input[type=checkbox]');
          if (cbEl && !cbEl.checked) {
            const vis = document.getElementById(cbEl.id + '-vis');
            if (vis) {
              vis.innerHTML         = '';
              vis.style.borderColor = 'var(--gold-dark)';
              vis.style.background  = 'var(--bg-surface)';
            }
          }
        }
      }
    }

    // ── Feature replacement: reposition replacement rows + grey out originals ──
    // The parent body div is 'sf-row-{sid}' (expanded body, not the outer wrapper).
    const parentBodyEl = document.getElementById('sf-row-' + sid);
    const stagingEl    = document.getElementById('sfr-staging-' + sid);
    if (parentBodyEl) {
      if (hasVariantSelected) {
        const selVarSid = variantForParent.get(sid);
        parentBodyEl.querySelectorAll('[data-sfr-variant-block]').forEach(block => {
          const bSid  = block.getAttribute('data-sfr-variant-block');
          const slugs = (block.getAttribute('data-sfr-replaces') || '').split(',').filter(Boolean);
          if (bSid === selVarSid) {
            // Move this block to sit ABOVE the first replaced original row
            const firstOrig = slugs.map(s => parentBodyEl.querySelector(`[data-sfr-slug="${s}"]`)).find(Boolean);
            if (firstOrig && firstOrig.parentNode) {
              firstOrig.parentNode.insertBefore(block, firstOrig);
            }
            block.style.display = '';
            // Grey out + strikethrough the replaced original ability rows (still expandable)
            slugs.forEach(slug => {
              const orig = parentBodyEl.querySelector(`[data-sfr-slug="${slug}"]`);
              if (orig) {
                orig.style.opacity    = '0.42';
                orig.style.filter     = 'grayscale(0.5)';
                orig.style.transition = 'opacity 0.2s, filter 0.2s';
                // Strikethrough the name text only; leave click handler intact for collapse
                const nameEl = orig.querySelector('.char-cf-name');
                if (nameEl) nameEl.style.textDecoration = 'line-through';
              }
            });
          } else {
            // A different variant's block — park it back in staging and hide it
            if (stagingEl) stagingEl.appendChild(block);
            block.style.display = 'none';
          }
        });
      } else {
        // No variant selected — restore all original rows and return blocks to staging
        parentBodyEl.querySelectorAll('[data-sfr-variant-block]').forEach(block => {
          const slugs = (block.getAttribute('data-sfr-replaces') || '').split(',').filter(Boolean);
          slugs.forEach(slug => {
            const orig = parentBodyEl.querySelector(`[data-sfr-slug="${slug}"]`);
            if (orig) {
              orig.style.opacity = '';
              orig.style.filter  = '';
              const nameEl = orig.querySelector('.char-cf-name');
              if (nameEl) nameEl.style.textDecoration = '';
            }
          });
          if (stagingEl) stagingEl.appendChild(block);
          block.style.display = 'none';
        });
      }
    }
  });

  // ── Variant rows (focused schools, subdomains, elemental schools) ──────────
  document.querySelectorAll(`[data-sf-group="${groupSlug}"][data-sf-sub-sid]`).forEach(el => {
    const parentSid  = el.getAttribute('data-sf-parent-sid');
    const variantSid = el.getAttribute('data-sf-sub-sid');
    const isSelected = !!selectedSecondaryFeatures[variantSid];

    let isGreyed;
    if (parentSid === '__elemental__') {
      // Elemental grey unless: nothing else is selected or this one is selected
      isGreyed = (atLimit && !isSelected) || selectedBaseSids.size > 0 || shadowedParents.size > 0;
    } else {
      // Focused school / subdomain: grey if its parent base is directly selected,
      // or if we're at limit and this isn't the one selected, or if elemental chosen
      isGreyed = elementalSelected
        || selectedBaseSids.has(parentSid)
        || (atLimit && !isSelected);
    }

    const label = el.querySelector('label');
    if (label) {
      label.style.opacity       = isGreyed ? '0.32' : '';
      label.style.pointerEvents = isGreyed ? 'none'  : '';
    }
    // Dim the row header text slightly (but still readable/expandable)
    const headerDiv = el.querySelector('div');
    if (headerDiv) headerDiv.style.opacity = isGreyed ? '0.45' : '';
  });
}

function toggleSecondaryFeature(sectionId, featureName, subtype, pickCount, groupSlug, parentSectionId) {
  const checkId = 'sf-check-' + sectionId;
  const cb = document.getElementById(checkId);
  if (!cb) return;

  if (cb.checked) {
    // Enforce pick limit across the entire group (base + all variant subtypes combined)
    const currentPicks = groupSlug
      ? Object.values(selectedSecondaryFeatures).filter(f => f.groupSlug === groupSlug).length
      : Object.values(selectedSecondaryFeatures).filter(f => f.subtype === subtype).length;
    if (currentPicks >= pickCount) {
      cb.checked = false;
      const lbl = SECONDARY_SUBTYPE_LABELS[subtype] || 'selection';
      showToast(`You can only select ${pickCount} ${lbl}${pickCount > 1 ? 's' : ''}`);
      return;
    }
    // Store groupSlug on the entry so refreshSFMutualExclusion can find all group members
    // Also capture the rendered body from the selection list DOM for the collapsible child box
    const _bodyDiv   = document.getElementById('sf-row-' + sectionId);
    const _checkEl   = document.getElementById('sf-check-' + sectionId);
    const _skillsRaw = _checkEl ? (_checkEl.getAttribute('data-sf-skills') || '') : '';
    const _spellsRaw = _checkEl ? (_checkEl.getAttribute('data-sf-spells') || '') : '';
    const _sfAnnot2  = document.getElementById('sf-check-' + sectionId);
    const _noteAttr  = _sfAnnot2 ? (_sfAnnot2.getAttribute('data-sf-notes') || '') : '';
    selectedSecondaryFeatures[sectionId] = {
      name: featureName,
      subtype,
      parentSectionId: parentSectionId || null,
      groupSlug: groupSlug || null,
      body:          _bodyDiv ? _bodyDiv.innerHTML : '',
      classSkills:   _skillsRaw ? _skillsRaw.split('||') : [],
      bonusSpells:   _spellsRaw,
      skillNotes:    _noteAttr,
      grantedPowers: _sfGrantedPowers[sectionId] || [],
    };
  } else {
    delete selectedSecondaryFeatures[sectionId];
  }

  // Update visual checkbox
  const vis = document.getElementById(checkId + '-vis');
  if (vis) {
    vis.innerHTML = cb.checked ? `<span style="color:var(--gold);font-size:11px;line-height:1;">✓</span>` : '';
    vis.style.borderColor = cb.checked ? 'var(--gold)' : 'var(--gold-dark)';
    vis.style.background   = cb.checked ? 'rgba(201,168,76,0.15)' : 'var(--bg-surface)';
  }

  // Update the selection counter for this group (counts all picks in the group)
  if (groupSlug) {
    const countEl = document.getElementById('sf-count-' + groupSlug);
    if (countEl) {
      const picks = Object.values(selectedSecondaryFeatures).filter(f => f.groupSlug === groupSlug).length;
      countEl.textContent = `${picks} / ${pickCount} selected`;
      countEl.style.color = picks === pickCount ? 'var(--gold)' : 'var(--gold-dark)';
    }
  }

  // Update add-button label and requirement state
  const sfCount   = Object.keys(selectedSecondaryFeatures).length;
  const archCount = Object.keys(selectedArchetypes).length;
  const total = sfCount + archCount;
  const btn = document.getElementById('detail-build-btn');
  if (btn && !btn.textContent.startsWith('✕') && !btn.textContent.startsWith('✓')) {
    btn.textContent = total > 0
      ? `+ Add to Character (${total} selection${total > 1 ? 's' : ''})`
      : '+ Add to Character';
  }
  // Re-check class requirements live as selections change
  const _reqClsName = (currentDetail && (currentDetail.name || currentDetail._name) || '').toLowerCase();
  refreshClassAddButtonReqs(_reqClsName);

  // Refresh mutual-exclusion visuals for all rows in this group
  if (groupSlug) refreshSFMutualExclusion(groupSlug, pickCount);

  // Update the class feature row (e.g. "Mystery" row) with selected item tags + child boxes
  injectSelectedFeaturesIntoCFRow(subtype);
  // Refresh class-skill addition notices for all active SFs
  refreshSFMetaSections();
}

// ─── Inject selected secondary features into the matching Class Feature row ───
// When a Mystery/Bloodline/Domain/etc. is selected, this finds the corresponding
// class feature row (e.g. cf-feat-mystery) in the detail panel and:
//   1. Adds name badge tags to the row header
//   2. Inserts a child info box inside the row body
// Works for all classes using CLASS_SECONDARY_TYPES (Oracle, Sorcerer, Cleric, etc.)
function injectSelectedFeaturesIntoCFRow(subtype) {
  const cfRowEl = document.querySelector(`[data-cf-sf-subtype="${subtype}"]`);
  if (!cfRowEl) return;

  const slug      = cfRowEl.id.replace('cf-feat-', '');
  const clsColor  = currentDetail ? getClassColor(currentDetail) : 'var(--gold)';
  const typeLabel = SECONDARY_SUBTYPE_LABELS[subtype] || subtype.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

  // Collect non-variant selections of this subtype (exclude focused schools / subdomains)
  const selections = Object.values(selectedSecondaryFeatures)
    .filter(f => f.subtype === subtype && !f.parentSectionId);

  // ── Update tag badges in the row header ───────────────────────────────────
  const tagsEl = document.getElementById(`cf-sf-tags-${slug}`);
  if (tagsEl) {
    tagsEl.innerHTML = selections.map(f =>
      `<span style="font-family:'Crimson Pro',serif;font-size:0.72rem;background:rgba(201,168,76,0.18);` +
      `border:1px solid rgba(201,168,76,0.5);border-radius:3px;padding:0.1rem 0.45rem;` +
      `color:var(--gold-light);white-space:nowrap;line-height:1.4;">${f.name}</span>`
    ).join('');
  }

  // ── Update collapsible child boxes in the row body ────────────────────────
  const childrenEl = document.getElementById(`cf-sf-child-${slug}`);
  if (childrenEl) {
    childrenEl.innerHTML = selections.map((f, i) => {
      const childId  = `cf-sf-cbox-${slug}-${i}`;
      const hasBody  = !!(f.body && f.body.trim());
      return (
        `<div style="border:1px solid var(--border);border-left:2px solid ${clsColor};` +
        `border-radius:0 4px 4px 0;overflow:hidden;margin-bottom:0.35rem;background:rgba(201,168,76,0.04);">` +
        `<div style="padding:0.4rem 0.85rem;display:flex;align-items:center;gap:0.5rem;${hasBody ? 'cursor:pointer;' : ''}` +
        `transition:background 0.15s;"` +
        (hasBody
          ? ` onclick="(function(el){var b=document.getElementById('${childId}');var a=el.querySelector('.sf-carr');` +
            `b.style.display=b.style.display==='none'?'block':'none';` +
            `a.textContent=b.style.display==='none'?'▸':'▾';})(this)"` +
            ` onmouseover="this.style.background='rgba(201,168,76,0.08)'"` +
            ` onmouseout="this.style.background=''"`
          : '') +
        `>` +
        (hasBody ? `<span class="sf-carr" style="color:${clsColor};font-size:0.7rem;width:10px;flex-shrink:0;">▸</span>` : '') +
        `<span style="font-family:Cinzel,serif;font-size:0.65rem;color:${clsColor};text-transform:uppercase;letter-spacing:0.08em;">${typeLabel}</span>` +
        `<span style="font-family:Cinzel,serif;color:var(--text-primary);font-size:0.82rem;flex:1;">${f.name}</span>` +
        `</div>` +
        (hasBody
          ? `<div id="${childId}" style="display:none;padding:0.6rem 0.9rem 0.7rem 1.4rem;background:var(--bg-surface);border-top:1px solid var(--border);">${f.body}</div>`
          : '') +
        `</div>`
      );
    }).join('');
  }
}

function toggleOppositionSchool(sectionId, name) {
  const oppCheckId = 'sf-opp-' + sectionId;
  const cb = document.getElementById(oppCheckId);
  if (!cb) return;

  if (cb.checked) {
    selectedOppositionSchools[sectionId] = name;
  } else {
    delete selectedOppositionSchools[sectionId];
  }

  const isOpp = !!selectedOppositionSchools[sectionId];

  // Update checkbox visual
  const vis = document.getElementById(oppCheckId + '-vis');
  if (vis) {
    vis.innerHTML = isOpp ? '<span style="color:#cc3333;font-size:11px;line-height:1;">✓</span>' : '';
    vis.style.borderColor = isOpp ? '#cc3333' : 'var(--gold-dark)';
    vis.style.background  = isOpp ? 'rgba(200,50,50,0.15)' : 'var(--bg-surface)';
  }

  // Update row banner styling
  const rowWrap   = document.getElementById('sf-row-' + sectionId + '-wrap');
  const rowHeader = document.getElementById('sf-row-' + sectionId + '-header');
  if (rowWrap) {
    rowWrap.style.borderLeft  = isOpp ? '3px solid #cc3333' : '';
    rowWrap.style.borderColor = isOpp ? 'rgba(200,50,50,0.4)' : '';
  }
  if (rowHeader) {
    rowHeader.style.background = isOpp ? 'rgba(200,50,50,0.08)' : 'var(--bg-card)';
    rowHeader.onmouseover = isOpp
      ? function() { this.style.background = 'rgba(200,50,50,0.14)'; }
      : function() { this.style.background = 'var(--bg-hover)'; };
    rowHeader.onmouseout = isOpp
      ? function() { this.style.background = 'rgba(200,50,50,0.08)'; }
      : function() { this.style.background = 'var(--bg-card)'; };
  }
}

// Parse a domain/bloodline spell-list body into [{level, spell}] entries.
// Handles two formats:
//   "1st—obscuring mist, 2nd—wind wall, ..."      (domain spells)
//   "enlarge person (3rd), see invisibility (5th), ..."  (bloodline bonus spells)
function parseSpellList(bodyHtml) {
  const raw = (bodyHtml || '')
    .replace(/<i>/gi, '').replace(/<\/i>/gi, '')
    .replace(/<[^>]+>/g, '')
    .replace(/&mdash;/g, '—').replace(/&ndash;/g, '–')
    .replace(/&[a-z]+;/g, ' ').replace(/\s+/g, ' ').trim();

  // Format A: "1st—spell, 2nd—spell, ..."
  const fmtA = [...raw.matchAll(/(\d+)(?:st|nd|rd|th)\s*[—–-]\s*([^,\.]+?)(?=,\s*\d|$|\.)/gi)];
  if (fmtA.length) return fmtA.map(m => ({ level: parseInt(m[1]), spell: m[2].trim() }));

  // Format B: "spell (3rd), spell2 (5th), ..."
  const fmtB = [...raw.matchAll(/([^,(]+?)\s*\((\d+)(?:st|nd|rd|th)\)/gi)];
  if (fmtB.length) return fmtB.map(m => ({ level: parseInt(m[2]), spell: m[1].trim() }));

  return [];
}

function renderSpellGrid(bodyHtml, gridLabel) {
  const spells = parseSpellList(bodyHtml);
  const ordinal = n => (['','1st','2nd','3rd','4th','5th','6th','7th','8th','9th'][n] || n + 'th');

  if (!spells.length) {
    // Fallback: plain text
    const text = (bodyHtml || '').replace(/<[^>]+>/g, '').replace(/&[a-z]+;/g, ' ').trim();
    return `<div style="color:var(--text-secondary);font-size:0.85rem;line-height:1.6;font-style:italic;">${text}</div>`;
  }

  const pills = spells.map(s =>
    `<div style="display:flex;align-items:center;gap:0.35rem;padding:0.18rem 0.55rem 0.18rem 0.4rem;background:var(--bg-card);border:1px solid var(--border);border-radius:4px;">
       <span style="font-family:Cinzel,serif;font-size:0.6rem;color:var(--gold-dark);flex-shrink:0;min-width:22px;text-align:center;">${ordinal(s.level)}</span>
       <span style="color:var(--text-secondary);font-size:0.8rem;font-style:italic;white-space:nowrap;">${s.spell}</span>
     </div>`
  ).join('');

  return `<div style="margin-top:0.4rem;">
    <div style="font-family:Cinzel,serif;font-size:0.68rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.09em;margin-bottom:0.3rem;">${gridLabel}</div>
    <div style="display:flex;flex-wrap:wrap;gap:0.25rem;">${pills}</div>
  </div>`;
}

// Render a single ability as a char-cf-row style collapsible banner —
// matches the look of class feature rows in the class features panel.
function renderAbilityAsFeatureRow(ab, classColor) {
  // Use raw HTML body to preserve <b>/<strong> tags from the DB (e.g. "+6 at 8th level").
  // boldKeyTerms() is HTML-aware (skips tag content) so it's safe to call on raw HTML.
  const abText = (ab.body || '').trim();
  const abId = 'sfab-' + (ab.section_id || Math.random().toString(36).slice(2, 8));
  // data-sfr-slug lets refreshSFMutualExclusion find and hide/show this row by power name
  const slug = (ab.name || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const slugAttr = slug ? ` data-sfr-slug="${slug}"` : '';
  return `
    <div class="char-cf-row"${slugAttr} style="border-left:3px solid ${classColor};margin-bottom:0.2rem;">
      <div class="char-cf-row-header"
           onclick="event.stopPropagation();(function(h){var b=h.nextElementSibling,a=h.querySelector('.char-cf-arr');var open=b.style.display!=='block';b.style.display=open?'block':'none';a.style.transform=open?'rotate(90deg)':'rotate(0deg)';})(this)">
        <span class="char-cf-arr" style="color:${classColor};">▸</span>
        <span class="char-cf-name">${ab.name}</span>
      </div>
      <div class="char-cf-row-body">
        ${abText ? boldKeyTerms(abText) : '<em style="color:var(--text-muted)">No description.</em>'}
      </div>
    </div>`;
}

// Render the body of a single secondary feature (domain, bloodline entry, etc.)
function renderSecondaryFeatureBody(feat, classColor) {
  const plain = s => (s || '').replace(/<[^>]+>/g, '').trim();
  const parts = [];

  // Top-level body text (rare for domains/bloodlines, but exists for some)
  const topBody = plain(feat.body);
  if (topBody) {
    parts.push(`<div style="color:var(--text-secondary);font-size:0.88rem;line-height:1.6;margin-bottom:0.45rem;">${boldKeyTerms(topBody)}</div>`);
  }

  const subs = (feat.sections || []).filter(s => s && s.type !== 'link');
  for (const sub of subs) {
    const subName = sub.name || '';
    const isDomainSpells  = /(?:replacement )?domain spells?/i.test(subName);
    const isBonusSpells   = /(?:replacement )?bonus spells?/i.test(subName);
    const isGrantedPowers = /granted powers?/i.test(subName) || /^replacement power$/i.test(subName);
    const isRevelations   = /revelations?/i.test(subName);

    if (isDomainSpells || isBonusSpells) {
      parts.push(renderSpellGrid(sub.body, isDomainSpells ? 'Domain Spells' : 'Bonus Spells'));
      continue;
    }

    if (isGrantedPowers || isRevelations) {
      // Optional prose intro on the granted powers section itself
      const gpText = plain(sub.body);
      if (gpText) parts.push(`<div style="color:var(--text-secondary);font-size:0.85rem;line-height:1.55;margin-bottom:0.3rem;">${boldKeyTerms(gpText)}</div>`);

      // Each ability rendered as a char-cf-row collapsible banner
      const abilities = (sub.sections || []).filter(s => s && s.type !== 'link' && s.name);
      if (abilities.length) {
        const hdr = isRevelations ? 'Revelations' : 'Granted Powers';
        parts.push(`<div style="font-family:Cinzel,serif;font-size:0.65rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.1em;margin:0.5rem 0 0.3rem;">${hdr}</div>`);
        parts.push(`<div style="display:flex;flex-direction:column;gap:0.15rem;">`);
        for (const ab of abilities) {
          parts.push(renderAbilityAsFeatureRow(ab, classColor));
        }
        parts.push(`</div>`);
      }
      continue;
    }

    // Generic named sub-section.
    // Case A: has child abilities (e.g. Bloodline Powers, Bonus Feats grouping)
    //   → render section name as a label, then each child as a char-cf-row
    // Case B: is itself an ability with a body but no children (e.g. Wizard school powers
    //   stored as direct subsections: Summoner's Charm, Acid Dart, etc.)
    //   → render the subsection itself as a char-cf-row
    const genericAbilities = (sub.sections || []).filter(s => s && s.type !== 'link' && s.name);
    const subText = plain(sub.body);

    if (genericAbilities.length) {
      // Case A — named grouping with child abilities
      if (subName) {
        parts.push(`<div style="font-family:Cinzel,serif;color:var(--gold-dark);font-size:0.7rem;text-transform:uppercase;letter-spacing:0.08em;margin:0.55rem 0 0.2rem;">${subName}</div>`);
      }
      if (subText) parts.push(`<div style="color:var(--text-secondary);font-size:0.85rem;line-height:1.55;margin-bottom:0.25rem;">${boldKeyTerms(subText)}</div>`);
      parts.push(`<div style="display:flex;flex-direction:column;gap:0.15rem;">`);
      for (const ab of genericAbilities) {
        parts.push(renderAbilityAsFeatureRow(ab, classColor));
      }
      parts.push(`</div>`);
    } else if (subName && subText) {
      // Case B — leaf ability: render as a collapsible char-cf-row banner
      parts.push(renderAbilityAsFeatureRow(sub, classColor));
    } else if (subName) {
      // Plain label with no body and no children (rare)
      parts.push(`<div style="font-family:Cinzel,serif;color:var(--gold-dark);font-size:0.7rem;text-transform:uppercase;letter-spacing:0.08em;margin:0.55rem 0 0.2rem;">${subName}</div>`);
    }
  }

  return parts.join('') || `<span style="color:var(--text-muted);font-size:0.85rem;font-style:italic;">No description available.</span>`;
}

// ─── Sub-feature body renderer ────────────────────────────────────────────────
// Like renderSecondaryFeatureBody but strips "Associated School/Domain" sections
// (already shown as a label) and is used for focused schools and subdomains.
function renderSubFeatureBody(sf, classColor) {
  const filtered = {
    ...sf,
    sections: (sf.sections || []).filter(s =>
      s && !/^associated (school|domain)$/i.test(s.name || '')
    ),
  };
  return renderSecondaryFeatureBody(filtered, classColor);
}

// NOTE: renderVariantCategoryBanners / renderVariantCategoryBanner have been removed.
// Variants are now nested inside their parent school/domain rows via renderNestedVariants().
// Elemental Schools (which replace ALL schools) use renderElementalSchoolsBanner().

// ─── Extract class-skill additions and bonus-spell text from a secondary feature ──────
// Returns { classSkills: string[], bonusSpells: string } where classSkills is an array of
// parsed skill names and bonusSpells is the raw text of the Bonus Spells section.
function extractSFAnnotations(item) {
  const plain = s => (s || '').replace(/<[^>]+>/g, '').trim();
  const classSkills = [];
  let bonusSpells   = '';
  let skillNotes    = ''; // extra notes beyond the class skill list (e.g. untrained, scaling bonuses)

  for (const sec of (item.sections || [])) {
    if (!sec) continue;
    const sName = (sec.name || '').trim();

    // ── Class Skills ──────────────────────────────────────────────────────────
    if (/^(?:class\s+)?skills?$/i.test(sName)) {
      const fullText = plain(sec.body);
      if (!fullText) continue;
      let text = fullText;
      const colonIdx = text.indexOf(':');
      if (colonIdx >= 0 && colonIdx < text.length - 2) {
        // Colon format: "Class Skills: Acrobatics, Bluff, ..." — strip the preamble
        text = text.slice(colonIdx + 1);
      } else {
        // Prose format: "X adds Intimidate, Perception, and Ride to her list of class skills"
        // Extract just the skill list between "adds" and "to (her|his|their|the) list"
        const proseMatch = text.match(/\badds?\s+(.+?)\s+to\s+(?:her|his|their|the)\b/i);
        if (proseMatch) text = proseMatch[1];
        // If no prose match either, fall through and try to split the full text as-is
      }
      // Split on commas and "and", then strip trailing ability score "(Xxx)" and punctuation
      text.split(/,\s*|\s+and\s+/i).forEach(part => {
        const skill = part.trim()
          .replace(/^(?:and|or)\s+/i, '')  // strip leftover "and "/"or " when comma split leaves it
          .replace(/\s*\((?:Str|Dex|Con|Int|Wis|Cha)\)[.,]?\s*$/i, '')
          .replace(/[.,]+$/, '')
          .trim();
        if (skill.length > 2) classSkills.push(skill);
      });
      // Capture any additional text beyond the skills-list sentence as special notes
      // (e.g. "can make Knowledge (nobility) checks untrained; 1/2 level bonus…")
      const skillListEnd = fullText.match(/\blist of class skills\.?\s*/i);
      if (skillListEnd) {
        const remaining = fullText.slice(fullText.indexOf(skillListEnd[0]) + skillListEnd[0].length).trim();
        if (remaining.length > 10) skillNotes = remaining;
      } else if (fullText.length > text.length + 5) {
        // Fallback: store full text as notes if it's substantially longer than just the list
        skillNotes = fullText;
      }
    }

    // ── Bonus Spells / Domain Spells ──────────────────────────────────────────
    if (/bonus spells?|domain spells?/i.test(sName)) {
      const text = plain(sec.body);
      if (text) bonusSpells = text;
    }
  }

  return { classSkills, bonusSpells, skillNotes };
}

// Extract level-gated powers from a secondary feature (bloodline, domain, school, mystery, spirit, etc.)
// Walks item.sections looking for sub-sections named "Bloodline Powers", "Domain Powers", etc.
// Returns [{name, body, reqLevel}] sorted by reqLevel.
function extractGrantedPowers(item) {
  const powers = [];
  const plain = s => (s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

  // Level-indicator patterns inside power body text
  function parseReqLevel(bodyText) {
    const txt = plain(bodyText);
    const m = txt.match(/(?:starting at|at)\s+(\d+)(?:st|nd|rd|th)\s+level/i)
           || txt.match(/must be at least (\d+)(?:st|nd|rd|th)/i)
           || txt.match(/minimum (?:of )?(\d+)(?:st|nd|rd|th)\s+level/i);
    return m ? parseInt(m[1]) : 1;
  }

  // Heading names that indicate a "powers" sub-section
  const POWERS_RE = /\b(bloodline\s+)?powers?\b|spirit\s+abilit|school\s+powers?|domain\s+powers?|mystery\s+powers?|order\s+abilit|arcana|bonus\s+feat/i;
  // Order informational sections shown as level-1 info entries
  const ORDER_INFO_RE = /^(?:edicts|challenge|skills)$/i;

  for (const sec of (item.sections || [])) {
    if (!sec) continue;
    const sName = (sec.name || '').toLowerCase();

    // Capture Edict / Challenge / Skills for warrior_orders as level-1 informational powers
    if (ORDER_INFO_RE.test(sName) && item.subtype === 'warrior_order') {
      powers.push({ name: sec.name, body: sec.body || '', reqLevel: 1 });
      continue;
    }

    if (!POWERS_RE.test(sName)) continue;
    // Skip pure "bonus spells" sections — those are handled separately
    if (/bonus\s+spells?/i.test(sName)) continue;

    for (const sub of (sec.sections || [])) {
      if (!sub || !sub.name) continue;
      const reqLevel = parseReqLevel(sub.body);
      powers.push({ name: sub.name, body: sub.body || '', reqLevel });
    }
  }

  // ── Warpriest Blessings ────────────────────────────────────────────────────
  // Blessings don't use a "powers container" section — "Minor Blessing" and
  // "Major Blessing" are direct children of the blessing item itself.
  // Minor blessings are available from level 1; major blessings from level 6.
  for (const sec of (item.sections || [])) {
    if (!sec || !sec.name) continue;
    if (/^(?:minor|major)\s+blessing$/i.test(sec.name)) {
      const fallbackLevel = /^major/i.test(sec.name) ? 6 : 1;
      const reqLevel      = parseReqLevel(sec.body) || fallbackLevel;
      powers.push({ name: sec.name, body: sec.body || '', reqLevel });
    }
  }

  return powers.sort((a, b) => a.reqLevel - b.reqLevel);
}

// Render level-gated granted power rows (used in "From Selections" on character page)
function buildGrantedPowersHtml(grantedPowers, clsLevel, clsColor) {
  if (!grantedPowers || !grantedPowers.length) return '';
  return grantedPowers.map((p, idx) => {
    const isActive  = clsLevel >= p.reqLevel;
    const hasBody   = !!(p.body && p.body.trim());
    const bodyId    = `gp-body-${slugify(p.name)}-${idx}`;
    const arrId     = `gp-arr-${slugify(p.name)}-${idx}`;

    const isNew     = isActive && clsLevel === p.reqLevel;
    const rowBg     = isActive ? `${clsColor}12` : `rgba(100,100,100,0.05)`;
    const borderClr = isActive ? clsColor : `rgba(150,150,150,0.3)`;
    const opacity   = isActive ? '1' : '0.55';
    const icon      = isActive ? '✦' : '◇';
    const iconColor = isActive ? clsColor : 'var(--text-muted)';
    const nameColor = isActive ? clsColor : 'var(--text-muted)';
    const cursor    = hasBody ? 'pointer' : 'default';
    const newBadge  = isNew
      ? `<span style="background:#3d75c4;color:#fff;font-size:0.52rem;font-family:Cinzel,serif;font-weight:700;letter-spacing:0.07em;text-transform:uppercase;padding:0.1rem 0.32rem;border-radius:3px;margin-left:0.4rem;vertical-align:middle;">New!</span>`
      : '';

    const toggleFn  = hasBody
      ? `(function(el){var b=document.getElementById('${bodyId}');var a=document.getElementById('${arrId}');var open=b.style.display!=='block';b.style.display=open?'block':'none';a.style.transform=open?'rotate(90deg)':'rotate(0deg)';})(this)`
      : '';

    return `<div style="margin:2px 0;border-radius:3px;background:${rowBg};border-left:2px solid ${borderClr};opacity:${opacity};">
      <div onclick="${toggleFn}" style="display:flex;gap:0.5rem;align-items:center;padding:0.3rem 0.7rem;cursor:${cursor};">
        <span style="color:${iconColor};font-size:0.7rem;flex-shrink:0;">${icon}</span>
        ${hasBody ? `<span id="${arrId}" style="color:${nameColor};font-size:0.65rem;flex-shrink:0;transition:transform 0.15s;display:inline-block;">▸</span>` : ''}
        <span style="font-size:0.8rem;line-height:1.4;flex:1;">
          <strong style="color:${nameColor};">${boldKeyTerms(p.name)}</strong>
          <span style="font-size:0.7rem;color:var(--text-muted);margin-left:0.3rem;">(Lvl ${p.reqLevel})</span>${newBadge}
        </span>
      </div>
      ${hasBody ? `<div id="${bodyId}" style="display:none;padding:0.4rem 0.9rem 0.55rem 1.8rem;border-top:1px solid ${borderClr}40;font-size:0.8rem;color:${isActive ? 'var(--text-primary)' : 'var(--text-muted)'};line-height:1.5;">${p.body}</div>` : ''}
    </div>`;
  }).join('');
}

// Render a full secondary-feature selector block (e.g. the full Domains section of Cleric)
// Variants (Focused Schools, Subdomains) are nested INSIDE their parent school/domain,
// styled like archetype replacements in the class-features panel.
function renderSecondaryFeatureList(feat, classColor, pickCount) {
  const items = (feat.sections || []).filter(s => s && s.type !== 'link' && s.name);
  if (!items.length) return '';

  const groupSlug  = slugify(feat.name);
  const label      = feat.name || 'Selections';
  const pickLabel  = pickCount > 1 ? `— Choose ${pickCount}` : '— Choose 1';
  const currentSel = Object.values(selectedSecondaryFeatures).filter(f => f.groupSlug === groupSlug).length;

  // Sub-feature map (focused schools, elemental schools, subdomains) loaded by loadCrossBookSubFeatures
  const subFeatMap = currentDetail?._subFeatures || {};

  let html = `<div style="margin-bottom:1.5rem;">
    <div style="display:flex;align-items:baseline;gap:0.6rem;font-family:Cinzel,serif;font-size:0.88rem;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:0.6rem;border-bottom:1px solid var(--border);padding-bottom:0.3rem;">
      <span style="color:var(--gold);">${label}</span>
      <span style="font-family:'Crimson Pro',serif;font-size:0.8rem;color:var(--text-muted);text-transform:none;letter-spacing:normal;font-style:italic;">${pickLabel}</span>
      <span id="sf-count-${groupSlug}" style="font-family:Cinzel,serif;font-size:0.7rem;color:${currentSel === pickCount ? 'var(--gold)' : 'var(--gold-dark)'};margin-left:auto;">${currentSel} / ${pickCount} selected</span>
    </div>
    <div style="display:flex;flex-direction:column;gap:0.3rem;">`;

  for (const item of items) {
    const sid          = item.section_id;
    const isChecked    = !!selectedSecondaryFeatures[sid];
    const isOpposition = !!selectedOppositionSchools[sid];
    const subtype      = item.subtype || '';
    const rowId        = 'sf-row-' + sid;
    const checkId      = 'sf-check-' + sid;
    const safeName     = (item.name || '').replace(/'/g, "\\'");

    // Body = full feature text
    const bodyHtml = renderSecondaryFeatureBody(item, classColor);

    // Extract class-skill additions, bonus-spell text, and skill notes for character-page display
    const _sfAnnot = extractSFAnnotations(item);
    const _skillsAttr  = _sfAnnot.classSkills.length  ? _sfAnnot.classSkills.join('||')       : '';
    const _spellsAttr  = _sfAnnot.bonusSpells         ? _sfAnnot.bonusSpells.replace(/"/g,"'") : '';
    const _notesAttr   = _sfAnnot.skillNotes          ? _sfAnnot.skillNotes.replace(/"/g,"'")  : '';

    // Extract level-gated granted powers (bloodline powers, domain powers, etc.)
    _sfGrantedPowers[sid] = extractGrantedPowers(item);

    // Find nested variants for this parent (focused schools / subdomains)
    const parentKey = (item.name || '').toLowerCase().replace(/ (school|domain)$/i, '');
    const nestedVariants = subFeatMap[parentKey] || [];

    // Pre-render hidden replacement blocks — one per variant that has replacement abilities.
    // Each block is hidden by default; refreshSFMutualExclusion shows the right one when selected.
    let variantBlocks = '';
    for (const sf of nestedVariants) {
      const replAbs = sf.replacementAbilities || [];
      const replaceSlugs = (sf.replaces || [])
        .map(r => r.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''))
        .join(',');
      if (!replAbs.length || !replaceSlugs) continue;
      const blockRows = replAbs.map(ab => renderAbilityAsFeatureRow(ab, classColor)).join('');
      variantBlocks += `<div data-sfr-variant-block="${sf.section_id}" data-sfr-replaces="${replaceSlugs}"
           style="display:none;border:1px solid var(--gold-dark);border-left:3px solid var(--gold);border-radius:0 5px 5px 0;background:rgba(201,168,76,0.05);padding:0.35rem 0.6rem 0.45rem 0.75rem;margin-bottom:0.3rem;">
        <div style="font-family:Cinzel,serif;font-size:0.6rem;color:var(--gold);text-transform:uppercase;letter-spacing:0.12em;margin-bottom:0.3rem;">✦ ${sf.name}</div>
        ${blockRows}
      </div>`;
    }

    html += `<div id="${rowId}-wrap" data-sf-sid="${sid}" data-sf-group="${groupSlug}" style="border:1px solid ${isOpposition ? 'rgba(200,50,50,0.4)' : 'var(--border)'};border-left:3px solid ${isOpposition ? '#cc3333' : classColor+'66'};border-radius:0 5px 5px 0;overflow:hidden;">
      <div id="${rowId}-header" style="display:flex;align-items:center;justify-content:space-between;padding:0.5rem 0.9rem;background:${isOpposition ? 'rgba(200,50,50,0.08)' : 'var(--bg-card)'};cursor:default;transition:background 0.15s;"
           onmouseover="this.style.background='${isOpposition ? 'rgba(200,50,50,0.14)' : 'var(--bg-hover)'}'" onmouseout="this.style.background='${isOpposition ? 'rgba(200,50,50,0.08)' : 'var(--bg-card)'}'">
        <div style="display:flex;align-items:center;gap:0.6rem;flex:1;cursor:pointer;"
             onclick="(function(el){var b=document.getElementById('${rowId}');var a=el.querySelector('.sf-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)">
          <span class="sf-arr" style="color:${classColor};font-size:0.72rem;width:10px;flex-shrink:0;">▸</span>
          <span data-sf-name-slot="1" style="font-family:Cinzel,serif;font-size:0.84rem;color:var(--text-primary);">${item.name}</span>
        </div>
        <label onclick="event.stopPropagation()" style="display:flex;align-items:center;gap:0.5rem;cursor:pointer;flex-shrink:0;margin-left:0.75rem;">
          <span style="font-family:Cinzel,serif;font-size:0.66rem;color:var(--text-secondary);text-transform:uppercase;letter-spacing:0.08em;">Select</span>
          <span style="position:relative;width:16px;height:16px;flex-shrink:0;display:inline-block;">
            <input type="checkbox" id="${checkId}" ${isChecked ? 'checked' : ''}
              onchange="toggleSecondaryFeature(${sid},'${safeName}','${subtype}',${pickCount},'${groupSlug}')"
              data-sf-skills="${_skillsAttr}" data-sf-spells="${_spellsAttr}" data-sf-notes="${_notesAttr}"
              style="position:absolute;opacity:0;width:100%;height:100%;margin:0;cursor:pointer;z-index:1;">
            <span id="${checkId}-vis" style="position:absolute;inset:0;border:1px solid ${isChecked ? 'var(--gold)' : 'var(--gold-dark)'};border-radius:3px;background:${isChecked ? 'rgba(201,168,76,0.15)' : 'var(--bg-surface)'};display:flex;align-items:center;justify-content:center;pointer-events:none;transition:background 0.15s,border-color 0.15s;">${isChecked ? `<span style="color:var(--gold);font-size:11px;line-height:1;">✓</span>` : ''}</span>
          </span>
        </label>
        ${subtype === 'arcane_school' ? `<label onclick="event.stopPropagation()" style="display:flex;align-items:center;gap:0.5rem;cursor:pointer;flex-shrink:0;margin-left:0.5rem;border-left:1px solid var(--border);padding-left:0.75rem;">
          <span style="font-family:Cinzel,serif;font-size:0.66rem;color:${isOpposition ? '#cc3333' : 'var(--text-secondary)'};text-transform:uppercase;letter-spacing:0.08em;">Oppose</span>
          <span style="position:relative;width:16px;height:16px;flex-shrink:0;display:inline-block;">
            <input type="checkbox" id="sf-opp-${sid}" ${isOpposition ? 'checked' : ''}
              onchange="toggleOppositionSchool(${sid},'${safeName}')"
              style="position:absolute;opacity:0;width:100%;height:100%;margin:0;cursor:pointer;z-index:1;">
            <span id="sf-opp-${sid}-vis" style="position:absolute;inset:0;border:1px solid ${isOpposition ? '#cc3333' : 'var(--gold-dark)'};border-radius:3px;background:${isOpposition ? 'rgba(200,50,50,0.15)' : 'var(--bg-surface)'};display:flex;align-items:center;justify-content:center;pointer-events:none;transition:background 0.15s,border-color 0.15s;">${isOpposition ? `<span style="color:#cc3333;font-size:11px;line-height:1;">✓</span>` : ''}</span>
          </span>
        </label>` : ''}
      </div>
      <div id="${rowId}" style="display:none;padding:0.6rem 0.9rem 0.7rem 1.4rem;background:var(--bg-surface);border-top:1px solid var(--border);">
        ${bodyHtml}
        <div id="sfr-staging-${sid}" style="display:contents;">${variantBlocks}</div>
        ${nestedVariants.length ? renderNestedVariants(nestedVariants, classColor, pickCount, groupSlug, sid) : ''}
      </div>
    </div>`;
  }

  html += `</div>`;

  // Elemental Schools — replace ALL standard schools, so they sit outside any single parent
  const elementalFeats = subFeatMap['__elemental__'] || [];
  if (elementalFeats.length) {
    html += renderElementalSchoolsBanner(elementalFeats, classColor, pickCount, groupSlug);
  }

  html += `</div>`;
  return html;
}

// ─── Render variant rows nested INSIDE a parent school/domain ─────────────────
// Styled like archetype replacement rows: indented, with a "replaces" badge,
// collapsible body, and a checkbox that counts against the same pick limit.
function renderNestedVariants(variants, classColor, pickCount, groupSlug, parentSid) {
  if (!variants.length) return '';

  // Group by subtype label for a small header
  const bySubtype = {};
  for (const sf of variants) {
    const st = sf.subtype || sf._parentSubtype || 'variant';
    if (!bySubtype[st]) bySubtype[st] = [];
    bySubtype[st].push(sf);
  }

  const subtypeLabels = {
    'focused_arcane_school': 'Focused Schools',
    'cleric_subdomain': 'Subdomains',
  };

  let html = '';
  for (const [st, feats] of Object.entries(bySubtype)) {
    const catLabel = subtypeLabels[st] || st.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

    html += `<div style="margin-top:0.7rem;border-top:1px solid var(--border);padding-top:0.5rem;">
      <div style="font-family:Cinzel,serif;font-size:0.68rem;text-transform:uppercase;letter-spacing:0.1em;color:var(--gold-dark);margin-bottom:0.35rem;display:flex;align-items:center;gap:0.4rem;">
        <span>${catLabel}</span>
        <span style="font-family:'Crimson Pro',serif;font-size:0.7rem;font-style:italic;color:var(--text-muted);text-transform:none;letter-spacing:normal;">— replaces this ${st.includes('school') ? 'school' : 'domain'}</span>
      </div>
      <div style="display:flex;flex-direction:column;gap:0.2rem;">`;

    for (const sf of feats) {
      const sid       = sf.section_id;
      const isChecked = !!selectedSecondaryFeatures[sid];
      const checkId   = 'sf-check-' + sid;
      const rowId     = 'sf-row-' + sid;
      const safeName  = (sf.name || '').replace(/'/g, "\\'");
      const parentSubtype = sf._parentSubtype || sf.subtype;
      const subBody   = renderSubFeatureBody(sf, classColor);

      // Build a specific "Replaces: Acid Dart" badge label from parsed data
      const capitalize = w => w ? w[0].toUpperCase() + w.slice(1) : '';
      const replaceLabel = (sf.replaces && sf.replaces.length)
        ? 'Replaces: ' + sf.replaces.map(r => r.split(' ').map(capitalize).join(' ')).join(', ')
        : 'Replaces';

      html += `
        <div id="${rowId}-sub-wrap" data-sf-sub-sid="${sid}" data-sf-parent-sid="${parentSid}" data-sf-group="${groupSlug}"
             style="border:1px solid var(--border);border-left:2px solid ${classColor}55;border-radius:0 4px 4px 0;overflow:hidden;">
          <div style="display:flex;align-items:center;justify-content:space-between;padding:0.38rem 0.7rem;background:var(--bg-card);transition:background 0.15s;"
               onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-card)'">
            <div style="display:flex;align-items:center;gap:0.5rem;flex:1;cursor:pointer;"
                 onclick="(function(el){var b=document.getElementById('${rowId}-sub');var a=el.querySelector('.sfv-sub-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)">
              <span class="sfv-sub-arr" style="color:${classColor}88;font-size:0.62rem;width:8px;flex-shrink:0;">▸</span>
              <div style="display:flex;align-items:center;gap:0.45rem;line-height:1.25;">
                <span style="font-family:Cinzel,serif;font-size:0.81rem;color:var(--text-primary);">${sf.name}</span>
                <span class="char-cf-replaced" style="font-size:0.58rem;">${replaceLabel}</span>
              </div>
            </div>
            <label onclick="event.stopPropagation()" style="display:flex;align-items:center;gap:0.4rem;cursor:pointer;flex-shrink:0;margin-left:0.65rem;">
              <span style="font-family:Cinzel,serif;font-size:0.59rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Select</span>
              <span style="position:relative;width:14px;height:14px;flex-shrink:0;display:inline-block;">
                <input type="checkbox" id="${checkId}" ${isChecked ? 'checked' : ''}
                  onchange="toggleSecondaryFeature(${sid},'${safeName}','${parentSubtype}',${pickCount},'${groupSlug}',${parentSid})"
                  style="position:absolute;opacity:0;width:100%;height:100%;margin:0;cursor:pointer;z-index:1;">
                <span id="${checkId}-vis" style="position:absolute;inset:0;border:1px solid ${isChecked ? 'var(--gold)' : 'var(--gold-dark)'};border-radius:2px;background:${isChecked ? 'rgba(201,168,76,0.15)' : 'var(--bg-surface)'};display:flex;align-items:center;justify-content:center;pointer-events:none;transition:background 0.15s,border-color 0.15s;">${isChecked ? `<span style="color:var(--gold);font-size:10px;line-height:1;">✓</span>` : ''}</span>
              </span>
            </label>
          </div>
          <div id="${rowId}-sub" style="display:none;padding:0.5rem 0.85rem 0.55rem 1.2rem;background:var(--bg-surface);border-top:1px solid var(--border);">
            ${subBody}
          </div>
        </div>`;
    }

    html += `</div></div>`;
  }

  return html;
}

// ─── Elemental Schools banner (replaces ALL arcane schools) ───────────────────
// These don't nest inside a single parent since they replace the entire school system.
// Rendered as a standalone collapsible section below the base schools list.
function renderElementalSchoolsBanner(feats, classColor, pickCount, groupSlug) {
  if (!feats.length) return '';
  const bannerId = `sfv-${groupSlug}-elemental`;

  let html = `
    <div style="margin-top:0.65rem;border:1px solid var(--border);border-left:3px solid ${classColor}55;border-radius:0 5px 5px 0;overflow:hidden;">
      <div style="display:flex;align-items:center;justify-content:space-between;padding:0.48rem 0.9rem;background:var(--bg-surface);cursor:pointer;user-select:none;"
           onclick="(function(btn){var b=document.getElementById('${bannerId}');var a=btn.querySelector('.sfv-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)"
           onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-surface)'">
        <div style="display:flex;align-items:baseline;gap:0.5rem;">
          <span class="sfv-arr" style="color:${classColor}99;font-size:0.65rem;width:10px;flex-shrink:0;">▸</span>
          <span style="font-family:Cinzel,serif;font-size:0.82rem;color:var(--gold-dark);text-transform:uppercase;letter-spacing:0.1em;">Elemental Schools</span>
          <span style="font-family:'Crimson Pro',serif;font-style:italic;font-size:0.78rem;color:var(--text-muted);text-transform:none;letter-spacing:normal;">APG — replaces all arcane schools</span>
        </div>
        <span style="font-family:Cinzel,serif;font-size:0.66rem;color:var(--text-muted);flex-shrink:0;">${feats.length} option${feats.length !== 1 ? 's' : ''}</span>
      </div>
      <div id="${bannerId}" style="display:none;padding:0.3rem 0.55rem 0.45rem;background:var(--bg-card);">
        <div style="display:flex;flex-direction:column;gap:0.22rem;">`;

  for (const sf of feats) {
    const sid       = sf.section_id;
    const isChecked = !!selectedSecondaryFeatures[sid];
    const checkId   = 'sf-check-' + sid;
    const rowId     = 'sf-row-' + sid;
    const safeName  = (sf.name || '').replace(/'/g, "\\'");
    const parentSubtype = sf._parentSubtype || sf.subtype;
    const subBody   = renderSubFeatureBody(sf, classColor);

    html += `
      <div id="${rowId}-sub-wrap" data-sf-sub-sid="${sid}" data-sf-parent-sid="__elemental__" data-sf-group="${groupSlug}" style="border:1px solid var(--border);border-left:2px solid ${classColor}55;border-radius:0 4px 4px 0;overflow:hidden;">
        <div style="display:flex;align-items:center;justify-content:space-between;padding:0.38rem 0.7rem;background:var(--bg-card);transition:background 0.15s;"
             onmouseover="this.style.background='var(--bg-hover)'" onmouseout="this.style.background='var(--bg-card)'">
          <div style="display:flex;align-items:center;gap:0.5rem;flex:1;cursor:pointer;"
               onclick="(function(el){var b=document.getElementById('${rowId}-sub');var a=el.querySelector('.sfv-sub-arr');b.style.display=b.style.display==='none'?'block':'none';a.textContent=b.style.display==='none'?'▸':'▾';})(this)">
            <span class="sfv-sub-arr" style="color:${classColor}88;font-size:0.62rem;width:8px;flex-shrink:0;">▸</span>
            <span style="font-family:Cinzel,serif;font-size:0.81rem;color:var(--text-primary);">${sf.name}</span>
          </div>
          <label onclick="event.stopPropagation()" style="display:flex;align-items:center;gap:0.4rem;cursor:pointer;flex-shrink:0;margin-left:0.65rem;">
            <span style="font-family:Cinzel,serif;font-size:0.59rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Select</span>
            <span style="position:relative;width:14px;height:14px;flex-shrink:0;display:inline-block;">
              <input type="checkbox" id="${checkId}" ${isChecked ? 'checked' : ''}
                onchange="toggleSecondaryFeature(${sid},'${safeName}','${parentSubtype}',${pickCount},'${groupSlug}','__elemental__')"
                style="position:absolute;opacity:0;width:100%;height:100%;margin:0;cursor:pointer;z-index:1;">
              <span id="${checkId}-vis" style="position:absolute;inset:0;border:1px solid ${isChecked ? 'var(--gold)' : 'var(--gold-dark)'};border-radius:2px;background:${isChecked ? 'rgba(201,168,76,0.15)' : 'var(--bg-surface)'};display:flex;align-items:center;justify-content:center;pointer-events:none;transition:background 0.15s,border-color 0.15s;">${isChecked ? `<span style="color:var(--gold);font-size:10px;line-height:1;">✓</span>` : ''}</span>
            </span>
          </label>
        </div>
        <div id="${rowId}-sub" style="display:none;padding:0.5rem 0.85rem 0.55rem 1.2rem;background:var(--bg-surface);border-top:1px solid var(--border);">
          ${subBody}
        </div>
      </div>`;
  }

  html += `</div></div></div>`;
  return html;
}

async function prefetchArchetypesForClass(className) {
  const archs=ARCHETYPE_MAP[className.toLowerCase().trim()]||[];
  await Promise.all(archs.map(async arch=>{
    if (!archetypeCache[arch.path]) {
      const parts=arch.path.replace(/\.json$/,'').split('/');
      const archName=parts[parts.length-1].replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase());
      const dbFile=archPathToDbFile(arch.path);
      try { archetypeCache[arch.path]=await loadArchetypeDetail(archName,dbFile)||{name:archName,body:null,sections:[]}; } catch(e){}
    }
    // Populate classSkillMods from freshly loaded cache if missing
    if (selectedArchetypes[arch.path] && !selectedArchetypes[arch.path].classSkillMods && archetypeCache[arch.path]) {
      selectedArchetypes[arch.path].classSkillMods = extractArchetypeClassSkills((archetypeCache[arch.path] || {}).sections);
    }
  }));
  refreshArchetypeConflicts();
}

// ═══════════════════════════════════════════════════════════════════════════
// CACHE CLEAR
// ═══════════════════════════════════════════════════════════════════════════
function clearAllCache() {
  Object.keys(localStorage).forEach(k=>{if(k.startsWith('pfcache_'))localStorage.removeItem(k);});
  showToast('Cache cleared! Reloading…');
  setTimeout(()=>location.reload(),1000);
}

// ═══════════════════════════════════════════════════════════════════════════
// INITIALIZE
// ═══════════════════════════════════════════════════════════════════════════
async function init() {
  const setStatus = msg => {
    const el=document.getElementById('races-content');
    if(el) el.innerHTML=`<div class="loading"><div class="loading-spinner"></div><div style="font-family:Cinzel,serif;color:var(--text-secondary);">${msg}</div></div>`;
  };
  try {
    setStatus('Loading sql.js engine…');
    await loadSqlJs();

    setStatus('Opening index database…');
    indexDb = await openDb(INDEX_DB_FILE);

    setStatus('Querying index…');
    dataCache.races     = loadRaces();
    dataCache.classes   = loadClasses();
    dataCache.feats     = loadFeats();
    dataCache.traits    = loadTraits();
    dataCache.equipment = loadItems();

    ['races','classes','feats','traits','equipment'].forEach(c=>lazyLoadedCategories.add(c));
    buildEquipmentManifestIndex();

    for (const cat of ['races','feats','traits']) {
      filteredData[cat]=dataCache[cat];
      populateFilters(cat,dataCache[cat]);
      // For races, apply the default subtype filter (monster_race unchecked)
      if (cat === 'races') {
        const defaultSubtypes = new Set(['standard_race','core_race','featured_race','uncommon_race']);
        filteredData.races = dataCache.races.filter(r => defaultSubtypes.has(r.subtype));
        renderData('races', filteredData.races);
        const cEl = document.getElementById('filter-count-races');
        if (cEl) cEl.textContent = `${filteredData.races.length} races`;
      } else {
        renderData(cat,dataCache[cat]);
        const cEl=document.getElementById(`filter-count-${cat}`);
        if(cEl) cEl.textContent=`${dataCache[cat].length} ${cat}`;
      }
    }

    // Apply default class filter (Core & Base — exclude prestige) on startup
    filteredData.classes = dataCache.classes.filter(c => !(c._path||'').includes('/class/prestige/'));
    renderData('classes', filteredData.classes);
    const classCEl = document.getElementById('filter-count-classes');
    if (classCEl) classCEl.textContent = `${filteredData.classes.length} classes`;

    renderCharacter();
    // Activate the races page (page-home was the initial placeholder during load)
    switchPage('races');
    updateNavTabGating();          // Gate tabs immediately on load
    updateCurrencyDisplay();       // Show current gold in nav bar
    console.log(`Ready — Races:${dataCache.races.length} Classes:${dataCache.classes.length} Feats:${dataCache.feats.length} Traits:${dataCache.traits.length} Items:${dataCache.equipment.length}`);

    // Background tasks — don't block initial render
    buildWeaponArmorMaps().then(() => {
      console.log(`Weapon map: ${Object.keys(weaponMiscMap).length}, Armor map: ${Object.keys(armorMiscMap).length}, Items: ${Object.keys(itemBodyMap).length}, Prices: ${Object.keys(itemPriceMap).length}`);
      // Re-render current equipment view if user already has it open
      if (currentEquipmentCategory && currentEquipmentSubcategory) {
        equipmentTabCache = {};
        loadEquipmentByCategory();
      }
    });
    buildClassRoleMap().then(() => {
      // Re-render classes with role text now available
      renderData('classes', filteredData.classes);
    });
    buildTraitBodyMap().then(() => {
      // Re-render traits with body text now available
      renderData('traits', filteredData.traits || dataCache.traits);
    });
    buildFeatBodyMap().then(() => {
      // Re-render feats with live benefit text now available
      renderData('feats', filteredData.feats || dataCache.feats);
    });
    buildRaceBodyMap().then(() => {
      // Re-render races with live body text (overrides static fallbacks for CR races)
      renderData('races', filteredData.races || dataCache.races);
    });
    // Merge archetypes from any DB not covered by the hardcoded ARCHETYPE_MAP
    loadArchetypesFromDbs();

  } catch(err) {
    console.error('Init error:',err);
    showError(`Failed to start: ${err.message}<br><br>
      Make sure <strong>index.db</strong> is in the same folder as this HTML file and you are serving it over a local web server (not file://).<br><br>
      Quick start: <code>python3 -m http.server</code>`);
  }
}

async function loadManifest() {} // no-op for compatibility

// ─── Load archetypes from DBs not covered by the hardcoded ARCHETYPE_MAP ─────
// Currently handles book-acg.db (Advanced Class Guide) and any future books.
// Queries sections for class_archetype type, uses parent_name to find the class,
// then merges into ARCHETYPE_MAP so they appear on the class detail page.
async function loadArchetypesFromDbs() {
  // DBs whose archetypes are already fully covered by the hardcoded map
  const SKIP_DBS = new Set([
    'book-apg.db', 'book-uc.db', 'book-um.db',
  ]);

  for (const dbFile of DB_FILES) {
    if (SKIP_DBS.has(dbFile)) continue;
    if (!AVAILABLE_DBS.has(dbFile)) continue;

    const source = dbFile.replace(/^book-/, '').replace(/\.db$/, '');
    // Map short source codes to folder names used in paths
    const sourceFolder = {
      acg: 'advanced_class_guide',
      arg: 'advanced_race_guide',
      gmg: 'game_mastery_guide',
      ucampaign: 'ultimate_campaign',
      ue:  'ultimate_equipment',
      ma:  'mythic_adventures',
    }[source] || source;

    try {
      // Fetch all class_archetype sections with their parent class name
      const rows = await bookQuery(dbFile, `
        SELECT s.section_id, s.name, p.name AS parent_name
        FROM sections s
        JOIN sections p ON s.parent_id = p.section_id
        WHERE s.type = 'class_archetype'
        ORDER BY p.name, s.name
      `, []);

      for (const row of rows) {
        if (!row.name || !row.parent_name) continue;
        const className = row.parent_name.toLowerCase().trim();
        const archSlug  = row.name.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
        const path      = `${sourceFolder}/class_archetype/${className.replace(/\s+/g,'_')}/${archSlug}.json`;

        if (!ARCHETYPE_MAP[className]) ARCHETYPE_MAP[className] = [];

        // Skip duplicates
        if (ARCHETYPE_MAP[className].some(a => a.name === row.name)) continue;

        ARCHETYPE_MAP[className].push({ name: row.name, path, source: sourceFolder });
      }

      if (rows.length) console.log(`Loaded ${rows.length} archetypes from ${dbFile}`);
    } catch(e) {
      console.warn(`loadArchetypesFromDbs: ${dbFile}:`, e.message);
    }
  }
}

// Pre-load Role text for all classes from book DBs — used on class cards
let classRoleMap = {}; // lowercase name → role text

async function buildClassRoleMap() {
  for (const dbFile of DB_FILES) {
    try {
      const rows = await bookQuery(dbFile, `
        SELECT p.name, r.body
        FROM sections p
        JOIN sections r ON r.parent_id = p.section_id AND r.name = 'Role'
        WHERE p.type = 'class'`);
      for (const r of rows) {
        const key = (r.name||'').toLowerCase();
        if (!classRoleMap[key] && r.body) {
          classRoleMap[key] = r.body.replace(/<[^>]+>/g,'').trim();
        }
      }
    } catch(e) {}
  }
}

// Pre-load body text for traits from book DBs — used on trait cards
let traitBodyMap = {}; // lowercase name → benefit/body text
let _cachedSkillBonuses = null; // set by getSkillBonuses(), cleared by recomputeStatBonuses()

async function buildTraitBodyMap() {
  for (const dbFile of DB_FILES) {
    try {
      const rows = await bookQuery(dbFile, `
        SELECT s.name, s.body,
          (SELECT b.body FROM sections b WHERE b.parent_id=s.section_id AND b.name IN ('Benefit','Benefits') LIMIT 1) as benefit
        FROM sections s WHERE s.type='trait'`);
      for (const r of rows) {
        const key = (r.name||'').toLowerCase();
        if (!traitBodyMap[key]) {
          const text = (r.benefit || r.body || '').replace(/<[^>]+>/g,'').trim();
          if (text) traitBodyMap[key] = text;
        }
      }
    } catch(e) {}
  }
}

// Helper: return cleaned body text for a trait from traitBodyMap (used by dynamic stat parser)
function getTraitBodyText(traitKey) {
  return traitBodyMap[traitKey] || null;
}

// ── Generate tag HTML for a trait card on the browse/traits page ──────────────
// Returns an HTML string of colored pill tags summarising what the trait does,
// or '' if no tags can be determined.
// chosenSkill: if provided (character page, choice already made), skip the
//              "Choose Class Skill: …" and "+N to that skill" tags — the chosen
//              skill is already displayed as the teal pill at the bottom of the card.
function generateTraitBrowseTags(name, item, chosenSkill) {
  const nameKey  = (name || '').toLowerCase().trim();
  const rawBody  = traitBodyMap[nameKey] || item.description || item.benefit || '';
  const bodyText = rawBody.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

  const tags = [];

  // Helper: create a styled pill span
  const mkTag = (text, bg, bdr, col) =>
    `<span style="font-size:0.62rem;font-family:Cinzel,serif;padding:0.1rem 0.38rem;` +
    `border-radius:3px;background:${bg};border:1px solid ${bdr};color:${col};white-space:nowrap;">` +
    `${escapeHtml(text)}</span>`;

  // 1. Known stat bonuses from TRAIT_EFFECTS (hardcoded, always reliable)
  const effects = TRAIT_EFFECTS[nameKey];
  if (effects && effects.length) {
    const seen = new Set();
    for (const fx of effects) {
      if (fx.stat === '_info') continue;
      // Strip trailing "(TraitName)" — redundant when the tag is already on that trait's card
      const label = (fx.label || '').replace(/\s*\([^)]+\)\s*$/, '').trim();
      if (!label || seen.has(label)) continue;
      seen.add(label);
      if (fx.conditional) {
        // Conditional bonus — amber tag
        tags.push(mkTag(label, 'rgba(220,170,60,0.1)', 'rgba(220,170,60,0.3)', '#d4a840'));
      } else {
        // Flat unconditional bonus — green tag
        tags.push(mkTag(label, 'rgba(100,200,120,0.12)', 'rgba(100,200,120,0.3)', '#80c890'));
      }
    }
  } else if (bodyText) {
    // Dynamic stat-bonus parsing for traits NOT in TRAIT_EFFECTS
    // Conditional-language detection (mirrors logic in recomputeStatBonuses)
    const _condRxBrowse = [
      /\b(?:as\s+long\s+as|while|when(?:ever)?|only\s+(?:if|when)|against|vs\.?|during|if\s+you)\b/i,
      /\b(?:for\s+\d+\s+(?:round|minute|hour))/i,
      /\b(?:once\s+per\s+day)\b/i,
      /\b(?:within\s+\d+\s+(?:feet|ft))\b/i,
    ];
    const _getSentenceBrowse = (text, idx, len) => {
      const s = text.lastIndexOf('.', idx) + 1;
      const e = text.indexOf('.', idx + len);
      return text.slice(s, e > 0 ? e : undefined).trim();
    };
    const _isCondBrowse = (sent) => _condRxBrowse.some(rx => rx.test(sent));

    const seen = new Set();
    for (const m of bodyText.matchAll(/\+(\d+)\s+(?:\w+\s+)?bonus\s+(?:on|to)\s+(fortitude|reflex|will)\s+(?:saving\s+throws?|saves?)/gi)) {
      const saveWord = m[2][0].toUpperCase() + m[2].slice(1).toLowerCase();
      const sentence = _getSentenceBrowse(bodyText, m.index, m[0].length);
      const label    = `+${parseInt(m[1])} ${saveWord}`;
      if (seen.has(label)) continue; seen.add(label);
      if (_isCondBrowse(sentence)) {
        tags.push(mkTag(`${label} (conditional)`, 'rgba(220,170,60,0.1)', 'rgba(220,170,60,0.3)', '#d4a840'));
      } else {
        tags.push(mkTag(label, 'rgba(100,200,120,0.12)', 'rgba(100,200,120,0.3)', '#80c890'));
      }
    }
    for (const m of bodyText.matchAll(/\+(\d+)\s+(?:\w+\s+)?bonus\s+(?:on|to)\s+initiative\b/gi)) {
      const label    = `+${parseInt(m[1])} Initiative`;
      const sentence = _getSentenceBrowse(bodyText, m.index, m[0].length);
      if (seen.has(label)) continue; seen.add(label);
      if (_isCondBrowse(sentence)) {
        tags.push(mkTag(`${label} (conditional)`, 'rgba(220,170,60,0.1)', 'rgba(220,170,60,0.3)', '#d4a840'));
      } else {
        tags.push(mkTag(label, 'rgba(100,200,120,0.12)', 'rgba(100,200,120,0.3)', '#80c890'));
      }
    }
    for (const m of bodyText.matchAll(/\+(\d+)\s+(?:\w+\s+)?bonus\s+to\s+(?:your\s+)?(?:armor\s+class|AC)\b/gi)) {
      const label    = `+${parseInt(m[1])} AC`;
      const sentence = _getSentenceBrowse(bodyText, m.index, m[0].length);
      if (seen.has(label)) continue; seen.add(label);
      if (_isCondBrowse(sentence)) {
        tags.push(mkTag(`${label} (conditional)`, 'rgba(220,170,60,0.1)', 'rgba(220,170,60,0.3)', '#d4a840'));
      } else {
        tags.push(mkTag(label, 'rgba(100,200,120,0.12)', 'rgba(100,200,120,0.3)', '#80c890'));
      }
    }
    for (const m of bodyText.matchAll(/\+(\d+)\s+(?:\w+\s+)?bonus\s+(?:on|to)\s+concentration\b/gi)) {
      const label = `+${parseInt(m[1])} Concentration`;
      if (!seen.has(label)) { seen.add(label); tags.push(mkTag(label, 'rgba(100,200,120,0.12)', 'rgba(100,200,120,0.3)', '#80c890')); }
    }
  }

  // 1b. Informational (non-stat) tags from TRAIT_INFO_TAGS (purple)
  const infoTags = TRAIT_INFO_TAGS[nameKey];
  if (infoTags && infoTags.length) {
    for (const tagText of infoTags) {
      if (tagText) tags.push(mkTag(tagText, 'rgba(160,120,200,0.1)', 'rgba(160,120,200,0.3)', '#b090d0'));
    }
  }

  // 1c. Ability-score substitution tags (purple info)
  const abilOverride = TRAIT_ABILITY_OVERRIDES[nameKey];
  if (abilOverride) {
    tags.push(mkTag(`★ Uses ${abilOverride.ability.toUpperCase()} for ${abilOverride.skill}`,
      'rgba(160,120,200,0.1)', 'rgba(160,120,200,0.3)', '#b090d0'));
  }

  if (bodyText) {
    // 2. Choice-based skill traits (e.g. Vagabond Child — "select one of the following skills")
    const choiceInfo = parseTraitSkillChoice(bodyText);
    if (choiceInfo && choiceInfo.options && choiceInfo.options.length >= 2) {
      // Only show the "Choose…" / "+N to that skill" prompt tags when no choice has been
      // made yet. Once a skill is chosen, the teal pill at the bottom of the card already
      // shows the selection — repeating the prompt above is redundant.
      if (!chosenSkill) {
        const choiceLabel = choiceInfo.classSkill
          ? `Choose Class Skill: (${choiceInfo.options.join(', ')})`
          : `Choose Skill: (${choiceInfo.options.join(', ')})`;
        tags.push(mkTag(choiceLabel, 'rgba(60,190,180,0.12)', 'rgba(60,190,180,0.35)', '#5adcd0'));
        if (choiceInfo.bonus > 0) {
          tags.push(mkTag(`+${choiceInfo.bonus} to that skill`, 'rgba(100,150,220,0.12)', 'rgba(100,150,220,0.3)', '#8ab0da'));
        }
      }
    } else {
      // 3. Fixed class skill grant (non-choice) — e.g. "X is always a class skill for you"
      if (/is\s+(?:always\s+)?a\s+class\s+skill\s+for\s+you/i.test(bodyText)) {
        const skillNames = PF1E_SKILLS.map(s => s.name);
        const foundSkills = skillNames.filter(sk =>
          new RegExp('\\b' + sk.replace(/[()/]/g, '\\$&') + '\\b', 'i').test(bodyText)
        );
        if (foundSkills.length > 0) {
          for (const sk of foundSkills) {
            tags.push(mkTag(`Class Skill: ${sk}`, 'rgba(60,190,180,0.12)', 'rgba(60,190,180,0.35)', '#5adcd0'));
          }
        } else {
          tags.push(mkTag('Class Skill', 'rgba(60,190,180,0.12)', 'rgba(60,190,180,0.35)', '#5adcd0'));
        }
      }

      // 4. Fixed or conditional skill bonuses (trait or racial bonus to a named skill)
      const skillNames = PF1E_SKILLS.map(s => s.name);
      const skillSeen  = new Set();
      for (const m of bodyText.matchAll(/\+(\d+)\s+(?:racial\s+|trait\s+)?bonus\s+(?:on|to)\s+([^.,;]+)/gi)) {
        const val       = parseInt(m[1]);
        const rawPhrase = m[2] || '';
        for (const sk of skillNames) {
          const skRx    = new RegExp('\\b' + sk.replace(/[()/]/g, '\\$&') + '\\b', 'i');
          const skMatch = skRx.exec(rawPhrase);
          if (skMatch) {
            const key = `${sk}+${val}`;
            if (!skillSeen.has(key)) {
              skillSeen.add(key);
              // Any text remaining after "SkillName [checks]" signals a conditional bonus
              const tail = rawPhrase.slice(skMatch.index + sk.length)
                .replace(/^\s*checks?\b\s*/i, '').trim();
              const isConditional = tail.length > 3;
              if (isConditional) {
                // Amber — matches the character page's conditional pill colour
                tags.push(mkTag(`↑ ${sk} +${val} (conditional)`, 'rgba(220,170,60,0.1)', 'rgba(220,170,60,0.3)', '#d4a840'));
              } else {
                tags.push(mkTag(`↑ ${sk} +${val}`, 'rgba(100,150,220,0.12)', 'rgba(100,150,220,0.3)', '#8ab0da'));
              }
            }
          }
        }
      }
    }
  }

  if (tags.length === 0) return '';
  return `<div style="display:flex;flex-wrap:wrap;gap:0.3rem;padding:0.5rem 1.25rem 0;margin-bottom:0.5rem;">${tags.join('')}</div>`;
}

let featBodyMap = {};    // lowercase name → summary/description text for card
let featBenefitMap = {}; // lowercase name → benefit text for card

async function buildFeatBodyMap() {
  for (const dbFile of DB_FILES) {
    try {
      const rows = await bookQuery(dbFile, `
        SELECT s.name, s.body,
          (SELECT b.body FROM sections b WHERE b.parent_id=s.section_id AND b.name IN ('Benefit','Benefits') LIMIT 1) as benefit
        FROM sections s WHERE s.type='feat'`);
      for (const r of rows) {
        const key = (r.name||'').toLowerCase();
        const body    = (r.body    || '').replace(/<[^>]+>/g,'').trim();
        const benefit = (r.benefit || '').replace(/<[^>]+>/g,'').trim();

        // Summary map: prefer s.body when substantive, else use benefit
        if (!featBodyMap[key]) {
          let text = '';
          if (body.length >= 40) {
            text = body;
          } else if (body.length > 0 && benefit.length > 0) {
            text = body + ' ' + benefit;
          } else {
            text = benefit || body;
          }
          if (text) featBodyMap[key] = text;
        }

        // Benefit map: always the Benefit child section (fall back to body if none)
        if (!featBenefitMap[key]) {
          const text = benefit || body;
          if (text) featBenefitMap[key] = text;
        }
      }
    } catch(e) {}
  }
}

