// ─── Class secondary feature type mapping ─────────────────────────────────────
// Maps class names (lowercase) to their secondary choice (domain, bloodline, etc.)
const CLASS_SECONDARY_TYPES = {
  'cleric':     { label: 'Domains',    subtype: 'cleric_domain',         pick: 2 },
  'inquisitor': { label: 'Domain',     subtype: 'cleric_domain',         pick: 1 },
  'druid':      { label: 'Domain',     subtype: 'cleric_domain',         pick: 1 },
  'sorcerer':   { label: 'Bloodline',  subtype: 'sorcerer_bloodline',    pick: 1 },
  'bloodrager': { label: 'Bloodline',  subtype: 'bloodrager_bloodline',  pick: 1 },
  'wizard':     { label: 'School',     subtype: 'arcane_school',         pick: 1 },
  'oracle':     { label: 'Mystery',    subtype: 'oracle_mystery',        pick: 1 },
  'warpriest':  { label: 'Blessings',  subtype: 'warpriest_blessing',    pick: 2 },
  'witch':      { label: 'Patron',     subtype: 'witch_patron',          pick: 1 },
  'shaman':     { label: 'Spirit',     subtype: 'shaman_spirit',         pick: 1 },
  'cavalier':   { label: 'Order',      subtype: 'warrior_order',         pick: 1 },
  'samurai':    { label: 'Order',      subtype: 'warrior_order',         pick: 1 },
};
// Returns a human-readable error string if selectedSecondaryFeatures doesn't yet
// satisfy the class's required pick count, or null if requirements are met.
function getClassRequirementError(className) {
  const sfConfig = CLASS_SECONDARY_TYPES[(className || '').toLowerCase().trim()];
  if (!sfConfig) return null;
  // Druid's Nature Bond: if companion was chosen, no domain required
  if ((className || '').toLowerCase().trim() === 'druid') {
    const dc = (character.classes || []).find(c => (c.name || c._name || '').toLowerCase().trim() === 'druid');
    if (dc && dc.bondChoice === 'companion') return null;
  }
  const { label, subtype, pick } = sfConfig;
  const have = Object.values(selectedSecondaryFeatures)
    .filter(sf => sf.subtype === subtype && !sf.parentSectionId).length;
  if (have >= pick) return null;
  const need = pick - have;
  return pick === 1
    ? `Requires a ${label} — choose one before adding`
    : `Requires ${need} more ${label}${need > 1 ? 's' : ''} (${have}/${pick} chosen)`;
}

// Refresh the detail-build-btn appearance to reflect whether class requirements are met.
// Only acts while the button is in "Add" mode (not Remove / Update).
function refreshClassAddButtonReqs(className) {
  const btn = document.getElementById('detail-build-btn');
  if (!btn || btn.textContent.startsWith('✕') || btn.textContent.startsWith('✓')) return;
  const err = getClassRequirementError(className);
  if (err) {
    btn.style.background    = 'linear-gradient(135deg, #3a2a10, #4a3520)';
    btn.style.borderColor   = '#aa7722';
    btn.style.color         = '#cc9944';
    btn.style.cursor        = 'not-allowed';
    btn.style.opacity       = '0.75';
    btn.textContent         = `⚠ ${err}`;
  } else {
    btn.style.background    = '';
    btn.style.borderColor   = '';
    btn.style.color         = '';
    btn.style.cursor        = '';
    btn.style.opacity       = '';
    const sfCount   = Object.keys(selectedSecondaryFeatures).length;
    const archCount = Object.keys(selectedArchetypes).length;
    const total = sfCount + archCount;
    btn.textContent = total > 0
      ? `+ Add to Character (${total} selection${total > 1 ? 's' : ''})`
      : '+ Add to Character';
  }
}

const SECONDARY_SUBTYPE_LABELS = {
  'cleric_domain':        'Domain',
  'sorcerer_bloodline':   'Bloodline',
  'bloodrager_bloodline': 'Bloodline',
  'arcane_school':        'School',
  'oracle_mystery':       'Mystery',
  'warpriest_blessing':   'Blessing',
  'shaman_spirit':        'Spirit',
  'witch_patron':         'Patron',
  'warrior_order':        'Order',
};
// All recognized secondary subtypes (for fast detection)
const SECONDARY_SUBTYPES = new Set(Object.values(CLASS_SECONDARY_TYPES).map(c => c.subtype));

