function setBondChoice(clsIdx, val) {
  if (character.classes[clsIdx]) {
    character.classes[clsIdx].bondChoice = val || null;
    renderCharacter();
  }
}

// ── Bond choice modal ─────────────────────────────────────────────────────────
let _bondModalClsIdx = null;

function openBondModal(clsIdx) {
  const cls = character.classes[clsIdx];
  if (!cls) return;
  const clsNm  = (cls.name || cls._name || '').toLowerCase().trim();
  const cfg    = BOND_CHOICE_CLASSES[clsNm];
  if (!cfg) return;
  _bondModalClsIdx = clsIdx;

  document.getElementById('bond-modal-title').textContent    = cfg.feature;
  document.getElementById('bond-modal-subtitle').textContent = 'Choose one option for your ' + (cls.name || cls._name || 'class') + ':';

  const optionsEl = document.getElementById('bond-modal-options');
  optionsEl.innerHTML = '';
  const currentChoice = cls.bondChoice || null;

  cfg.options.forEach(opt => {
    const isCurrent = opt.val === currentChoice;
    const card = document.createElement('div');
    card.style.cssText = `background:var(--bg-deep);border:2px solid ${isCurrent ? 'var(--gold)' : 'var(--border)'};border-radius:8px;padding:0.9rem 1.1rem;cursor:pointer;transition:border-color 0.15s,background 0.15s;`;
    card.innerHTML = `
      <div style="font-family:Cinzel,serif;font-size:0.88rem;color:${isCurrent ? 'var(--gold)' : 'var(--text-primary)'};margin-bottom:0.28rem;display:flex;align-items:center;gap:0.45rem;">
        ${isCurrent ? '<span style="font-size:0.72rem;">✓</span>' : ''}
        ${opt.label}
      </div>
      <div style="font-size:0.77rem;color:var(--text-secondary);line-height:1.5;">${opt.desc}</div>
    `;
    if (!isCurrent) {
      card.addEventListener('mouseenter', () => { card.style.borderColor='var(--border-glow)'; card.style.background='var(--bg-surface)'; });
      card.addEventListener('mouseleave', () => { card.style.borderColor='var(--border)';      card.style.background='var(--bg-deep)';    });
    }
    card.addEventListener('click', () => {
      closeBondModal();
      const prevChoice = character.classes[clsIdx] && character.classes[clsIdx].bondChoice;
      setBondChoice(clsIdx, opt.val);
      // Auto-open companion/familiar/mount picker if this option type hasn't been chosen yet
      if (opt.val === 'companion' && !character.classes[clsIdx].companion) {
        setTimeout(() => openCompanionModal(clsIdx, 'companion'), 80);
      } else if (opt.val === 'mount' && !character.classes[clsIdx].mount) {
        setTimeout(() => openCompanionModal(clsIdx, 'mount'), 80);
      } else if (opt.val === 'familiar' && !character.classes[clsIdx].familiar) {
        setTimeout(() => openCompanionModal(clsIdx, 'familiar'), 80);
      }
    });
    optionsEl.appendChild(card);
  });

  document.getElementById('bond-modal-backdrop').style.display = 'flex';
}

function closeBondModal() {
  document.getElementById('bond-modal-backdrop').style.display = 'none';
}

// Returns weapon bond enhancement bonus and uses/day for Paladin / Antipaladin
function _getWeaponBondStats(clsLevel) {
  const lvl = parseInt(clsLevel) || 1;
  if (lvl < 5) return null;
  // +1 at 5th, +2 at 8th, +3 at 11th, +4 at 14th, +5 at 17th, +6 at 20th
  const bonus = Math.min(6, 1 + Math.floor((lvl - 5) / 3));
  // 1 use at 5th, +1 per 4 levels beyond 5th
  const uses  = Math.min(6, 1 + Math.floor((lvl - 5) / 4));
  return { bonus, uses, duration: `${lvl} min.` };
}

function _buildWeaponBondHtml(clsName, clsLevel, clsColor) {
  const stats = _getWeaponBondStats(clsLevel);
  if (!stats) return `<div style="font-size:0.78rem;color:var(--text-muted);font-style:italic;">Weapon bond becomes available at class level 5.</div>`;
  const lvl = parseInt(clsLevel) || 1;
  const isAnti = (clsName || '').toLowerCase() === 'antipaladin';
  const abilities = isAnti
    ? 'anarchic, flaming, flaming burst, keen, speed, unholy, vicious'
    : 'axiomatic, brilliant energy, defending, disruption, flaming, flaming burst, holy, keen, merciful, speed';
  const rows = [
    ['Enhancement Bonus', `+${stats.bonus}`],
    ['Uses / Day',        `${stats.uses}`],
    ['Duration',          stats.duration],
    ['Properties Available', abilities],
  ];
  if (lvl >= 20) rows.push(['Lv. 20 Special', isAnti ? 'Always active; deals +2d6 dmg vs. good' : 'Always active; deals +2d6 dmg vs. evil']);
  return `<div style="font-size:0.73rem;color:var(--text-muted);font-style:italic;margin-bottom:0.55rem;">Activate as a standard action. Enhancement bonus can be split among properties.</div>`
    + `<table style="border-collapse:collapse;width:100%;font-size:0.75rem;">`
    + rows.map(([l,v]) =>
        `<tr><td style="padding:2px 10px 2px 0;color:var(--text-muted);white-space:nowrap;vertical-align:top;font-size:0.71rem;">${l}</td>`
        + `<td style="padding:2px 0;color:var(--text-primary);font-weight:600;font-size:0.75rem;">${v}</td></tr>`
      ).join('')
    + `</table>`;
}

function _buildHuntingCompanionsHtml(clsLevel, clsColor) {
  return `<div style="font-size:0.73rem;color:var(--text-muted);font-style:italic;margin-bottom:0.45rem;">As a swift action, designate one target. Allies within 30 ft. gain the benefit below vs. that target until the ranger designates a new one.</div>`
    + `<table style="border-collapse:collapse;width:100%;font-size:0.75rem;">`
    + [
        ['Favored Enemy Bonus', `+${Math.floor(((parseInt(clsLevel)||1) + 4) / 5) * 2 || 2} (half your highest bonus)`],
        ['Activation',          'Swift action'],
        ['Range',               '30 ft.'],
      ].map(([l,v]) =>
        `<tr><td style="padding:2px 10px 2px 0;color:var(--text-muted);white-space:nowrap;font-size:0.71rem;">${l}</td>`
        + `<td style="padding:2px 0;color:var(--text-primary);font-weight:600;font-size:0.75rem;">${v}</td></tr>`
      ).join('')
    + `</table>`;
}

function _buildBondedObjectHtml(clsIdx, clsLevel, clsColor) {
  const OBJECT_TYPES = ['Amulet', 'Ring', 'Staff', 'Wand', 'Weapon'];
  const cls = (character.classes || [])[clsIdx] || {};
  const chosen = cls.bondedObjectType || '';
  // Once per day the wizard can cast any spell from their spellbook through the object
  const usesPerDay = 1;
  const rows = [
    ['Object Type',     chosen ? `<span style="color:var(--text-primary);font-weight:600;">${chosen}</span>` : `<span style="color:var(--text-muted);font-style:italic;">Not yet chosen</span>`],
    ['Uses / Day',      `${usesPerDay}`],
    ['Special',         'Cast any memorized spell through the object once per day, even without having prepared it.'],
    ['Loss',            'If the object is lost or destroyed, the wizard must bond a replacement after a week-long ritual.'],
  ];
  const tableHtml = `<table style="border-collapse:collapse;width:100%;font-size:0.75rem;">`
    + rows.map(([l,v]) =>
        `<tr><td style="padding:2px 10px 2px 0;color:var(--text-muted);white-space:nowrap;font-size:0.71rem;vertical-align:top;">${l}</td>`
        + `<td style="padding:2px 0;color:var(--text-secondary);font-size:0.75rem;">${v}</td></tr>`
      ).join('')
    + `</table>`;

  // Object-type picker
  const pickerHtml = `<div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:0.5rem;">
    ${OBJECT_TYPES.map(t => {
      const sel = t === chosen;
      return `<button onclick="event.stopPropagation();_setBondedObjectType(${clsIdx},'${t}')"
        style="font-family:Cinzel,serif;font-size:0.62rem;padding:2px 8px;border-radius:3px;cursor:pointer;
               border:1px solid ${sel ? clsColor : clsColor+'44'};
               background:${sel ? clsColor+'22' : 'transparent'};
               color:${sel ? 'var(--text-primary)' : 'var(--text-muted)'};
               transition:all 0.12s;">${t}</button>`;
    }).join('')}
  </div>`;

  return tableHtml + pickerHtml;
}

function _setBondedObjectType(clsIdx, objType) {
  if (character.classes && character.classes[clsIdx]) {
    character.classes[clsIdx].bondedObjectType = objType;
    renderCharacter();
  }
}

