// ── Global toggle helper for companion/familiar stat block collapsible rows ──
function _compToggleRow(h) {
  const b = h.nextElementSibling;
  const a = h.querySelector('.char-cf-arr');
  const o = b && b.style.display !== 'block';
  if (b) b.style.display = o ? 'block' : 'none';
  if (a) a.style.transform = o ? 'rotate(90deg)' : 'rotate(0deg)';
}

// ── Companion helper functions ──────────────────────────────────────────────
function _compFmtMod(n) { return (n >= 0 ? '+' : '') + Math.floor(n); }

function _getEffCompLevel(cls) {
  const cfg = COMPANION_CLASSES[(cls.name || cls._name || '').toLowerCase().trim()];
  if (!cfg || cfg.type === 'familiar') return parseInt(cls.level) || 1;
  const lvl = parseInt(cls.level) || 1;
  if (cfg.minLevel && lvl < cfg.minLevel) return 0;
  return Math.max(1, lvl + (cfg.levelOffset || 0));
}

function _getCompAbilities(effLvl) {
  const abs = [];
  for (let i = 1; i <= Math.min(effLvl, 20); i++) {
    const s = ANIMAL_COMPANION_PROGRESSION[i-1].special;
    if (s) s.split(', ').forEach(a => { if (a && !abs.includes(a)) abs.push(a); });
  }
  return abs;
}

function _compStatGrid(rows) {
  return `<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:0.45rem 1rem;margin-bottom:0.55rem;">${rows.map(([l,v])=>`<div><div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.07em;color:var(--text-muted);margin-bottom:1px;">${l}</div><div style="font-size:0.77rem;color:var(--text-primary);">${v}</div></div>`).join('')}</div>`;
}

function _compRow(label, value) {
  return `<div style="margin-bottom:0.32rem;font-size:0.77rem;"><span style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.07em;color:var(--text-muted);">${label}</span><br><span style="color:var(--text-primary);">${value}</span></div>`;
}

function _buildCompStatBlock(animalName, effLevel) {
  const animal = ANIMAL_COMPANIONS.find(a => a.name === animalName);
  if (!animal) return '<em style="color:var(--text-muted);">Unknown companion.</em>';
  const eff = Math.max(1, Math.min(20, effLevel));
  const p   = ANIMAL_COMPANION_PROGRESSION[eff - 1];
  const useAdv = animal.adv && eff >= animal.adv.minLevel;
  const size   = (useAdv && animal.adv.size)   || animal.base.size;
  const speed  = (useAdv && animal.adv.speed)  || animal.base.speed;
  const attack = (useAdv && animal.adv.attack) || animal.base.attack;
  const sq     = (useAdv && animal.adv.sq)     || animal.base.sq || '';
  // SA: combine base + adv (animals retain base SA when advancing, and gain new ones)
  const sa     = [animal.base.sa, useAdv ? animal.adv.sa : ''].filter(Boolean).join(', ');
  const note   = animal.base.note || '';
  let str = animal.base.str + (useAdv ? (animal.adv.strD||0) : 0) + p.strDex;
  let dex = animal.base.dex + (useAdv ? (animal.adv.dexD||0) : 0) + p.strDex;
  let con = animal.base.con + (useAdv ? (animal.adv.conD||0) : 0);
  const int_ = animal.base.int, wis = animal.base.wis, cha = animal.base.cha;
  const baseNat  = (useAdv && animal.adv.natArmor !== undefined) ? animal.adv.natArmor : animal.base.natArmor;
  const totalNat = baseNat + p.natArmor;
  const sizeAcM  = {Fine:8,Diminutive:4,Tiny:2,Small:1,Medium:0,Large:-1,Huge:-2,Gargantuan:-4,Colossal:-8};
  const sizeMod  = sizeAcM[size] || 0;
  const strMod = Math.floor((str-10)/2), dexMod = Math.floor((dex-10)/2),
        conMod = Math.floor((con-10)/2), intMod = Math.floor((int_-10)/2),
        wisMod = Math.floor((wis-10)/2), chaMod = Math.floor((cha-10)/2);
  const totalAc = 10 + dexMod + totalNat + sizeMod;
  const estHp   = Math.floor(p.hd * (5.5 + conMod));
  const fort = p.fort + conMod, ref = p.ref + dexMod, will = p.will + wisMod;
  const abilities = _getCompAbilities(eff);
  const fm = _compFmtMod;

  const formLbl = useAdv
    ? `<span style="background:rgba(201,168,76,0.18);border:1px solid var(--gold-dark);border-radius:3px;padding:1px 7px;color:var(--gold-light);font-size:0.68rem;">✦ Advanced Form</span>`
    : `<span style="background:rgba(255,255,255,0.05);border:1px solid var(--border);border-radius:3px;padding:1px 7px;color:var(--text-muted);font-size:0.68rem;">Base Form</span>`;

  function crRow(name, desc) {
    const d = COMPANION_SQ_DESCS[name] || COMPANION_SA_DESCS[name] || COMPANION_ABILITY_DESCS[name] || desc || '';
    return `<div class="char-cf-row" style="border-left:3px solid var(--border);margin-bottom:0.18rem;">` +
      `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)">` +
        `<span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span>` +
        `<span style="font-size:0.78rem;flex:1;">${name}</span>` +
      `</div>` +
      `<div class="char-cf-row-body">${d || '<em style="color:var(--text-muted);">No description available.</em>'}</div>` +
    `</div>`;
  }

  let html = '';

  // ── Header bar ──────────────────────────────────────────────────────────
  html += `<div style="display:flex;align-items:center;flex-wrap:wrap;gap:0.5rem;margin-bottom:0.6rem;padding-bottom:0.5rem;border-bottom:1px solid var(--border);">` +
    formLbl +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">${size}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">⚡ ${speed}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">HD ${p.hd}d8 &bull; BAB ${fm(p.bab)}</span>` +
  `</div>`;

  // ── Ability Scores ───────────────────────────────────────────────────────
  html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;">Ability Scores</div>`;
  html += `<div style="display:grid;grid-template-columns:repeat(6,1fr);gap:0.22rem;margin-bottom:0.55rem;">`;
  for (const [lbl, score, mod] of [['STR',str,strMod],['DEX',dex,dexMod],['CON',con,conMod],['INT',int_,intMod],['WIS',wis,wisMod],['CHA',cha,chaMod]]) {
    html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;text-align:center;padding:0.28rem 0.1rem;">` +
      `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.04em;">${lbl}</div>` +
      `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">${score}</div>` +
      `<div style="font-size:0.68rem;color:var(--gold-light);">${fm(mod)}</div>` +
    `</div>`;
  }
  html += `</div>`;

  // ── Defenses ─────────────────────────────────────────────────────────────
  html += `<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:0.3rem;margin-bottom:0.5rem;">`;
  // AC
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">AC</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${totalAc}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">10+${fm(dexMod)} Dex+${totalNat} Nat${sizeMod!==0?fm(sizeMod)+' Size':''}</div>` +
  `</div>`;
  // Fort
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Fort</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(fort)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.fort} base ${fm(conMod)} Con</div>` +
  `</div>`;
  // Ref
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Ref</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(ref)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.ref} base ${fm(dexMod)} Dex</div>` +
  `</div>`;
  // Will
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Will</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(will)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.will} base ${fm(wisMod)} Wis</div>` +
  `</div>`;
  html += `</div>`;

  // ── HP / Skills row ───────────────────────────────────────────────────────
  html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:0.3rem;margin-bottom:0.45rem;">`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">HP (est.)</div>` +
    `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">${estHp}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.hd}d8 + ${conMod*p.hd} Con</div>` +
  `</div>`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Skills / Tricks / Feats</div>` +
    `<div style="font-size:0.78rem;color:var(--text-primary);">${p.skills} pts &bull; ${p.tricks} tricks &bull; ${p.feats} feats</div>` +
  `</div>`;
  html += `</div>`;

  // ── Attacks ───────────────────────────────────────────────────────────────
  html += `<div style="padding:0.3rem 0.5rem;background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;margin-bottom:0.45rem;">` +
    `<span style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);margin-right:0.4rem;">Attacks</span>` +
    `<span style="font-size:0.77rem;color:var(--text-primary);">${attack}</span>` +
    (note ? `<div style="font-size:0.63rem;color:var(--text-muted);font-style:italic;margin-top:0.12rem;">${note}</div>` : '') +
  `</div>`;

  // ── Special Qualities (collapsible) ───────────────────────────────────────
  if (sq) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.1rem 0 0.3rem;">Special Qualities</div>`;
    sq.split(', ').forEach(q => html += crRow(q.trim()));
  }

  // ── Special Attacks (collapsible) ─────────────────────────────────────────
  if (sa) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;">Special Attacks</div>`;
    sa.split(', ').forEach(a_ => html += crRow(a_.trim()));
  }

  // ── Companion Abilities (collapsible) ─────────────────────────────────────
  if (abilities.length) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;">Companion Abilities</div>`;
    abilities.forEach(ab => html += crRow(ab));
  }

  html += `<div style="font-size:0.63rem;color:var(--text-muted);margin-top:0.4rem;font-style:italic;">Eff. druid level: ${eff}${p.strDex>0?` &bull; Str/Dex bonus: +${p.strDex}`:''}</div>`;
  return html;
}

// ─────────────────────────────────────────────────────────────────────────────
// Interactive companion mini-sheet (DOM-based, replaces _buildCompStatBlock
// in the character page panel). Returns a DOM element with wired stat boxes,
// skills table, and collapsible SQ/SA/Abilities rows.
// ─────────────────────────────────────────────────────────────────────────────
function buildCompanionMiniSheet(cls, clsIdx, animalName, effLevel) {
  if (!cls.companionMisc) cls.companionMisc = {};
  if (!cls.companionSkillRanks) cls.companionSkillRanks = {};
  const cm = cls.companionMisc;
  const sr = cls.companionSkillRanks;

  const animal = ANIMAL_COMPANIONS.find(a => a.name === animalName);
  if (!animal) {
    const err = document.createElement('em');
    err.style.color = 'var(--text-muted)';
    err.textContent = 'Unknown companion.';
    return err;
  }

  const eff  = Math.max(1, Math.min(20, effLevel));
  const p    = ANIMAL_COMPANION_PROGRESSION[eff - 1];
  const useAdv = animal.adv && eff >= animal.adv.minLevel;
  const size   = (useAdv && animal.adv.size)   || animal.base.size;
  const speed  = (useAdv && animal.adv.speed)  || animal.base.speed;
  const attack = (useAdv && animal.adv.attack) || animal.base.attack;
  const sq     = (useAdv && animal.adv.sq)     || animal.base.sq || '';
  // SA: combine base + adv (animals retain base SA when advancing, and gain new ones)
  const sa     = [animal.base.sa, useAdv ? animal.adv.sa : ''].filter(Boolean).join(', ');
  const note   = animal.base.note || '';

  // Base ability scores (creature data + advancement + progression strDex)
  const baseStr = animal.base.str + (useAdv ? (animal.adv.strD||0) : 0) + p.strDex;
  const baseDex = animal.base.dex + (useAdv ? (animal.adv.dexD||0) : 0) + p.strDex;
  const baseCon = animal.base.con + (useAdv ? (animal.adv.conD||0) : 0);
  const baseInt = animal.base.int, baseWis = animal.base.wis, baseCha = animal.base.cha;

  const sizeAcM  = {Fine:8,Diminutive:4,Tiny:2,Small:1,Medium:0,Large:-1,Huge:-2,Gargantuan:-4,Colossal:-8};
  const sizeCmbM = {Fine:-8,Diminutive:-4,Tiny:-2,Small:-1,Medium:0,Large:1,Huge:2,Gargantuan:4,Colossal:8};

  // Reactive score accessors — includes user misc adjustments
  const G = {
    str: () => baseStr + (Number(cm.str_misc)||0),
    dex: () => baseDex + (Number(cm.dex_misc)||0),
    con: () => baseCon + (Number(cm.con_misc)||0),
    int: () => baseInt + (Number(cm.int_misc)||0),
    wis: () => baseWis + (Number(cm.wis_misc)||0),
    cha: () => baseCha + (Number(cm.cha_misc)||0),
  };
  const M = {
    str: () => Math.floor((G.str()-10)/2),
    dex: () => Math.floor((G.dex()-10)/2),
    con: () => Math.floor((G.con()-10)/2),
    int: () => Math.floor((G.int()-10)/2),
    wis: () => Math.floor((G.wis()-10)/2),
    cha: () => Math.floor((G.cha()-10)/2),
  };

  const baseNat  = (useAdv && animal.adv.natArmor !== undefined) ? animal.adv.natArmor : animal.base.natArmor;
  const totalNat = baseNat + p.natArmor;

  function calcAC()   { return 10 + M.dex() + totalNat + (sizeAcM[size]||0)  + (Number(cm.ac_misc)||0); }
  function calcFort() { return p.fort + M.con() + (Number(cm.fort_misc)||0); }
  function calcRef()  { return p.ref  + M.dex() + (Number(cm.ref_misc)||0);  }
  function calcWill() { return p.will + M.wis() + (Number(cm.will_misc)||0); }
  function calcCMB()  { return p.bab + M.str() + (sizeCmbM[size]||0) + (Number(cm.cmb_misc)||0); }
  function calcCMD()  { return 10 + p.bab + M.str() + M.dex() + (sizeCmbM[size]||0) + (Number(cm.cmd_misc)||0); }
  function calcInit() { return M.dex() + (Number(cm.init_misc)||0); }
  // HD average (dice only, no CON) — used as the auto-estimated base
  function calcHPDice() { return Math.floor(p.hd * 5.5); }
  // CON contribution is always applied on top (whether using auto or override)
  function calcHPCon()  { return p.hd * M.con(); }
  function calcHP() {
    const base = (cm.hp_base != null && cm.hp_base !== '') ? Number(cm.hp_base) : calcHPDice();
    return base + calcHPCon() + (Number(cm.hp_misc)||0);
  }
  function fmt(n)     { return (n >= 0 ? '+' : '') + n; }

  const wrap = document.createElement('div');
  const refreshables = [];
  function refresh() { refreshables.forEach(b => b._refresh && b._refresh()); }

  // ── Helper: interactive stat box ─────────────────────────────────────────
  // label       – text label
  // getVal      – function returning the current total (string or number)
  // miscKey     – key in cm for misc bonus (null = no misc input)
  // getBdLines  – function returning [{lbl,val}] breakdown rows
  function makeCompBox(label, getVal, miscKey, getBdLines, topColor) {
    const box = document.createElement('div');
    box.style.cssText = `background:var(--bg-deep);border:1px solid var(--border);border-top:2px solid ${topColor||'var(--border)'};border-radius:6px;overflow:hidden;`;

    const top = document.createElement('div');
    top.style.cssText = 'padding:0.28rem 0.45rem 0.3rem;cursor:pointer;user-select:none;';

    const lblRow = document.createElement('div');
    lblRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;';
    const lblSpan = document.createElement('span');
    lblSpan.style.cssText = 'font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.06em;';
    lblSpan.textContent = label;
    const arrSpan = document.createElement('span');
    arrSpan.style.cssText = 'color:var(--text-muted);font-size:0.52rem;transition:transform 0.15s;';
    arrSpan.textContent = '▼';
    lblRow.appendChild(lblSpan); lblRow.appendChild(arrSpan);

    const valEl = document.createElement('div');
    valEl.style.cssText = 'font-size:1rem;font-weight:700;color:var(--text-primary);margin-top:0.05rem;';
    valEl.textContent = getVal();

    top.appendChild(lblRow); top.appendChild(valEl);
    box.appendChild(top);

    const bd = document.createElement('div');
    bd.style.cssText = 'display:none;padding:0.3rem 0.45rem;border-top:1px solid var(--border);background:var(--bg-card);';
    box.appendChild(bd);

    function renderBd() {
      bd.innerHTML = '';
      if (getBdLines) {
        getBdLines().forEach(({lbl, val}) => {
          const row = document.createElement('div');
          row.style.cssText = 'display:flex;justify-content:space-between;font-family:Cinzel,serif;font-size:0.58rem;padding:0.05rem 0;border-bottom:1px solid rgba(255,255,255,0.04);';
          row.innerHTML = `<span style="color:var(--text-muted);">${lbl}</span><span style="color:var(--text-secondary);">${val}</span>`;
          bd.appendChild(row);
        });
      }
      if (miscKey !== null) {
        const mRow = document.createElement('div');
        mRow.style.cssText = 'display:flex;align-items:center;gap:0.4rem;margin-top:0.28rem;padding-top:0.2rem;border-top:1px solid rgba(255,255,255,0.06);';
        const mLbl = document.createElement('span');
        mLbl.style.cssText = 'font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;flex:1;';
        mLbl.textContent = 'Misc';
        const mInp = document.createElement('input');
        mInp.type = 'number';
        mInp.value = Number(cm[miscKey]) || 0;
        mInp.style.cssText = 'width:3rem;background:var(--bg-surface);border:1px solid var(--border-glow);border-radius:3px;outline:none;font-family:"Cinzel Decorative",Cinzel,serif;font-size:0.82rem;color:var(--text-secondary);text-align:center;padding:0.1rem 0;';
        mInp.addEventListener('focus', () => mInp.style.borderColor = 'var(--gold)');
        mInp.addEventListener('blur',  () => mInp.style.borderColor = 'var(--border-glow)');
        mInp.addEventListener('input', () => {
          cm[miscKey] = parseInt(mInp.value) || 0;
          valEl.textContent = getVal();
          refresh(); // update all derived
        });
        mRow.appendChild(mLbl); mRow.appendChild(mInp);
        bd.appendChild(mRow);
      }
    }
    renderBd();

    let open = false;
    top.addEventListener('click', () => {
      open = !open;
      bd.style.display = open ? 'block' : 'none';
      arrSpan.style.transform = open ? 'rotate(180deg)' : '';
      if (open) renderBd();
    });
    box._refresh = () => { valEl.textContent = getVal(); if (open) renderBd(); };
    return box;
  }

  // ── Header bar ────────────────────────────────────────────────────────────
  const formLbl = useAdv
    ? `<span style="background:rgba(201,168,76,0.18);border:1px solid var(--gold-dark);border-radius:3px;padding:1px 7px;color:var(--gold-light);font-size:0.68rem;">✦ Advanced Form</span>`
    : `<span style="background:rgba(255,255,255,0.05);border:1px solid var(--border);border-radius:3px;padding:1px 7px;color:var(--text-muted);font-size:0.68rem;">Base Form</span>`;
  const hdr = document.createElement('div');
  hdr.style.cssText = 'display:flex;align-items:center;flex-wrap:wrap;gap:0.5rem;margin-bottom:0.65rem;padding-bottom:0.5rem;border-bottom:1px solid var(--border);';
  hdr.innerHTML = `${formLbl}<span style="font-size:0.72rem;color:var(--text-secondary);">${size}</span><span style="color:var(--border);">|</span><span style="font-size:0.72rem;color:var(--text-secondary);">⚡ ${speed}</span><span style="color:var(--border);">|</span><span style="font-size:0.72rem;color:var(--text-secondary);">HD ${p.hd}d8 &bull; BAB ${fmt(p.bab)}</span>`;
  wrap.appendChild(hdr);

  // ── Ability Scores ────────────────────────────────────────────────────────
  const abSecLbl = document.createElement('div');
  abSecLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;';
  abSecLbl.textContent = 'Ability Scores';
  wrap.appendChild(abSecLbl);

  const abGrid = document.createElement('div');
  abGrid.style.cssText = 'display:grid;grid-template-columns:repeat(6,1fr);gap:0.22rem;margin-bottom:0.55rem;';

  const ABIL_LIST = [['STR','str',baseStr],['DEX','dex',baseDex],['CON','con',baseCon],['INT','int',baseInt],['WIS','wis',baseWis],['CHA','cha',baseCha]];
  ABIL_LIST.forEach(([lbl,key,base]) => {
    const box = document.createElement('div');
    box.style.cssText = 'background:var(--bg-deep);border:1px solid var(--border);border-top:2px solid var(--gold-dark);border-radius:4px;text-align:center;overflow:hidden;cursor:pointer;';
    const lblD  = document.createElement('div');
    lblD.style.cssText = 'font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.04em;padding-top:0.2rem;';
    lblD.textContent = lbl;
    const scoreEl = document.createElement('div');
    scoreEl.style.cssText = 'font-size:0.88rem;font-weight:600;color:var(--text-primary);';
    scoreEl.textContent = G[key]();
    const modEl = document.createElement('div');
    modEl.style.cssText = 'font-size:0.68rem;color:var(--gold-light);';
    modEl.textContent = fmt(M[key]());
    const bd = document.createElement('div');
    bd.style.cssText = 'display:none;padding:0.18rem 0.28rem;border-top:1px solid var(--border);background:var(--bg-card);text-align:left;';

    function renderAbBd() {
      bd.innerHTML = '';
      const baseRow = document.createElement('div');
      baseRow.style.cssText = 'font-family:Cinzel,serif;font-size:0.56rem;color:var(--text-muted);display:flex;justify-content:space-between;padding:0.04rem 0;border-bottom:1px solid rgba(255,255,255,0.04);';
      baseRow.innerHTML = `<span>Base (${animal.name})</span><span style="color:var(--text-secondary);">${base}</span>`;
      bd.appendChild(baseRow);
      const mRow = document.createElement('div');
      mRow.style.cssText = 'display:flex;align-items:center;gap:0.3rem;margin-top:0.22rem;';
      const mLbl = document.createElement('span');
      mLbl.style.cssText = 'font-family:Cinzel,serif;font-size:0.56rem;color:var(--text-muted);text-transform:uppercase;flex:1;';
      mLbl.textContent = 'Misc';
      const mInp = document.createElement('input');
      mInp.type = 'number'; mInp.value = Number(cm[key+'_misc'])||0;
      mInp.style.cssText = 'width:2.8rem;background:var(--bg-surface);border:1px solid var(--border-glow);border-radius:3px;outline:none;font-family:"Cinzel Decorative",Cinzel,serif;font-size:0.78rem;color:var(--text-secondary);text-align:center;padding:0.06rem 0;';
      mInp.addEventListener('focus', () => mInp.style.borderColor='var(--gold)');
      mInp.addEventListener('blur',  () => mInp.style.borderColor='var(--border-glow)');
      mInp.addEventListener('input', () => {
        cm[key+'_misc'] = parseInt(mInp.value)||0;
        scoreEl.textContent = G[key]();
        modEl.textContent   = fmt(M[key]());
        refresh();
      });
      mRow.appendChild(mLbl); mRow.appendChild(mInp);
      bd.appendChild(mRow);
    }
    renderAbBd();

    let abOpen = false;
    box.addEventListener('click', () => {
      abOpen = !abOpen;
      bd.style.display = abOpen ? 'block' : 'none';
      if (abOpen) renderAbBd();
    });
    box.appendChild(lblD); box.appendChild(scoreEl); box.appendChild(modEl); box.appendChild(bd);
    abGrid.appendChild(box);

    refreshables.push({ _refresh: () => {
      scoreEl.textContent = G[key]();
      modEl.textContent   = fmt(M[key]());
      if (abOpen) renderAbBd();
    }});
  });
  wrap.appendChild(abGrid);

  // ── Combat: BAB / Init / CMB / CMD ────────────────────────────────────────
  const combatSecLbl = document.createElement('div');
  combatSecLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;';
  combatSecLbl.textContent = 'Combat';
  wrap.appendChild(combatSecLbl);

  const combatRow = document.createElement('div');
  combatRow.style.cssText = 'display:grid;grid-template-columns:repeat(4,1fr);gap:0.25rem;margin-bottom:0.45rem;';

  // BAB — read-only from progression
  {
    const b = document.createElement('div');
    b.style.cssText = 'background:var(--bg-deep);border:1px solid var(--border);border-top:2px solid #c87a3a;border-radius:6px;padding:0.28rem 0.45rem;';
    b.innerHTML = `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">BAB</div><div style="font-size:1rem;font-weight:700;color:#e8a84c;">${fmt(p.bab)}</div><div style="font-size:0.56rem;color:var(--text-muted);">progression</div>`;
    combatRow.appendChild(b);
  }
  // Init
  { const b = makeCompBox('Init', () => fmt(calcInit()), 'init_misc',
      () => [{lbl:'DEX mod', val:fmt(M.dex())}], '#4a6a9a');
    refreshables.push(b); combatRow.appendChild(b); }
  // CMB
  { const b = makeCompBox('CMB', () => fmt(calcCMB()), 'cmb_misc',
      () => [{lbl:'BAB',val:fmt(p.bab)},{lbl:'STR mod',val:fmt(M.str())},
             ...((sizeCmbM[size]||0)!==0?[{lbl:`Size (${size})`,val:fmt(sizeCmbM[size]||0)}]:[])],
      '#c87a3a');
    refreshables.push(b); combatRow.appendChild(b); }
  // CMD
  { const b = makeCompBox('CMD', () => calcCMD(), 'cmd_misc',
      () => [{lbl:'Base',val:'10'},{lbl:'BAB',val:fmt(p.bab)},{lbl:'STR mod',val:fmt(M.str())},{lbl:'DEX mod',val:fmt(M.dex())},
             ...((sizeCmbM[size]||0)!==0?[{lbl:`Size (${size})`,val:fmt(sizeCmbM[size]||0)}]:[])],
      '#c87a3a');
    refreshables.push(b); combatRow.appendChild(b); }
  wrap.appendChild(combatRow);

  // ── Defenses: AC / Fort / Ref / Will ─────────────────────────────────────
  const defSecLbl = document.createElement('div');
  defSecLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;';
  defSecLbl.textContent = 'Defenses';
  wrap.appendChild(defSecLbl);

  const defRow = document.createElement('div');
  defRow.style.cssText = 'display:grid;grid-template-columns:repeat(4,1fr);gap:0.25rem;margin-bottom:0.45rem;';

  { const b = makeCompBox('AC', () => calcAC(), 'ac_misc',
      () => [{lbl:'Base',val:'10'},{lbl:'DEX mod',val:fmt(M.dex())},{lbl:'Natural',val:'+'+totalNat},
             ...((sizeAcM[size]||0)!==0?[{lbl:`Size (${size})`,val:fmt(sizeAcM[size]||0)}]:[])], '#4a8a5a');
    refreshables.push(b); defRow.appendChild(b); }
  { const b = makeCompBox('Fortitude', () => fmt(calcFort()), 'fort_misc',
      () => [{lbl:'Base save',val:fmt(p.fort)},{lbl:'CON mod',val:fmt(M.con())}], '#4a6a9a');
    refreshables.push(b); defRow.appendChild(b); }
  { const b = makeCompBox('Reflex', () => fmt(calcRef()), 'ref_misc',
      () => [{lbl:'Base save',val:fmt(p.ref)},{lbl:'DEX mod',val:fmt(M.dex())}], '#4a6a9a');
    refreshables.push(b); defRow.appendChild(b); }
  { const b = makeCompBox('Will', () => fmt(calcWill()), 'will_misc',
      () => [{lbl:'Base save',val:fmt(p.will)},{lbl:'WIS mod',val:fmt(M.wis())}], '#4a6a9a');
    refreshables.push(b); defRow.appendChild(b); }
  wrap.appendChild(defRow);

  // ── HP / Speed ────────────────────────────────────────────────────────────
  const hpRow = document.createElement('div');
  hpRow.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:0.25rem;margin-bottom:0.5rem;';

  {
    // HP box — manual build so we can include a "Base HP Override" input alongside the misc bonus
    const hpBox = document.createElement('div');
    hpBox.style.cssText = 'background:var(--bg-deep);border:1px solid var(--border);border-top:2px solid var(--red-accent);border-radius:6px;overflow:hidden;';

    const hpTop = document.createElement('div');
    hpTop.style.cssText = 'padding:0.28rem 0.45rem 0.3rem;cursor:pointer;user-select:none;';

    const hpLblRow = document.createElement('div');
    hpLblRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;';
    const hpLblSpan = document.createElement('span');
    hpLblSpan.style.cssText = 'font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.06em;';
    const hpArrSpan = document.createElement('span');
    hpArrSpan.style.cssText = 'color:var(--text-muted);font-size:0.52rem;transition:transform 0.15s;';
    hpArrSpan.textContent = '▼';
    hpLblRow.appendChild(hpLblSpan); hpLblRow.appendChild(hpArrSpan);

    const hpValEl = document.createElement('div');
    hpValEl.style.cssText = 'font-size:1rem;font-weight:700;color:var(--text-primary);margin-top:0.05rem;';

    function updateHpLabel() {
      hpLblSpan.textContent = (cm.hp_base != null && cm.hp_base !== '') ? 'HP' : 'HP (est.)';
    }
    function updateHpVal() { hpValEl.textContent = calcHP(); }
    updateHpLabel(); updateHpVal();

    hpTop.appendChild(hpLblRow); hpTop.appendChild(hpValEl);
    hpBox.appendChild(hpTop);

    const hpBd = document.createElement('div');
    hpBd.style.cssText = 'display:none;padding:0.3rem 0.45rem;border-top:1px solid var(--border);background:var(--bg-card);';
    hpBox.appendChild(hpBd);

    const _inpStyle = 'width:3rem;background:var(--bg-surface);border:1px solid var(--border-glow);border-radius:3px;outline:none;font-family:"Cinzel Decorative",Cinzel,serif;font-size:0.82rem;color:var(--text-secondary);text-align:center;padding:0.1rem 0;';
    const _rowStyle = 'display:flex;align-items:center;gap:0.4rem;margin-top:0.28rem;padding-top:0.2rem;border-top:1px solid rgba(255,255,255,0.06);';
    const _lblStyle = 'font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;flex:1;';

    function renderHpBd() {
      hpBd.innerHTML = '';
      // Info rows
      const diceVal = calcHPDice();
      const conVal  = calcHPCon();
      [{lbl:'HD', val:p.hd+'d8'}, {lbl:'CON/HD', val:fmt(M.con())+'×'+p.hd}, {lbl:'Estimated', val:diceVal}, {lbl:'CON Total', val:fmt(conVal)}].forEach(({lbl,val}) => {
        const r = document.createElement('div');
        r.style.cssText = 'display:flex;justify-content:space-between;font-family:Cinzel,serif;font-size:0.58rem;padding:0.05rem 0;border-bottom:1px solid rgba(255,255,255,0.04);';
        r.innerHTML = `<span style="color:var(--text-muted);">${lbl}</span><span style="color:var(--text-secondary);">${val}</span>`;
        hpBd.appendChild(r);
      });
      // Base HP override
      const baseRow = document.createElement('div');
      baseRow.style.cssText = _rowStyle;
      const baseLbl = document.createElement('span');
      baseLbl.style.cssText = _lblStyle;
      baseLbl.textContent = 'Base Override';
      const baseInp = document.createElement('input');
      baseInp.type = 'number'; baseInp.placeholder = diceVal;
      baseInp.value = (cm.hp_base != null && cm.hp_base !== '') ? cm.hp_base : '';
      baseInp.style.cssText = _inpStyle;
      baseInp.addEventListener('focus', () => baseInp.style.borderColor='var(--gold)');
      baseInp.addEventListener('blur',  () => baseInp.style.borderColor='var(--border-glow)');
      baseInp.addEventListener('input', () => {
        const v = baseInp.value.trim();
        cm.hp_base = (v === '') ? null : (parseInt(v) || 0);
        updateHpLabel(); updateHpVal(); refresh();
      });
      baseRow.appendChild(baseLbl); baseRow.appendChild(baseInp);
      hpBd.appendChild(baseRow);
      // Misc bonus
      const miscRow = document.createElement('div');
      miscRow.style.cssText = 'display:flex;align-items:center;gap:0.4rem;margin-top:0.1rem;';
      const miscLbl = document.createElement('span');
      miscLbl.style.cssText = _lblStyle;
      miscLbl.textContent = 'Misc Bonus';
      const miscInp = document.createElement('input');
      miscInp.type = 'number'; miscInp.value = Number(cm.hp_misc)||0;
      miscInp.style.cssText = _inpStyle;
      miscInp.addEventListener('focus', () => miscInp.style.borderColor='var(--gold)');
      miscInp.addEventListener('blur',  () => miscInp.style.borderColor='var(--border-glow)');
      miscInp.addEventListener('input', () => {
        cm.hp_misc = parseInt(miscInp.value)||0;
        updateHpVal(); refresh();
      });
      miscRow.appendChild(miscLbl); miscRow.appendChild(miscInp);
      hpBd.appendChild(miscRow);
    }
    renderHpBd();

    let hpOpen = false;
    hpTop.addEventListener('click', () => {
      hpOpen = !hpOpen;
      hpBd.style.display = hpOpen ? 'block' : 'none';
      hpArrSpan.style.transform = hpOpen ? 'rotate(180deg)' : '';
      if (hpOpen) renderHpBd();
    });
    hpBox._refresh = () => { updateHpLabel(); updateHpVal(); if (hpOpen) renderHpBd(); };
    refreshables.push(hpBox);
    hpRow.appendChild(hpBox);
  }
  {
    const speedBox = document.createElement('div');
    speedBox.style.cssText = 'background:var(--bg-deep);border:1px solid var(--border);border-top:2px solid #7a5a9a;border-radius:6px;padding:0.28rem 0.45rem;';
    speedBox.innerHTML = `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Speed</div><div style="font-size:0.88rem;font-weight:700;color:var(--text-primary);">${speed}</div>`;
    hpRow.appendChild(speedBox);
  }
  wrap.appendChild(hpRow);

  // ── Attacks ───────────────────────────────────────────────────────────────
  const atkDiv = document.createElement('div');
  atkDiv.style.cssText = 'padding:0.3rem 0.5rem;background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;margin-bottom:0.5rem;';
  atkDiv.innerHTML = `<span style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);margin-right:0.4rem;">Attacks</span><span style="font-size:0.77rem;color:var(--text-primary);">${attack}</span>${note?`<div style="font-size:0.63rem;color:var(--text-muted);font-style:italic;margin-top:0.1rem;">${note}</div>`:''}`;
  wrap.appendChild(atkDiv);

  // ── Skills ────────────────────────────────────────────────────────────────
  {
    const skillsAvail = p.skills;
    const maxRank = p.hd;
    const COMP_SKILLS = [
      {name:'Acrobatics',    ab:'dex'}, {name:'Climb',         ab:'str'},
      {name:'Escape Artist', ab:'dex'}, {name:'Fly',           ab:'dex'},
      {name:'Intimidate',    ab:'cha'}, {name:'Perception',    ab:'wis'},
      {name:'Stealth',       ab:'dex'}, {name:'Survival',      ab:'wis'},
      {name:'Swim',          ab:'str'},
    ];

    const getUsed = () => Object.values(sr).reduce((s,v) => s + Math.max(0,parseInt(v)||0), 0);

    const skillWrap = document.createElement('div');
    skillWrap.style.cssText = 'margin-bottom:0.5rem;border:1px solid var(--border);border-radius:6px;overflow:hidden;';

    let skillOpen = window['_compSkillOpen_'+clsIdx] !== false;

    const skillHdr = document.createElement('div');
    skillHdr.style.cssText = 'display:flex;align-items:center;gap:0.5rem;padding:0.32rem 0.55rem;background:var(--bg-deep);cursor:pointer;user-select:none;';
    const skTitleEl = document.createElement('span');
    skTitleEl.style.cssText = 'font-family:Cinzel,serif;font-size:0.6rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);flex:1;';
    skTitleEl.textContent = 'Skills';
    const skTrackerEl = document.createElement('span');
    skTrackerEl.style.cssText = 'font-family:Cinzel,serif;font-size:0.62rem;background:rgba(0,0,0,0.2);border:1px solid rgba(201,168,76,0.2);border-radius:3px;padding:0.08rem 0.4rem;';
    function updateSkTracker() {
      const used = getUsed();
      const rc = used > skillsAvail ? '#e05555' : (used===skillsAvail&&skillsAvail>0)?'var(--gold)':'var(--text-muted)';
      skTrackerEl.textContent = `${used}/${skillsAvail} pts`;
      skTrackerEl.style.color = rc;
    }
    updateSkTracker();
    const skArr = document.createElement('span');
    skArr.style.cssText = 'color:var(--gold);font-size:0.75rem;transition:transform 0.15s;';
    skArr.textContent = '▸';
    skArr.style.transform = skillOpen ? 'rotate(90deg)' : '';
    skillHdr.appendChild(skTitleEl); skillHdr.appendChild(skTrackerEl); skillHdr.appendChild(skArr);

    const skillBody = document.createElement('div');
    skillBody.style.display = skillOpen ? 'block' : 'none';
    skillBody.style.cssText += 'overflow:hidden;';

    skillHdr.addEventListener('click', () => {
      skillOpen = !skillOpen;
      skillBody.style.display = skillOpen ? 'block' : 'none';
      skArr.style.transform = skillOpen ? 'rotate(90deg)' : '';
      window['_compSkillOpen_'+clsIdx] = skillOpen;
    });

    // Skills table
    const tbl = document.createElement('table');
    tbl.style.cssText = 'width:100%;border-collapse:collapse;font-size:0.8rem;background:var(--bg-card);';
    tbl.innerHTML = `<thead><tr style="border-bottom:1px solid var(--border);">
      <th style="text-align:left;padding:0.2rem 0.5rem;font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Skill</th>
      <th style="text-align:center;padding:0.2rem;font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Rnks</th>
      <th style="text-align:center;padding:0.2rem;font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Abil</th>
      <th style="text-align:center;padding:0.2rem;font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">CS</th>
      <th style="text-align:center;padding:0.2rem 0.5rem 0.2rem 0.2rem;font-family:Cinzel,serif;font-size:0.58rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;">Total</th>
    </tr></thead>`;
    const tbody = document.createElement('tbody');

    COMP_SKILLS.forEach((sk, idx) => {
      const ranks   = Math.max(0, parseInt(sr[sk.name])||0);
      const abilMd  = M[sk.ab]();
      const csB     = ranks > 0 ? 3 : 0;
      const total   = ranks + abilMd + csB;
      const rowBg   = idx % 2 === 0 ? 'transparent' : 'rgba(255,255,255,0.025)';
      const tr      = document.createElement('tr');
      tr.style.background = rowBg;

      const nameTd = document.createElement('td');
      nameTd.style.cssText = 'padding:0.16rem 0.5rem;font-size:0.76rem;color:var(--text-primary);white-space:nowrap;';
      nameTd.innerHTML = `${sk.name} <span style="font-size:0.58rem;color:var(--text-muted);">(${sk.ab.toUpperCase()})</span>`;

      const rankTd = document.createElement('td');
      rankTd.style.cssText = 'text-align:center;padding:0.08rem 0.2rem;';
      const rankInp = document.createElement('input');
      rankInp.type = 'number'; rankInp.value = ranks; rankInp.min = 0; rankInp.max = maxRank;
      rankInp.style.cssText = 'width:2.2rem;text-align:center;background:var(--bg-surface);border:1px solid var(--border);border-radius:3px;outline:none;font-family:Cinzel,serif;font-size:0.72rem;color:var(--text-secondary);padding:0.05rem 0;';
      rankInp.addEventListener('focus', () => rankInp.style.borderColor = 'var(--gold)');
      rankInp.addEventListener('blur',  () => rankInp.style.borderColor = 'var(--border)');

      const abilTd = document.createElement('td');
      abilTd.style.cssText = 'text-align:center;padding:0.16rem 0.2rem;font-family:Cinzel,serif;font-size:0.7rem;color:var(--text-muted);';
      abilTd.textContent = fmt(abilMd);

      const csTd = document.createElement('td');
      csTd.style.cssText = 'text-align:center;padding:0.16rem 0.2rem;font-family:Cinzel,serif;font-size:0.7rem;color:var(--gold-light);';
      csTd.textContent = csB ? '+3' : '—';

      const totalTd = document.createElement('td');
      totalTd.style.cssText = 'text-align:center;padding:0.16rem 0.5rem 0.16rem 0.2rem;font-family:"Cinzel Decorative",Cinzel,serif;font-size:0.78rem;font-weight:700;';
      function refreshTotal() {
        const rr = parseInt(rankInp.value)||0;
        const am = M[sk.ab]();
        const cs = rr > 0 ? 3 : 0;
        const tot = rr + am + cs;
        totalTd.textContent = tot >= 0 ? '+'+tot : ''+tot;
        totalTd.style.color = tot > 0 ? 'var(--gold-light)' : 'var(--text-muted)';
        abilTd.textContent = fmt(am);
        csTd.textContent = cs ? '+3' : '—';
      }
      refreshTotal();

      rankInp.addEventListener('change', () => {
        let v = Math.max(0, Math.min(maxRank, parseInt(rankInp.value)||0));
        rankInp.value = v;
        sr[sk.name] = v;
        refreshTotal();
        updateSkTracker();
      });

      rankTd.appendChild(rankInp);
      tr.appendChild(nameTd); tr.appendChild(rankTd); tr.appendChild(abilTd);
      tr.appendChild(csTd); tr.appendChild(totalTd);
      tbody.appendChild(tr);

      // Register for ability-score refreshes
      refreshables.push({ _refresh: () => refreshTotal() });
    });

    tbl.appendChild(tbody);
    skillBody.appendChild(tbl);
    skillWrap.appendChild(skillHdr);
    skillWrap.appendChild(skillBody);
    wrap.appendChild(skillWrap);
  }

  // ── SQ / SA / Companion Abilities (collapsible rows) ──────────────────────
  function crRow(name) {
    const d = COMPANION_SQ_DESCS[name] || COMPANION_SA_DESCS[name] || COMPANION_ABILITY_DESCS[name] || '';
    const div = document.createElement('div');
    div.className = 'char-cf-row';
    div.style.cssText = 'border-left:3px solid var(--border);margin-bottom:0.18rem;';
    div.innerHTML =
      `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)">` +
        `<span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span>` +
        `<span style="font-size:0.78rem;flex:1;">${name}</span>` +
      `</div>` +
      `<div class="char-cf-row-body">${d || '<em style="color:var(--text-muted);">No description available.</em>'}</div>`;
    return div;
  }
  if (sq) {
    const sqLbl = document.createElement('div');
    sqLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.1rem 0 0.3rem;';
    sqLbl.textContent = 'Special Qualities';
    wrap.appendChild(sqLbl);
    sq.split(', ').forEach(q => wrap.appendChild(crRow(q.trim())));
  }
  if (sa) {
    const saLbl = document.createElement('div');
    saLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;';
    saLbl.textContent = 'Special Attacks';
    wrap.appendChild(saLbl);
    sa.split(', ').forEach(a_ => wrap.appendChild(crRow(a_.trim())));
  }
  const abilities = _getCompAbilities(eff);
  if (abilities.length) {
    const abLbl = document.createElement('div');
    abLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;';
    abLbl.textContent = 'Companion Abilities';
    wrap.appendChild(abLbl);
    abilities.forEach(ab => wrap.appendChild(crRow(ab)));
  }

  // ── Chosen Tricks / Feats ─────────────────────────────────────────────────
  const ch = cls.companionChoices || {};
  if ((ch.tricks && ch.tricks.length) || (ch.feats && ch.feats.length)) {
    const tfDiv = document.createElement('div');
    tfDiv.style.cssText = 'margin-top:0.6rem;border-top:1px solid rgba(255,255,255,0.07);padding-top:0.5rem;';
    if (ch.tricks && ch.tricks.length) {
      const tLbl = document.createElement('div');
      tLbl.style.cssText = 'font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;';
      tLbl.textContent = 'Trained Tricks';
      tfDiv.appendChild(tLbl);
      ch.tricks.forEach(t => {
        const desc = COMPANION_TRICK_DESCS[t] || '';
        const row = document.createElement('div');
        row.className = 'char-cf-row';
        row.style.cssText = 'border-left:3px solid var(--gold-dark);margin-bottom:0.18rem;';
        row.innerHTML = `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)"><span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span><span style="font-size:0.78rem;flex:1;color:var(--gold-light);">${t}</span></div><div class="char-cf-row-body">${desc||'<em style="color:var(--text-muted);">No description available.</em>'}</div>`;
        tfDiv.appendChild(row);
      });
    }
    if (ch.feats && ch.feats.length) {
      const fLbl = document.createElement('div');
      fLbl.style.cssText = `font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:${ch.tricks&&ch.tricks.length?'0.55rem':'0'} 0 0.3rem;`;
      fLbl.textContent = 'Bonus Feats';
      tfDiv.appendChild(fLbl);
      ch.feats.forEach(f => {
        const desc = COMPANION_FEAT_DESCS[f] || '';
        const row = document.createElement('div');
        row.className = 'char-cf-row';
        row.style.cssText = 'border-left:3px solid var(--gold-dark);margin-bottom:0.18rem;';
        row.innerHTML = `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)"><span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span><span style="font-size:0.78rem;flex:1;color:var(--gold-light);">${f}</span></div><div class="char-cf-row-body">${desc||'<em style="color:var(--text-muted);">No description available.</em>'}</div>`;
        tfDiv.appendChild(row);
      });
    }
    wrap.appendChild(tfDiv);
  }

  // Footer
  const footer = document.createElement('div');
  footer.style.cssText = 'font-size:0.63rem;color:var(--text-muted);margin-top:0.45rem;font-style:italic;';
  footer.textContent = `Eff. druid level: ${eff}${p.strDex > 0 ? ` · Str/Dex bonus: +${p.strDex}` : ''}`;
  wrap.appendChild(footer);

  return wrap;
}

function _buildFamStatBlock(famName, masterLvl) {
  const f = FAMILIAR_LIST.find(x => x.name === famName);
  if (!f) return '<em style="color:var(--text-muted);">Unknown familiar.</em>';
  const lvl = Math.max(1, Math.min(20, masterLvl));
  const p   = FAMILIAR_PROGRESSION[lvl - 1];
  const fm  = _compFmtMod;

  // Parse ability scores from f.ability string like "Str 2, Dex 15, Con 6, Wis 14, Cha 4"
  const abMap = {};
  (f.ability || '').split(',').forEach(chunk => {
    const m = chunk.trim().match(/^(\w+)\s+(\d+)$/);
    if (m) abMap[m[1]] = parseInt(m[2]);
  });
  const str  = abMap.Str || 10, dex  = abMap.Dex || 10, con  = abMap.Con || 10;
  const int_ = abMap.Int || p.int, wis = abMap.Wis || 10, cha = abMap.Cha || 10;
  const finalInt = p.int; // Use progression Int (overrides base)
  const strMod = Math.floor((str-10)/2),  dexMod = Math.floor((dex-10)/2),
        conMod = Math.floor((con-10)/2),  intMod = Math.floor((finalInt-10)/2),
        wisMod = Math.floor((wis-10)/2),  chaMod = Math.floor((cha-10)/2);

  const famAbilities = ['Alertness', 'Improved Evasion', 'Share Spells', 'Empathic Link'];
  if (lvl >= 3)  famAbilities.push('Deliver Touch Spells');
  if (lvl >= 5)  famAbilities.push('Speak with Master');
  if (lvl >= 7)  famAbilities.push('Speak with Animals of Its Kind');
  if (lvl >= 11) famAbilities.push(`Spell Resistance (${lvl+5})`);
  if (lvl >= 13) famAbilities.push('Scry on Familiar (1/day)');

  function crRow(name, desc) {
    const d = FAMILIAR_ABILITY_DESCS[name] || COMPANION_SQ_DESCS[name] || desc || '';
    return `<div class="char-cf-row" style="border-left:3px solid var(--border);margin-bottom:0.18rem;">` +
      `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)">` +
        `<span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span>` +
        `<span style="font-size:0.78rem;flex:1;">${name}</span>` +
      `</div>` +
      `<div class="char-cf-row-body">${d || '<em style="color:var(--text-muted);">No description available.</em>'}</div>` +
    `</div>`;
  }

  let html = '';

  // ── Header ──────────────────────────────────────────────────────────────
  html += `<div style="display:flex;align-items:center;flex-wrap:wrap;gap:0.5rem;margin-bottom:0.6rem;padding-bottom:0.5rem;border-bottom:1px solid var(--border);">` +
    `<span style="background:rgba(255,255,255,0.05);border:1px solid var(--border);border-radius:3px;padding:1px 7px;color:var(--text-muted);font-size:0.68rem;">Familiar</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">${f.size}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">⚡ ${f.speed}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">HP: ½ master &bull; BAB/Saves: master's</span>` +
  `</div>`;

  // ── Ability Scores ───────────────────────────────────────────────────────
  html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;">Ability Scores</div>`;
  html += `<div style="display:grid;grid-template-columns:repeat(6,1fr);gap:0.22rem;margin-bottom:0.55rem;">`;
  for (const [lbl, score, mod] of [['STR',str,strMod],['DEX',dex,dexMod],['CON',con,conMod],['INT',finalInt,intMod],['WIS',wis,wisMod],['CHA',cha,chaMod]]) {
    html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;text-align:center;padding:0.28rem 0.1rem;">` +
      `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.04em;">${lbl}</div>` +
      `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">${score}</div>` +
      `<div style="font-size:0.68rem;color:var(--gold-light);">${fm(mod)}</div>` +
    `</div>`;
  }
  html += `</div>`;

  // ── Nat. Armor / HP / Master Bonus ───────────────────────────────────────
  html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:0.3rem;margin-bottom:0.5rem;">`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Nat. Armor Adj.</div>` +
    `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">+${p.natArmorAdj}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">added to base nat. armor</div>` +
  `</div>`;
  html += `<div style="background:rgba(201,168,76,0.08);border:1px solid var(--gold-dark);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Master Bonus</div>` +
    `<div style="font-size:0.78rem;font-weight:600;color:var(--gold-light);">${f.special}</div>` +
    (f.note ? `<div style="font-size:0.65rem;color:var(--gold-light);font-style:italic;margin-top:0.12rem;">✦ ${f.note}</div>` : '') +
  `</div>`;
  html += `</div>`;

  // ── Familiar Abilities (collapsible) ──────────────────────────────────────
  html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.1rem 0 0.3rem;">Familiar Abilities</div>`;
  famAbilities.forEach(ab => {
    // Normalize spell resistance key for lookup
    const lookupKey = ab.startsWith('Spell Resistance') ? 'Spell Resistance (level+5)' : ab;
    html += crRow(ab, FAMILIAR_ABILITY_DESCS[lookupKey]);
  });

  html += `<div style="font-size:0.63rem;color:var(--text-muted);margin-top:0.4rem;font-style:italic;">Master level: ${lvl} &bull; Familiar Int: ${finalInt}</div>`;
  return html;
}

function _buildMountStatBlock(mountName, effLvl) {
  const m = MOUNT_DATA[mountName];
  if (!m) return '<em style="color:var(--text-muted);">Unknown mount.</em>';
  const eff = Math.max(1, Math.min(20, effLvl));
  const p   = ANIMAL_COMPANION_PROGRESSION[eff - 1];
  const fm  = _compFmtMod;
  let str = m.str + p.strDex, dex = m.dex + p.strDex, con = m.con;
  const int_ = m.int || 2, wis = m.wis || 12, cha = m.cha || 6;
  const totalNat = m.natArmor + p.natArmor;
  const sizeAcM  = {Fine:8,Diminutive:4,Tiny:2,Small:1,Medium:0,Large:-1,Huge:-2,Gargantuan:-4,Colossal:-8};
  const sizeMod  = sizeAcM[m.size] || 0;
  const strMod = Math.floor((str-10)/2),  dexMod = Math.floor((dex-10)/2),
        conMod = Math.floor((con-10)/2),  intMod = Math.floor((int_-10)/2),
        wisMod = Math.floor((wis-10)/2),  chaMod = Math.floor((cha-10)/2);
  const totalAc = 10 + dexMod + totalNat + sizeMod;
  const estHp   = Math.floor(p.hd * (5.5 + conMod));
  const fort = p.fort + conMod, ref = p.ref + dexMod, will = p.will + wisMod;
  const abilities = _getCompAbilities(eff);

  function crRow(name, desc) {
    const d = COMPANION_SQ_DESCS[name] || COMPANION_ABILITY_DESCS[name] || MOUNT_TEMPLATE_DESCS[name] || desc || '';
    return `<div class="char-cf-row" style="border-left:3px solid var(--border);margin-bottom:0.18rem;">` +
      `<div class="char-cf-row-header" style="padding:0.28rem 0.65rem;cursor:pointer;" onclick="_compToggleRow(this)">` +
        `<span class="char-cf-arr" style="font-size:0.62rem;color:var(--text-muted);transition:transform 0.15s;flex-shrink:0;">▶</span>` +
        `<span style="font-size:0.78rem;flex:1;">${name}</span>` +
      `</div>` +
      `<div class="char-cf-row-body">${d || '<em style="color:var(--text-muted);">No description available.</em>'}</div>` +
    `</div>`;
  }

  let html = '';

  // ── Header ──────────────────────────────────────────────────────────────
  html += `<div style="display:flex;align-items:center;flex-wrap:wrap;gap:0.5rem;margin-bottom:0.6rem;padding-bottom:0.5rem;border-bottom:1px solid var(--border);">` +
    `<span style="background:rgba(201,168,76,0.12);border:1px solid var(--gold-dark);border-radius:3px;padding:1px 7px;color:var(--gold-light);font-size:0.68rem;">Special Mount</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">${m.size}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">⚡ ${m.speed}</span>` +
    `<span style="color:var(--border);">|</span>` +
    `<span style="font-size:0.72rem;color:var(--text-secondary);">HD ${p.hd}d8 &bull; BAB ${fm(p.bab)}</span>` +
  `</div>`;

  // ── Ability Scores ───────────────────────────────────────────────────────
  html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin-bottom:0.3rem;">Ability Scores</div>`;
  html += `<div style="display:grid;grid-template-columns:repeat(6,1fr);gap:0.22rem;margin-bottom:0.55rem;">`;
  for (const [lbl, score, mod] of [['STR',str,strMod],['DEX',dex,dexMod],['CON',con,conMod],['INT',int_,intMod],['WIS',wis,wisMod],['CHA',cha,chaMod]]) {
    html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;text-align:center;padding:0.28rem 0.1rem;">` +
      `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);letter-spacing:0.04em;">${lbl}</div>` +
      `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">${score}</div>` +
      `<div style="font-size:0.68rem;color:var(--gold-light);">${fm(mod)}</div>` +
    `</div>`;
  }
  html += `</div>`;

  // ── Defenses ─────────────────────────────────────────────────────────────
  html += `<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:0.3rem;margin-bottom:0.5rem;">`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">AC</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${totalAc}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">10+${fm(dexMod)} Dex+${totalNat} Nat${sizeMod!==0?fm(sizeMod)+' Size':''}</div>` +
  `</div>`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Fort</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(fort)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.fort} base ${fm(conMod)} Con</div>` +
  `</div>`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Ref</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(ref)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.ref} base ${fm(dexMod)} Dex</div>` +
  `</div>`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Will</div>` +
    `<div style="font-size:1rem;font-weight:700;color:var(--text-primary);">${fm(will)}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.will} base ${fm(wisMod)} Wis</div>` +
  `</div>`;
  html += `</div>`;

  // ── HP / Skills ──────────────────────────────────────────────────────────
  html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:0.3rem;margin-bottom:0.45rem;">`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">HP (est.)</div>` +
    `<div style="font-size:0.88rem;font-weight:600;color:var(--text-primary);">${estHp}</div>` +
    `<div style="font-size:0.58rem;color:var(--text-muted);">${p.hd}d8 + ${conMod*p.hd} Con</div>` +
  `</div>`;
  html += `<div style="background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;padding:0.28rem 0.45rem;">` +
    `<div style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);">Skills / Tricks / Feats</div>` +
    `<div style="font-size:0.78rem;color:var(--text-primary);">${p.skills} pts &bull; ${p.tricks} tricks &bull; ${p.feats} feats</div>` +
  `</div>`;
  html += `</div>`;

  // ── Attacks ───────────────────────────────────────────────────────────────
  html += `<div style="padding:0.3rem 0.5rem;background:var(--bg-deep);border:1px solid var(--border);border-radius:4px;margin-bottom:0.45rem;">` +
    `<span style="font-size:0.52rem;text-transform:uppercase;color:var(--text-muted);margin-right:0.4rem;">Attacks</span>` +
    `<span style="font-size:0.77rem;color:var(--text-primary);">${m.attack}</span>` +
    (m.note ? `<div style="font-size:0.63rem;color:var(--text-muted);font-style:italic;margin-top:0.12rem;">${m.note}</div>` : '') +
  `</div>`;

  // ── Special Qualities (collapsible) ───────────────────────────────────────
  if (m.sq) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.1rem 0 0.3rem;">Special Qualities</div>`;
    m.sq.split(', ').forEach(q => html += crRow(q.trim()));
  }

  // ── Template Abilities (collapsible) ──────────────────────────────────────
  if (m.template) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;">Template Abilities</div>`;
    // Parse template string like "Celestial: Smite Evil 1/day, resist acid/cold/electricity 5, DR 5/evil"
    const parts = m.template.replace(/^[^:]+:\s*/, '').split(', ');
    parts.forEach(part => html += crRow(part.trim()));
  }

  // ── Companion Abilities (collapsible) ─────────────────────────────────────
  if (abilities.length) {
    html += `<div style="font-size:0.58rem;text-transform:uppercase;letter-spacing:0.08em;color:var(--gold);margin:0.45rem 0 0.3rem;">Companion Abilities</div>`;
    abilities.forEach(ab => html += crRow(ab));
  }

  html += `<div style="font-size:0.63rem;color:var(--text-muted);margin-top:0.4rem;font-style:italic;">Eff. companion level: ${eff}${p.strDex>0?` &bull; Str/Dex bonus: +${p.strDex}`:''}</div>`;
  return html;
}

function setCompanionChoice(ci, n) { if (character.classes[ci]) { character.classes[ci].companion = n||null; renderCharacter(); } }
function setFamiliarChoice(ci, n)  { if (character.classes[ci]) { character.classes[ci].familiar  = n||null; renderCharacter(); } }
function setMountChoice(ci, n)     { if (character.classes[ci]) { character.classes[ci].mount     = n||null; renderCharacter(); } }

// ═══════════════════════════════════════════════════════════════════════════
// COMPANION / FAMILIAR / MOUNT SELECTION MODAL
// ═══════════════════════════════════════════════════════════════════════════
const COMPANION_TRICKS = [
  'Attack','Attack Any Target','Bring','Come','Defend','Down',
  'Fetch','Guard','Heel','Perform','Seek','Shake','Sit','Stay','Track','Work'
];
const COMPANION_FEATS = [
  'Armor Proficiency (Light)','Blind-Fight','Combat Reflexes','Diehard','Dodge',
  'Endurance','Great Fortitude','Improved Bull Rush','Improved Initiative',
  'Improved Natural Armor','Improved Natural Attack','Iron Will','Lightning Reflexes',
  'Mobility','Multiattack','Power Attack','Run',
  'Skill Focus (Perception)','Skill Focus (Stealth)','Toughness',
  'Weapon Focus (bite)','Weapon Focus (claw)','Weapon Focus (gore)','Weapon Focus (slam)'
];

const COMPANION_TRICK_DESCS = {
  'Attack':          'The animal attacks apparent enemies. You may point to a particular creature that you wish the animal to attack, and it will comply if able. Normally, an animal will attack only humanoids, monstrous humanoids, giants, or other animals.',
  'Attack Any Target':'As the attack trick, but the animal will attack any creature you designate, including creatures it would not normally attack.',
  'Bring':           'The animal goes to a specific location you indicate and returns with a specific item, distinguishing it from similar objects as directed.',
  'Come':            'The animal comes to you, even if it normally would not do so.',
  'Defend':          'The animal defends you (or is ready to defend you if no threat is present), even without any command being given. You can also command it to defend a specific other character.',
  'Down':            'The animal breaks off from combat or a task it was commanded to do and backs down. An animal that doesn\'t know this trick continues to fight until the opponent is defeated or flees.',
  'Fetch':           'The animal goes to a specific area, retrieves a specific item, and returns with it. More specific than the Bring trick — requires identifying both the area and the object.',
  'Guard':           'The animal stays in place and prevents others from approaching, attacking anyone who attempts to pass without permission.',
  'Heel':            'The animal follows you closely, even to places where it normally wouldn\'t go.',
  'Perform':         'The animal performs a variety of simple tricks (sit up, roll over, roar, shake hands, and so on) on command.',
  'Seek':            'The animal moves into an area and looks around for anything that is obviously alive or animate, alerting you to its findings.',
  'Shake':           'The animal makes a friendly physical-contact gesture such as shaking hands. This is purely cosmetic and has no combat application.',
  'Sit':             'The animal sits up on its haunches and waits until given its next command.',
  'Stay':            'The animal stays in place, waiting for you to return. It does not challenge other creatures that come by, though it still defends itself if attacked.',
  'Track':           'The animal tracks the scent presented to it. (Requires the animal to have the scent special ability.)',
  'Work':            'The animal willingly pulls or pushes a medium or heavy load, such as a cart, plow, or millstone.',
};

const COMPANION_FEAT_DESCS = {
  'Armor Proficiency (Light)':  'The animal treats light armor as if it had no armor check penalty, and can use light armor without the –4 nonproficiency penalty.',
  'Blind-Fight':                'You can reroll miss chances from concealment (but not total concealment). You are not denied your Dex bonus against invisible attackers, and you take no extra penalty when charging or running through concealment.',
  'Combat Reflexes':            'You may make a number of additional attacks of opportunity per round equal to your Dexterity bonus. You can also make attacks of opportunity while flat-footed.',
  'Diehard':                    'You automatically stabilize when below 0 HP and remain conscious (though staggered). You only die when your negative HP total equals your Constitution score.',
  'Dodge':                      'You gain a +1 dodge bonus to your AC. You lose this bonus whenever you lose your Dexterity bonus to AC.',
  'Endurance':                  '+4 bonus on checks to avoid nonlethal damage from a forced march, running, swimming, holding your breath, going without sleep, or other strenuous activities.',
  'Great Fortitude':            '+2 bonus on all Fortitude saving throws.',
  'Improved Bull Rush':         'You do not provoke an attack of opportunity when performing a bull rush, and you gain a +2 bonus on combat maneuver checks to bull rush a foe.',
  'Improved Initiative':        '+4 bonus on initiative checks.',
  'Improved Natural Armor':     'Your natural armor bonus to AC increases by +1. You can take this feat multiple times, each time increasing the natural armor bonus.',
  'Improved Natural Attack':    'Choose one of the animal\'s natural attacks. The damage dealt by that attack increases by one step (as if it were one size larger).',
  'Iron Will':                  '+2 bonus on all Will saving throws.',
  'Lightning Reflexes':         '+2 bonus on all Reflex saving throws.',
  'Mobility':                   '+4 dodge bonus to Armor Class against attacks of opportunity provoked by moving out of or within a threatened area.',
  'Multiattack':                'The animal\'s secondary natural attacks take only a –2 penalty on attack rolls instead of the normal –5 penalty.',
  'Power Attack':               'You can choose to take a –1 penalty on all melee attack rolls to gain a +2 bonus on all melee damage rolls (doubles for two-handed weapons).',
  'Run':                        'When running, the animal moves at 5× its normal speed. It retains its Dexterity bonus to AC while running and can make Acrobatics checks to jump with a +4 bonus.',
  'Skill Focus (Perception)':   '+3 bonus on all Perception checks. Increases to +6 if the animal has 10 or more ranks in Perception.',
  'Skill Focus (Stealth)':      '+3 bonus on all Stealth checks. Increases to +6 if the animal has 10 or more ranks in Stealth.',
  'Toughness':                  '+3 hit points, plus +1 additional hit point per Hit Die beyond 3.',
  'Weapon Focus (bite)':        '+1 bonus on attack rolls made with the bite natural attack.',
  'Weapon Focus (claw)':        '+1 bonus on attack rolls made with the claw natural attack.',
  'Weapon Focus (gore)':        '+1 bonus on attack rolls made with the gore natural attack.',
  'Weapon Focus (slam)':        '+1 bonus on attack rolls made with the slam natural attack.',
};

let _compModal = {
  clsIdx: null, type: null, list: [], selected: null,
  tricks: [], feats: [], tricksMax: 0, featsMax: 0,
};

function openCompanionModal(clsIdx, type) {
  const cls     = character.classes[clsIdx];
  if (!cls) return;
  const clsNm   = (cls.name || cls._name || '').toLowerCase().trim();
  const compCfg = COMPANION_CLASSES[clsNm];
  const effLvl  = _getEffCompLevel(cls);

  // Build list of options
  let list = [];
  let title = 'Choose';
  if (type === 'companion') {
    list  = compCfg && compCfg.mounts
      ? ANIMAL_COMPANIONS.filter(a => compCfg.mounts.includes(a.name))
      : ANIMAL_COMPANIONS;
    title = 'Choose ' + (compCfg && compCfg.label ? compCfg.label : 'Animal Companion');
  } else if (type === 'familiar') {
    list  = FAMILIAR_LIST;
    title = 'Choose Familiar';
  } else if (type === 'mount') {
    list  = Object.keys(MOUNT_DATA).filter(k => (MOUNT_LIST[clsNm]||[]).includes(k))
              .map(k => ({ name: k, ...MOUNT_DATA[k] }));
    title = 'Choose Special Mount';
  }

  const prog      = ANIMAL_COMPANION_PROGRESSION[Math.max(0, Math.min(19, effLvl - 1))];
  // Mounts also use the companion progression for tricks/feats (Paladin/Antipaladin special mounts)
  const tricksMax = (type === 'companion' || type === 'mount') ? (prog ? prog.tricks : 0) : 0;
  const featsMax  = (type === 'companion' || type === 'mount') ? (prog ? prog.feats  : 0) : 0;

  // Restore existing choices
  const existingTricks = (cls.companionChoices && cls.companionChoices.tricks) || [];
  const existingFeats  = (cls.companionChoices && cls.companionChoices.feats)  || [];

  _compModal = {
    clsIdx, type, list, effLvl, clsNm, compCfg,
    selected:  type === 'companion' ? cls.companion : type === 'familiar' ? cls.familiar : cls.mount,
    tricks:    existingTricks.slice(),
    feats:     existingFeats.slice(),
    tricksMax, featsMax,
  };

  document.getElementById('companion-modal-title').textContent = title;
  document.getElementById('companion-modal-search').value = '';

  // Always reset confirm button before opening — prevents stale "enabled" state
  // from a previous companion selection bleeding into a fresh modal session
  const _cmConfirmBtn = document.getElementById('companion-modal-confirm');
  _cmConfirmBtn.disabled = true;
  _cmConfirmBtn.style.opacity = '0.5';
  document.getElementById('companion-modal-selection-label').textContent = 'Nothing selected yet.';
  // Clear any previous choices from detail col
  const _cmChoicesWrapper = document.getElementById('companion-modal-choices-wrapper');
  if (_cmChoicesWrapper) _cmChoicesWrapper.innerHTML = '';

  _compModalRenderList(list);
  _compModalSelectItem(_compModal.selected);
  document.body.style.overflow = 'hidden';
  document.getElementById('companion-modal-backdrop').classList.add('open');
}

function closeCompanionModal() {
  document.getElementById('companion-modal-backdrop').classList.remove('open');
  document.body.style.overflow = '';
}

function _compModalFilter(val) {
  const q = val.toLowerCase();
  const filtered = _compModal.list.filter(item => (item.name||'').toLowerCase().includes(q));
  _compModalRenderList(filtered);
  // Re-highlight if still visible
  document.querySelectorAll('.comp-list-row').forEach(r => {
    if (r.dataset.name === _compModal.selected) r.classList.add('selected');
  });
}

function _compModalRenderList(items) {
  const listEl = document.getElementById('companion-modal-list');
  listEl.innerHTML = items.map(item => {
    const name    = item.name;
    const size    = item.size || (item.base && item.base.size) || '';
    const isSel   = name === _compModal.selected;
    return `<div class="comp-list-row${isSel?' selected':''}" data-name="${name}" onclick="_compModalSelectItem('${name.replace(/'/g,"\\'")}')" >
      <div>
        <div class="comp-list-name">${name}</div>
        ${size ? `<div class="comp-list-size">${size}</div>` : ''}
      </div>
    </div>`;
  }).join('');
}

function _compModalSelectItem(name) {
  if (!name) return;
  _compModal.selected = name;
  // Update list highlight
  document.querySelectorAll('.comp-list-row').forEach(r => {
    r.classList.toggle('selected', r.dataset.name === name);
  });
  // Render detail pane
  const detailEl = document.getElementById('companion-modal-detail');
  let html = '';
  if (_compModal.type === 'companion') {
    const effLvl = _compModal.effLvl || 1;
    html = `<div style="font-family:Cinzel,serif;font-size:0.9rem;color:var(--gold);margin-bottom:0.75rem;text-transform:uppercase;letter-spacing:0.07em;">${name}</div>`
         + _buildCompStatBlock(name, effLvl);
  } else if (_compModal.type === 'familiar') {
    const fam = FAMILIAR_LIST.find(f => f.name === name);
    if (fam) {
      html = `<div style="font-family:Cinzel,serif;font-size:0.9rem;color:var(--gold);margin-bottom:0.75rem;text-transform:uppercase;letter-spacing:0.07em;">${name}</div>`
           + _buildFamStatBlock(name, _compModal.effLvl || 1);
    }
  } else if (_compModal.type === 'mount') {
    html = `<div style="font-family:Cinzel,serif;font-size:0.9rem;color:var(--gold);margin-bottom:0.75rem;text-transform:uppercase;letter-spacing:0.07em;">${name}</div>`
         + _buildMountStatBlock(name, _compModal.effLvl || 1);
  }
  detailEl.innerHTML = html || '<em style="color:var(--text-muted);">No detail available.</em>';

  // Enable confirm
  const confirmBtn = document.getElementById('companion-modal-confirm');
  confirmBtn.disabled = false;
  confirmBtn.style.opacity = '1';
  document.getElementById('companion-modal-selection-label').textContent = `Selected: ${name}`;

  // Render tricks/feats choices panel for animal companions
  _compModalRenderChoices();
}

function _compAccordionToggle(bodyId) {
  const body = document.getElementById(bodyId);
  if (!body) return;
  const hdr = body.previousElementSibling;
  const isOpen = body.classList.toggle('open');
  if (hdr) hdr.classList.toggle('open', isOpen);
}

function _compChoiceRowToggle(rowTop) {
  const desc = rowTop.nextElementSibling;
  if (!desc || !desc.classList.contains('comp-choice-desc')) return;
  const isOpen = desc.style.display === 'block';
  desc.style.display = isOpen ? 'none' : 'block';
  const arr = rowTop.querySelector('.comp-choice-arr');
  if (arr) arr.textContent = isOpen ? '▾' : '▴';
}

function _compModalRenderChoices() {
  const wrapper = document.getElementById('companion-modal-choices-wrapper');
  if (!wrapper) return;

  // Show tricks/feats for companions AND mounts (special mounts use same progression)
  if ((_compModal.type !== 'companion' && _compModal.type !== 'mount') || (!_compModal.tricksMax && !_compModal.featsMax)) {
    wrapper.innerHTML = '';
    return;
  }

  const tricksFull = _compModal.tricksMax > 0 && _compModal.tricks.length >= _compModal.tricksMax;

  let html = '';

  // ── Tricks Section ──────────────────────────────────────────────────────────
  if (_compModal.tricksMax > 0) {
    const tCount = _compModal.tricks.length;
    const tMax   = _compModal.tricksMax;
    const tFull  = tCount >= tMax;
    // Auto-close tricks when full (so feats gets focus), open otherwise
    const isOpen = !tFull;
    html += `<div class="comp-choices-section">
      <div class="comp-choices-hdr${isOpen ? ' open' : ''}" onclick="_compAccordionToggle('_comp-tricks-body')">
        <span class="comp-choices-arr">▼</span>
        <span class="comp-choices-hdr-title">Tricks</span>
        <span class="comp-choices-count${tFull ? ' full' : ''}">${tCount} / ${tMax}</span>
        ${tFull ? '<span class="comp-choices-done">✓ All Selected</span>' : ''}
      </div>
      <div id="_comp-tricks-body" class="comp-choices-body${isOpen ? ' open' : ''}">`;
    for (const t of COMPANION_TRICKS) {
      const checked  = _compModal.tricks.includes(t);
      const disabled = !checked && _compModal.tricks.length >= _compModal.tricksMax;
      const desc     = COMPANION_TRICK_DESCS[t] || '';
      const safeT    = t.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
      html += `<div class="comp-choice-row${checked ? ' checked' : ''}${disabled ? ' disabled' : ''}">
        <div class="comp-choice-row-top${desc ? ' expandable' : ''}" ${desc ? 'onclick="_compChoiceRowToggle(this)"' : ''}>
          <input type="checkbox" class="comp-choice-check" ${checked ? 'checked' : ''} ${disabled ? 'disabled' : ''}
            onclick="event.stopPropagation();_compModalToggleTrick('${safeT}',this.checked)">
          <span class="comp-choice-name">${t}</span>
          ${desc ? '<span class="comp-choice-arr">▾</span>' : ''}
        </div>
        ${desc ? `<div class="comp-choice-desc">${desc}</div>` : ''}
      </div>`;
    }
    html += `</div></div>`;
  }

  // ── Bonus Feats Section ─────────────────────────────────────────────────────
  if (_compModal.featsMax > 0) {
    const fCount = _compModal.feats.length;
    const fMax   = _compModal.featsMax;
    const fFull  = fCount >= fMax;
    // Auto-open feats when tricks are full (or no tricks), or when feats already have selections
    const isOpen = tricksFull || _compModal.tricksMax === 0 || fCount > 0;
    html += `<div class="comp-choices-section">
      <div class="comp-choices-hdr${isOpen ? ' open' : ''}" onclick="_compAccordionToggle('_comp-feats-body')">
        <span class="comp-choices-arr">▼</span>
        <span class="comp-choices-hdr-title">Bonus Feats</span>
        <span class="comp-choices-count${fFull ? ' full' : ''}">${fCount} / ${fMax}</span>
        ${fFull ? '<span class="comp-choices-done">✓ All Selected</span>' : ''}
      </div>
      <div id="_comp-feats-body" class="comp-choices-body${isOpen ? ' open' : ''}">`;
    for (const f of COMPANION_FEATS) {
      const checked  = _compModal.feats.includes(f);
      const disabled = !checked && _compModal.feats.length >= _compModal.featsMax;
      const desc     = COMPANION_FEAT_DESCS[f] || '';
      const safeF    = f.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
      html += `<div class="comp-choice-row${checked ? ' checked' : ''}${disabled ? ' disabled' : ''}">
        <div class="comp-choice-row-top${desc ? ' expandable' : ''}" ${desc ? 'onclick="_compChoiceRowToggle(this)"' : ''}>
          <input type="checkbox" class="comp-choice-check" ${checked ? 'checked' : ''} ${disabled ? 'disabled' : ''}
            onclick="event.stopPropagation();_compModalToggleFeat('${safeF}',this.checked)">
          <span class="comp-choice-name">${f}</span>
          ${desc ? '<span class="comp-choice-arr">▾</span>' : ''}
        </div>
        ${desc ? `<div class="comp-choice-desc">${desc}</div>` : ''}
      </div>`;
    }
    html += `</div></div>`;
  }

  wrapper.innerHTML = html;
}

function _compModalToggleTrick(name, on) {
  if (on) {
    if (_compModal.tricks.length < _compModal.tricksMax) _compModal.tricks.push(name);
  } else {
    _compModal.tricks = _compModal.tricks.filter(t => t !== name);
  }
  _compModalRenderChoices();
}

function _compModalToggleFeat(name, on) {
  if (on) {
    if (_compModal.feats.length < _compModal.featsMax) _compModal.feats.push(name);
  } else {
    _compModal.feats = _compModal.feats.filter(f => f !== name);
  }
  _compModalRenderChoices();
}

function confirmCompanionModal() {
  if (!_compModal.selected || _compModal.clsIdx === null) return;
  const cls = character.classes[_compModal.clsIdx];
  if (!cls) return;
  if (_compModal.type === 'companion') {
    cls.companion = _compModal.selected;
    // .slice() ensures each class stores its own independent copy, not a shared reference
    cls.companionChoices = { tricks: _compModal.tricks.slice(), feats: _compModal.feats.slice() };
  } else if (_compModal.type === 'familiar') {
    cls.familiar = _compModal.selected;
  } else if (_compModal.type === 'mount') {
    cls.mount = _compModal.selected;
    // Mounts (Paladin/Antipaladin special mounts) also get tricks/feats from progression
    cls.companionChoices = { tricks: _compModal.tricks.slice(), feats: _compModal.feats.slice() };
  }
  closeCompanionModal();
  renderCharacter();
}

// ─── General confirm dialog ───────────────────────────────────────────────
let _confirmCallback = null;
function showConfirmDialog(message, onYes, yesLabel) {
  document.getElementById('confirm-dialog-msg').innerHTML = message;
  const yesBtn = document.getElementById('confirm-dialog-yes');
  yesBtn.textContent = yesLabel || 'Yes, Remove';
  _confirmCallback = onYes;
  yesBtn.onclick = () => { closeConfirmDialog(); if (_confirmCallback) _confirmCallback(); };
  document.getElementById('confirm-dialog-backdrop').classList.add('open');
}
function closeConfirmDialog() {
  document.getElementById('confirm-dialog-backdrop').classList.remove('open');
  _confirmCallback = null;
}

// ─── Inline two-step class-removal confirmation (matches save/load delete style) ──
function _showClsRmConfirm(rmBtn, clsIdx, name) {
  const banner = rmBtn.parentElement;
  banner.style.outline   = '1px solid #7a2222';
  banner.style.boxShadow = 'inset 0 0 0 1px rgba(200,60,60,0.35)';
  const safeName = name.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
  const wrap = document.createElement('span');
  wrap.style.cssText = 'display:inline-flex;align-items:center;gap:0.4rem;flex-shrink:0;';
  wrap.innerHTML =
    `<span style="font-family:Cinzel,serif;font-size:0.72rem;color:#f07070;font-weight:700;letter-spacing:0.03em;white-space:nowrap;">Remove "${name}"?</span>` +
    `<button class="card-btn" style="background:rgba(200,60,60,0.35);border-color:#c55;color:#ffaaaa;font-weight:700;box-shadow:0 0 6px rgba(200,60,60,0.4);" onclick="event.stopPropagation();_showClsRmStep2(this,${clsIdx},'${safeName}')">Yes</button>` +
    `<button class="card-btn" style="background:var(--bg-surface);border-color:var(--border);color:var(--text-secondary);" onclick="event.stopPropagation();renderCharacter()">Cancel</button>`;
  rmBtn.replaceWith(wrap);
}
function _showClsRmStep2(yesBtnEl, clsIdx, name) {
  const wrap   = yesBtnEl.parentElement;
  const banner = wrap.parentElement;
  banner.style.outline   = '1px solid #c55';
  banner.style.boxShadow = 'inset 0 0 0 1px rgba(220,80,80,0.6), 0 0 12px rgba(200,60,60,0.25)';
  wrap.innerHTML =
    `<span style="font-family:Cinzel,serif;font-size:0.72rem;color:#ff6060;font-weight:700;letter-spacing:0.04em;white-space:nowrap;text-shadow:0 0 8px rgba(255,80,80,0.5);">⚠ Can't be undone!</span>` +
    `<button class="card-btn" style="background:rgba(200,60,60,0.55);border-color:#e05555;color:#fff;font-weight:700;box-shadow:0 0 10px rgba(220,60,60,0.6);text-shadow:0 1px 2px rgba(0,0,0,0.5);" onclick="event.stopPropagation();_doRemoveClass(${clsIdx})">Really Remove</button>` +
    `<button class="card-btn" style="background:var(--bg-surface);border-color:var(--border);color:var(--text-secondary);" onclick="event.stopPropagation();renderCharacter()">Cancel</button>`;
}
function _doRemoveClass(clsIdx) {
  character.classes.splice(clsIdx, 1);
  if (character.favoredClassIndex >= character.classes.length)
    character.favoredClassIndex = Math.max(0, character.classes.length - 1);
  renderCharacter(); updateBadge();
}

