// ── Compute combined proficiencies from character's classes + race ────────────
function getCharacterProficiencies() {
  const weaponLevels = new Set();  // 'simple', 'martial'
  const armorTypes   = new Set();  // 'light', 'medium', 'heavy', 'shields', 'tower shield'
  let   firearmProf  = false;      // firearms require gunslinger or explicit feat
  // Racial: specific named items always grant proficiency; keywords need martial prof to apply
  const specificItems = new Map(); // lowercase item name → display source string
  const keywordProfs  = [];        // [{keyword, source}]

  // Class proficiencies
  for (const cls of (character.classes || [])) {
    const cname = (cls.name || '').toLowerCase();
    const wp = CLASS_WEAPON_PROFS[cname];
    if (wp === 'simple' || wp === 'limited') weaponLevels.add('simple');
    if (wp === 'martial') { weaponLevels.add('simple'); weaponLevels.add('martial'); }
    for (const a of (CLASS_ARMOR_PROFS[cname] || [])) armorTypes.add(a);
    if (CLASS_FIREARM_PROFS.has(cname)) firearmProf = true;
  }

  // Racial weapon familiarity
  if (character.race) {
    const raceName = (character.race.name || character.race._name || '').toLowerCase().trim();
    const fam = RACE_WEAPON_FAMILIARITY[raceName];
    if (fam) {
      const displaySrc = `${character.race.name || raceName} ${fam.source}`;
      for (const it of (fam.specificItems || [])) {
        if (!specificItems.has(it)) specificItems.set(it, displaySrc);
      }
      if (fam.keyword) keywordProfs.push({ keyword: fam.keyword, source: displaySrc });
    }
  }

  return { weaponLevels, armorTypes, firearmProf, specificItems, keywordProfs };
}

// ── Helper: check if an item has racial/specific-item proficiency ─────────────
// Returns {proficient, source, type} or null if no racial proficiency applies.
// type: 'specific'         — named item always proficient
//       'keyword'          — keyword match AND character has martial prof
//       'keyword-no-prof'  — keyword match but no martial prof (not yet proficient)
function getRacialItemProfInfo(itemNameLower, profs) {
  // Specific named item (always proficient regardless of class)
  if (profs.specificItems.has(itemNameLower)) {
    return { proficient: true, source: profs.specificItems.get(itemNameLower), type: 'specific' };
  }
  // Keyword match
  for (const { keyword, source } of profs.keywordProfs) {
    if (itemNameLower.includes(keyword.toLowerCase())) {
      if (profs.weaponLevels.has('martial')) {
        return { proficient: true,
                 source: `${source} — any weapon with "${keyword}" in name (treated as Martial)`,
                 type: 'keyword' };
      } else {
        return { proficient: false,
                 source: `${source} — any weapon with "${keyword}" in name (requires Martial Weapon Prof)`,
                 type: 'keyword-no-prof' };
      }
    }
  }
  return null;
}

// ── Helper: refresh equipment proficiency tabs & cards after class changes ────
function refreshEquipmentProficiency() {
  if (!document.querySelector('.equipment-category-tab')) return; // equipment tab not yet rendered
  renderEquipmentCategoryTabs();
  // Restore active state on main category tab
  if (currentEquipmentCategory) {
    document.querySelectorAll('.equipment-category-tab').forEach(t =>
      t.classList.toggle('active', t.textContent.trim().includes(currentEquipmentCategory)));
  }
  renderEquipmentSubcategoryTabs();
  // Re-render visible equipment cards to apply new proficiency glow/faint
  if (currentEquipmentCategory && filteredData.equipment && filteredData.equipment.length) {
    renderData('equipment', filteredData.equipment);
  }
}

